-- Poems batch 45
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ab0e4b32-caff-4b09-92c1-d1f9defce9f9','江行無題一百首 九十二','錢珝','唐','唐诗','tang','','[]','江雨正霏微，江村晚渡稀。',24,'全唐诗/poet.tang.40000.json','["江雨正霏微，江村晚渡稀。", "何曾妨釣艇，更待得魚歸。"]'),
('91a8fbb3-711e-4357-a50e-b31313c83377','江行無題一百首 九十三','錢珝','唐','唐诗','tang','','[]','新野舊樓名，潯陽勝賞情。',24,'全唐诗/poet.tang.40000.json','["新野舊樓名，潯陽勝賞情。", "照人長一色，江月共淒清。"]'),
('005f6c5a-a14c-4396-a092-bf8d0bcf478b','江行無題一百首 九十四','錢珝','唐','唐诗','tang','','["\u957f\u6c5f"]','願飲西江水，那吟北渚愁。',24,'全唐诗/poet.tang.40000.json','["願飲西江水，那吟北渚愁。", "莫教留滯跡，遠比蔡昭侯。"]'),
('6ac16933-bda9-43ef-a68d-aa17cfa35bae','江行無題一百首 九十五','錢珝','唐','唐诗','tang','','[]','湖口分江水，東流獨有情。',24,'全唐诗/poet.tang.40000.json','["湖口分江水，東流獨有情。", "常時好風物，誰伴謝宣城。"]'),
('3732bc1a-82b6-4dce-b1cf-0ceec9a85a02','江行無題一百首 九十六','錢珝','唐','唐诗','tang','','[]','潯陽江畔菊，應似古來秋。',24,'全唐诗/poet.tang.40000.json','["潯陽江畔菊，應似古來秋。", "爲問幽棲客，吟時得酒不。"]'),
('b8d29e83-0bd1-4298-b8d0-d2efba89a8f7','江行無題一百首 九十七','錢珝','唐','唐诗','tang','','[]','高峯有佳號，千尺倚寒風。',24,'全唐诗/poet.tang.40000.json','["高峯有佳號，千尺倚寒風。", "若使爐煙在，猶應爲上公。"]'),
('c2bb01ed-11bf-4919-8c6d-15f019e79e17','江行無題一百首 九十八','錢珝','唐','唐诗','tang','','[]','萬木已清霜，江邊村事忙。',24,'全唐诗/poet.tang.40000.json','["萬木已清霜，江邊村事忙。", "故溪黃稻熟，一夜夢中香。"]'),
('e471aec3-1c1b-4228-9564-2ae2e8990b91','江行無題一百首 九十九','錢珝','唐','唐诗','tang','','[]','楚水苦縈回，征帆落又開。',24,'全唐诗/poet.tang.40000.json','["楚水苦縈回，征帆落又開。", "可緣非直路，却有好風來。"]'),
('e56f9988-89d6-40fc-84af-dba32f882445','江行無題一百首 一百','錢珝','唐','唐诗','tang','','[]','遠謫歲時[晏]，暮江風雨寒。',26,'全唐诗/poet.tang.40000.json','["遠謫歲時[晏]，暮江風雨寒。", "仍愁繫舟處，驚夢近長灘。"]'),
('30a8471a-2b0f-482d-80b6-7606855a84fc','春恨三首 一','錢珝','唐','唐诗','tang','','[]','負罪將軍在北朝，秦淮芳草綠迢迢。',32,'全唐诗/poet.tang.40000.json','["負罪將軍在北朝，秦淮芳草綠迢迢。", "高臺愛妾魂銷盡，始得丘遲爲一招。"]'),
('3d51823f-4690-4047-bb57-a9bd95666725','春恨三首 二','錢珝','唐','唐诗','tang','','[]','久戍臨洮報未歸，篋香銷盡別時衣。',32,'全唐诗/poet.tang.40000.json','["久戍臨洮報未歸，篋香銷盡別時衣。", "身輕願比蘭堦蝶，萬里還尋塞草飛。"]'),
('97778acd-7c68-44ef-b330-98dd0ed1b2fc','春恨三首 三','錢珝','唐','唐诗','tang','','[]','永巷頻聞小苑遊，舊恩如淚亦難收。',32,'全唐诗/poet.tang.40000.json','["永巷頻聞小苑遊，舊恩如淚亦難收。", "君前願報新顏色，團扇須防白露秋。"]'),
('125d47ef-f848-442e-871a-c37a890b01d0','蜀國偶題','錢珝','唐','唐诗','tang','','[]','忽憶明皇西幸時，暗傷潛恨竟誰知。',32,'全唐诗/poet.tang.40000.json','["忽憶明皇西幸時，暗傷潛恨竟誰知。", "佩蘭應語宮臣道，莫向金盤進茘枝。"]'),
('26b06f1c-4632-42a2-9658-31b725d90e59','未展芭蕉','錢珝','唐','唐诗','tang','','[]','冷燭無煙綠蠟乾，芳心猶卷怯春寒。',32,'全唐诗/poet.tang.40000.json','["冷燭無煙綠蠟乾，芳心猶卷怯春寒。", "一緘書箚藏何事，會被東風暗拆看。"]'),
('e4449fbb-cf45-43a2-b3ff-4ee886423be1','同程九早入中書','錢珝','唐','唐诗','tang','','[]','漢家賢相重英奇，蟠木何材也見知。',64,'全唐诗/poet.tang.40000.json','["漢家賢相重英奇，蟠木何材也見知。", "不意雲霄能自致，空驚鵷鷺忽相隨。", "臘雪初明柏子殿，春光欲上萬年枝。", "獨慚皇鑒明如日，未厭春光向玉墀。"]'),
('65fd2bb1-6ff8-4e39-ab8b-d35acb120d6b','陳情獻中丞','喻坦之','唐','唐诗','tang','','[]','孤拙竟何營，徒希折桂名。',144,'全唐诗/poet.tang.40000.json','["孤拙竟何營，徒希折桂名。", "始終誰肯薦，得失自難明。", "貢乏雄文獻，歸無瘠土耕。", "滄江長發夢，紫陌久慙行。", "意縱求知切，才惟懼鑒精。", "五言非琢玉，十載看遷鶯。", "取進心甘鈍，傷嗟骨每驚。", "塵襟痕積淚，客鬢白新莖。", "顧盼身堪教，吹噓羽覺生。", "依門情轉切，荷德力須傾。", "獎善猶憐貢，垂恩必不輕。", "從茲便提挈，雲路自生榮。"]'),
('1603f9fd-4294-4988-8c85-12f3ba52807a','長安雪後','喻坦之','唐','唐诗','tang','','[]','碧落雲收盡，天涯雪霽時。',96,'全唐诗/poet.tang.40000.json','["碧落雲收盡，天涯雪霽時。", "草開當井地，樹折帶巢枝。", "野渡滋寒麥，高泉漲禁池。", "遙分丹闕出，迴對上林宜。", "宿片攀簷取，凝花就砌窺。", "氣凌禽翅束，凍入馬蹄危。", "北想連沙漠，南思極海涯。", "冷光兼素彩，向暮朔風吹。"]'),
('77576a34-b2d1-498e-9cfe-ea51f70c2083','送友人遊東川','喻坦之','唐','唐诗','tang','','[]','食盡須分散，將行幾願留。',48,'全唐诗/poet.tang.40000.json','["食盡須分散，將行幾願留。", "春兼三月閏，人擬半年遊。", "風俗同吳地，山川擁梓州。", "思君登棧道，猨嘯始應愁。"]'),
('c3263eec-83a9-4775-8b60-809efe95d9ff','題樟亭驛樓','喻坦之','唐','唐诗','tang','','[]','危檻倚山城，風帆檻外行。',48,'全唐诗/poet.tang.40000.json','["危檻倚山城，風帆檻外行。", "日生滄海赤，潮落浙江清。", "秋晚遙峰出，沙乾細草平。", "西陵煙樹色，長見伍員情。"]'),
('8c4ef309-8478-43a2-ad29-64c8cec6d073','大梁送友人東遊','喻坦之','唐','唐诗','tang','','[]','自古東西路，舟車此地分。',48,'全唐诗/poet.tang.40000.json','["自古東西路，舟車此地分。", "河聲梁苑夜，草色楚田曛。", "鴈已多南去，蟬猶在此聞。", "聖朝無諫獵，何計謁明君。"]'),
('89c07120-a988-4f69-9687-0ab62e6fa2bd','送友人遊蜀','喻坦之','唐','唐诗','tang','','[]','爲儒早得名，爲客不憂程。',48,'全唐诗/poet.tang.40000.json','["爲儒早得名，爲客不憂程。", "春盡離丹闕，花繁到錦城。", "雪消巴水漲，日上劍關明。", "預想迴來樹，秋蟬已數聲。"]'),
('af4d7207-2859-4ae9-9f1b-2f0833314330','留別友人書齋','喻坦之','唐','唐诗','tang','','[]','相見不相暌，一留日已西。',48,'全唐诗/poet.tang.40000.json','["相見不相暌，一留日已西。", "軒涼庭木大，巷僻鳥巢低。", "背俗修琴譜，思家話藥畦。", "卜鄰期太華，同上上方梯。"]'),
('0a93b883-a286-4cff-b440-0d0a38749ef6','題耿處士林亭','喻坦之','唐','唐诗','tang','','[]','身向閑中老，生涯本豁然。',48,'全唐诗/poet.tang.40000.json','["身向閑中老，生涯本豁然。", "草堂山水下，漁艇鳥花邊。", "窺井猨兼鹿，啼林鳥雜蟬。", "何時人事了，依此亦高眠。"]'),
('5f655743-ad8f-41db-b1cb-a440608023df','商於逢友人','喻坦之','唐','唐诗','tang','','[]','行役何時了，年年骨肉分。',48,'全唐诗/poet.tang.40000.json','["行役何時了，年年骨肉分。", "春風來漢棹，雪路入商雲。", "水險溪難定，林寒鳥異羣。", "相逢聊坐石，啼狖語中聞。"]'),
('2064ae72-e606-4bbb-88e8-31e61194cadc','灞上逢故人','喻坦之','唐','唐诗','tang','','[]','花落杏園枝，驅車問路岐。',48,'全唐诗/poet.tang.40000.json','["花落杏園枝，驅車問路岐。", "人情誰可會，身事自堪疑。", "嶽雨狂雷送，溪槎漲水吹。", "家山如此景，幾處不相隨。"]'),
('f3615a17-7056-4380-8317-5c2493b3470b','發浙江','喻坦之','唐','唐诗','tang','','[]','島嶼遍含煙，煙中濟大川。',48,'全唐诗/poet.tang.40000.json','["島嶼遍含煙，煙中濟大川。", "山城猶轉漏，沙浦已搖船。", "海曙霞浮日，江遙水合天。", "此時空闊思，翻想涉窮邊。"]'),
('0fdd594f-ab98-4c43-bbf3-2a07560c51ab','晚泊旴𣅿','喻坦之','唐','唐诗','tang','','[]','廣葦夾深流，蕭蕭到海秋。',48,'全唐诗/poet.tang.40000.json','["廣葦夾深流，蕭蕭到海秋。", "宿船橫月浦，驚鳥遶霜洲。", "雲濕淮南樹，笳清泗水樓。", "徒懸鄉國思，羈跡尚東游。"]'),
('917e73f1-6706-4c86-9cf5-323de43d5998','歸江南','喻坦之','唐','唐诗','tang','','[]','歸日值江春，看花過楚津。',48,'全唐诗/poet.tang.40000.json','["歸日值江春，看花過楚津。", "草晴蟲網遍，沙曉浪痕新。", "蓮葉初浮水，鷗雛已狎人。", "漁心慚未遂，空厭路岐塵。"]'),
('f0f96a6d-6d44-4729-aa26-9cef6a519a2f','代北言懷','喻坦之','唐','唐诗','tang','','[]','困馬榆關北，那堪落景催。',48,'全唐诗/poet.tang.40000.json','["困馬榆關北，那堪落景催。", "路行沙不絕，風與雪兼來。", "草得春猶白，鴻侵夏始迴。", "行人莫遠入，戍角有餘哀。"]'),
('a5d7ed3d-704e-415b-ab4f-e4f9e6b278cc','春遊曲江','喻坦之','唐','唐诗','tang','','[]','誤入杏花塵，晴江一看春。',48,'全唐诗/poet.tang.40000.json','["誤入杏花塵，晴江一看春。", "菰蒲雖似越，骨肉且非秦。", "曲岸藏翹鷺，垂楊拂躍鱗。", "徒憐汀草色，未是醉眠人。"]'),
('bdeeb316-5a01-432c-93f0-ef4bffe37469','和范秘書宿省中作','喻坦之','唐','唐诗','tang','','[]','清省宜寒夜，仙才稱獨吟。',48,'全唐诗/poet.tang.40000.json','["清省宜寒夜，仙才稱獨吟。", "鐘來宮轉漏，月過閤移陰。", "鶴避燈前盡，芸高幄外深。", "想知因此興，暫動憶山心。"]'),
('ee9b5cf7-035e-42fd-8499-ab7569c9bf4f','寄華陰姚少府','喻坦之','唐','唐诗','tang','','[]','泰華當公署，爲官興可知。',48,'全唐诗/poet.tang.40000.json','["泰華當公署，爲官興可知。", "硯和青靄凍，簾對白雲垂。", "峻掌光浮日，危蓮影入池。", "料於三考內，應惜德音移。"]'),
('a3113647-49aa-4045-8383-55c278e0eafc','路泊富春寄友人','喻坦之','唐','唐诗','tang','','[]','江鐘寒夕微，江鳥望巢飛。',48,'全唐诗/poet.tang.40000.json','["江鐘寒夕微，江鳥望巢飛。", "木落山城出，潮生海棹歸。", "獨吟霜島月，誰寄雪天衣。", "此別三千里，關西信更稀。"]'),
('bb8f895a-df99-4370-b9ac-081bc82f9c91','梅花','崔道融','唐','唐诗','tang','','["\u548f\u7269", "\u6885\u82b1", "\u6292\u6000", "\u548f\u7269\u8bd7"]','數萼初含雪，孤標畫本難。',48,'全唐诗/poet.tang.40000.json','["數萼初含雪，孤標畫本難。", "香中別有韻，清極不知寒。", "橫笛和愁聽，斜枝倚病看。", "朔風如解意，容易莫摧殘。"]'),
('1a13de39-0997-4e53-af27-18de3993ae90','銅雀妓二首 一','崔道融','唐','唐诗','tang','','[]','嚴妝垂玉筯，妙舞對清風。',24,'全唐诗/poet.tang.40000.json','["嚴妝垂玉筯，妙舞對清風。", "無復君王顧，春來起漸慵。"]'),
('f3f5adf4-6d02-4fdd-a379-73c647148997','銅雀妓二首 二','崔道融','唐','唐诗','tang','','[]','歌咽新翻曲，香銷舊賜衣。',24,'全唐诗/poet.tang.40000.json','["歌咽新翻曲，香銷舊賜衣。", "陵園春雨暗，不見六龍歸。"]'),
('50fbaf1f-cd4f-4db2-98e6-2fe73ce30080','春閨二首 一','崔道融','唐','唐诗','tang','','[]','寒食月明雨，落花香滿泥。',24,'全唐诗/poet.tang.40000.json','["寒食月明雨，落花香滿泥。", "佳人持錦字，無雁寄遼西。"]'),
('2e1df922-db4c-4d3c-ad59-68d7a4b07db8','春閨二首 二','崔道融','唐','唐诗','tang','','[]','欲剪宜春字，春寒入剪刀。',24,'全唐诗/poet.tang.40000.json','["欲剪宜春字，春寒入剪刀。", "遼陽在何處，莫望寄征袍。"]'),
('7abcef57-6d62-4c9f-bcbe-c1c0aa8d1657','訪僧不遇','崔道融','唐','唐诗','tang','','[]','尋僧已寂寞，林下鎖山房。',24,'全唐诗/poet.tang.40000.json','["尋僧已寂寞，林下鎖山房。", "松竹雖無語，牽衣借晚涼。"]'),
('3b807423-dbcc-430c-8b72-d4e666f43d6e','田上','崔道融','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u519c\u6c11", "\u52b3\u4f5c"]','雨足高田白，披蓑半夜耕。',24,'全唐诗/poet.tang.40000.json','["雨足高田白，披蓑半夜耕。", "人牛力俱盡，東方殊未明。"]'),
('1c98ad78-29df-486c-918b-c66d9f27427c','月夕','崔道融','唐','唐诗','tang','','[]','月上隨人意，人閑月更清。',24,'全唐诗/poet.tang.40000.json','["月上隨人意，人閑月更清。", "朱樓高百尺，不見到天明。"]'),
('12289c42-52d0-4ce0-b5e0-327f42c3cc79','槿花','崔道融','唐','唐诗','tang','','[]','槿花不見夕，一日一回新。',24,'全唐诗/poet.tang.40000.json','["槿花不見夕，一日一回新。", "東風吹桃李，須到明年春。"]'),
('e27de97c-965f-4f02-b02c-4cd4a0cb48e3','西施灘','崔道融','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6292\u60c5", "\u540a\u53e4\u4f24\u4eca", "\u8bae\u8bba"]','宰嚭亡吳國，西施陷惡名。',24,'全唐诗/poet.tang.40000.json','["宰嚭亡吳國，西施陷惡名。", "浣紗春水急，似有不平聲。"]'),
('92f7c036-50fb-4b99-985b-d57199c9dbf0','江上逢故人','崔道融','唐','唐诗','tang','','[]','故里琴樽侶，相逢近臘梅。',24,'全唐诗/poet.tang.40000.json','["故里琴樽侶，相逢近臘梅。", "江村買一醉，破淚却成咍。"]'),
('54ab8db5-ce4e-437c-b9aa-edf1ccb02193','牧豎','崔道融','唐','唐诗','tang','','["\u513f\u7ae5"]','牧豎持蓑笠，逢人氣傲然。',24,'全唐诗/poet.tang.40000.json','["牧豎持蓑笠，逢人氣傲然。", "臥牛吹短笛，耕却傍溪田。"]'),
('9cb031a7-c7d4-4e05-9fe5-2874eace3c63','過農家','崔道融','唐','唐诗','tang','','[]','欲羨農家子，秋新看刈禾。',24,'全唐诗/poet.tang.40000.json','["欲羨農家子，秋新看刈禾。", "蘇秦無負郭，六印又如何。"]'),
('e5a2c4c7-0cef-49a6-b026-48c34a99bf29','江夕','崔道融','唐','唐诗','tang','','[]','江心秋月白，起柁信潮行。',24,'全唐诗/poet.tang.40000.json','["江心秋月白，起柁信潮行。", "蛟龍化爲人，半夜吹笛聲。"]'),
('abf83bcf-e87c-4453-b884-58787c95a3dc','春墅','崔道融','唐','唐诗','tang','','[]','蛙聲近過社，農事忽已忙。',24,'全唐诗/poet.tang.40000.json','["蛙聲近過社，農事忽已忙。", "鄰婦餉田歸，不見百花芳。"]'),
('b216c7e8-8380-4bed-b78a-ced81bd10b6b','江村','崔道融','唐','唐诗','tang','','[]','日暮片帆落，江村如有情。',24,'全唐诗/poet.tang.40000.json','["日暮片帆落，江村如有情。", "獨對沙上月，滿船人睡聲。"]'),
('7ce5c7ac-64bf-4197-a4cd-78765e34546b','擬樂府子夜四時歌四首 一','崔道融','唐','唐诗','tang','','[]','吳子愛桃李，月色不到地。',24,'全唐诗/poet.tang.40000.json','["吳子愛桃李，月色不到地。", "明朝欲看花，六宮人不睡。"]'),
