('615358ae-a271-412e-9fd0-63c822b034a1','擬樂府子夜四時歌四首 三','崔道融','唐','唐诗','tang','','[]','月色明如晝，蟲聲入戶多。',24,'全唐诗/poet.tang.40000.json','["月色明如晝，蟲聲入戶多。", "狂夫自不歸，滿地無天河。"]'),
('e0b7c186-da62-4dfa-8a5f-186944ee1343','擬樂府子夜四時歌四首 四','崔道融','唐','唐诗','tang','','[]','銀缸照殘夢，零淚霑粉臆。',24,'全唐诗/poet.tang.40000.json','["銀缸照殘夢，零淚霑粉臆。", "洞房猶自寒，何況關山北。"]'),
('8816e6ae-84ad-4db1-b132-c41ce05797f1','寄人二首 一','崔道融','唐','唐诗','tang','','[]','花上斷續雨，江頭來去風。',24,'全唐诗/poet.tang.40000.json','["花上斷續雨，江頭來去風。", "相思春欲盡，未遣酒尊空。"]'),
('e1c4b0ee-27e3-4a7d-a8c1-c300a80bb39d','寄人二首 二','崔道融','唐','唐诗','tang','','["\u957f\u6c5f"]','澹澹長江水，悠悠遠客情。',24,'全唐诗/poet.tang.40000.json','["澹澹長江水，悠悠遠客情。", "落花相與恨，到地一無聲。"]'),
('b4ef7e39-4ece-44b8-825e-9ae1a179c90f','江鷗','崔道融','唐','唐诗','tang','','[]','白鳥波上棲，見人懶飛起。',24,'全唐诗/poet.tang.40000.json','["白鳥波上棲，見人懶飛起。", "爲有求魚心，不是戀江水。"]'),
('a1951ae4-c079-47e1-90e9-fc5fe1c7c98e','春晚','崔道融','唐','唐诗','tang','','[]','三月寒食時，日色濃於酒。',24,'全唐诗/poet.tang.40000.json','["三月寒食時，日色濃於酒。", "落盡牆頭花，鶯聲隔原柳。"]'),
('2a815db8-4abd-4219-aeeb-02be5d657b19','漢宮詞','崔道融','唐','唐诗','tang','','[]','獨詔胡衣出，天花落殿堂。',24,'全唐诗/poet.tang.40000.json','["獨詔胡衣出，天花落殿堂。", "他人不敢妬，垂淚向君王。"]'),
('42dfbd71-6a02-4779-b13f-90e9f9d2be42','旅行','崔道融','唐','唐诗','tang','','[]','少壯經勤苦，衰年始浪遊。',24,'全唐诗/poet.tang.40000.json','["少壯經勤苦，衰年始浪遊。", "誰憐不龜手，他處却封侯。"]'),
('265fb53a-27c6-41bb-9050-ada25e9f9ee9','班婕妤','崔道融','唐','唐诗','tang','','[]','寵極辭同輦，恩深棄後宮。',24,'全唐诗/poet.tang.40000.json','["寵極辭同輦，恩深棄後宮。", "自題秋扇後，不敢怨春風。"]'),
('68edd417-9da1-4f1a-b003-2aa0cf97e535','元日有題','崔道融','唐','唐诗','tang','','[]','十載元正酒，相歡意轉深。',24,'全唐诗/poet.tang.40000.json','["十載元正酒，相歡意轉深。", "自量麋鹿分，只合在山林。"]'),
('8f95780a-5805-4778-9005-869907237587','古樹','崔道融','唐','唐诗','tang','','[]','古樹春風入，陽和力太遲。',24,'全唐诗/poet.tang.40000.json','["古樹春風入，陽和力太遲。", "莫言生意盡，更引萬年枝。"]'),
('6a9661cf-57ca-449b-b308-69c113506170','春題二首 一','崔道融','唐','唐诗','tang','','[]','青春未得意，見花却如讐。',24,'全唐诗/poet.tang.40000.json','["青春未得意，見花却如讐。", "路逢白面郎，醉插花滿頭。"]'),
('b5feb89f-dc1b-4d9b-b523-43934ff19d07','春題二首 二','崔道融','唐','唐诗','tang','','[]','滿眼桃李花，愁人如不見。',24,'全唐诗/poet.tang.40000.json','["滿眼桃李花，愁人如不見。", "別有惜花人，東風莫吹散。"]'),
('3a56e675-4972-41f5-9b57-7a676203580a','長安春','崔道融','唐','唐诗','tang','','[]','長安牡丹開，繡轂輾晴雷。',24,'全唐诗/poet.tang.40000.json','["長安牡丹開，繡轂輾晴雷。", "若使花長在，人應看不回。"]'),
('2c67f463-679f-4c52-8e1e-dea47735aa94','病起二首 一','崔道融','唐','唐诗','tang','','[]','病起春已晚，曳筇傷綠苔。',24,'全唐诗/poet.tang.40000.json','["病起春已晚，曳筇傷綠苔。", "強攀庭樹枝，喚作花未開。"]'),
('939a80cc-e75e-499e-9251-bdeee7d598ec','病起二首 二','崔道融','唐','唐诗','tang','','[]','病起遶庭除，春泥黏屐齒。',24,'全唐诗/poet.tang.40000.json','["病起遶庭除，春泥黏屐齒。", "如從萬里來，骨肉滿面喜。"]'),
('74add4ef-98f9-4833-8e5c-062bdfbab8f7','峽路','崔道融','唐','唐诗','tang','','[]','清猨啼不住，白水下來新。',24,'全唐诗/poet.tang.40000.json','["清猨啼不住，白水下來新。", "八月莫爲客，夜長愁殺人。"]'),
('db70d0ad-809e-4236-999d-7a773d0aaf46','長門怨','崔道融','唐','唐诗','tang','','[]','長門春欲盡，明月照花枝。',24,'全唐诗/poet.tang.40000.json','["長門春欲盡，明月照花枝。", "買得相如賦，君恩不可移。"]'),
('974b9ab5-5e91-4a0c-a515-f9516043ab2d','月夕有懷','崔道融','唐','唐诗','tang','','[]','圓光照一海，遠客在孤舟。',24,'全唐诗/poet.tang.40000.json','["圓光照一海，遠客在孤舟。", "相憶無期見，中宵獨上樓。"]'),
('ac21d367-6082-451f-8c04-d00f406a7c7b','夜泊九江','崔道融','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','夜泊江門外，歡聲月裏樓。',24,'全唐诗/poet.tang.40000.json','["夜泊江門外，歡聲月裏樓。", "明朝歸去路，猶隔洞庭秋。"]'),
('cfc8ccb7-1fc2-4a61-905d-7b59c79d5571','寒食夜','崔道融','唐','唐诗','tang','','[]','滿地梨花白，風吹碎月明。',24,'全唐诗/poet.tang.40000.json','["滿地梨花白，風吹碎月明。", "大家寒食夜，獨貯望鄉情。"]'),
('1addc82e-6d17-47d7-b089-3f7273fede40','歸燕','崔道融','唐','唐诗','tang','','[]','海燕頻來去，西人獨滯留。',24,'全唐诗/poet.tang.40000.json','["海燕頻來去，西人獨滯留。", "天邊又相送，腸斷故園秋。"]'),
('9f5efe86-5e9a-4e12-9b71-73710139bd5c','長安春','崔道融','唐','唐诗','tang','','[]','珠箔映高柳，美人紅袖垂。',24,'全唐诗/poet.tang.40000.json','["珠箔映高柳，美人紅袖垂。", "忽聞半天語，不見上樓時。"]'),
('4973c3cd-702f-470d-abfa-c194e4688dca','鑾駕東回','崔道融','唐','唐诗','tang','','[]','兩川花捧御衣香，萬歲山呼輦路長。',32,'全唐诗/poet.tang.40000.json','["兩川花捧御衣香，萬歲山呼輦路長。", "天子還從馬嵬過，別無惆悵似明皇。"]'),
('1a808ecb-f462-4c8d-9ae3-b8f7e0401e8a','釣魚','崔道融','唐','唐诗','tang','','[]','閑釣江魚不釣名，瓦甌斟酒暮山青。',32,'全唐诗/poet.tang.40000.json','["閑釣江魚不釣名，瓦甌斟酒暮山青。", "醉頭倒向蘆花裏，却笑無端犯客星。"]'),
('28acff24-003a-4fd0-bf3a-b8a3a5dbfc65','西施','崔道融','唐','唐诗','tang','','[]','苧蘿山下如花女，占得姑蘇臺上春。',32,'全唐诗/poet.tang.40000.json','["苧蘿山下如花女，占得姑蘇臺上春。", "一笑不能亡敵國，五湖何處有功臣。"]'),
('2b15cfb0-61fb-4081-aa00-3504ea2c69f4','馬嵬','崔道融','唐','唐诗','tang','','[]','萬乘淒涼蜀路歸，眼前珠翠與心違。',32,'全唐诗/poet.tang.40000.json','["萬乘淒涼蜀路歸，眼前珠翠與心違。", "重華不是風流主，湘水猶傳泣二妃。"]'),
('c0695c4d-445c-4f5e-876a-66ed7276ba7c','羯鼓','崔道融','唐','唐诗','tang','','[]','華清宮裏打撩聲，供奉絲簧束手聽。',32,'全唐诗/poet.tang.40000.json','["華清宮裏打撩聲，供奉絲簧束手聽。", "寂莫鑾輿斜谷裏，是誰翻得雨淋鈴。"]'),
('bd98b37a-ab9e-4091-993a-275807aaa109','寄李左司','崔道融','唐','唐诗','tang','','[]','柏臺蘭省共清風，鳴玉朝聯夜被同。',32,'全唐诗/poet.tang.40000.json','["柏臺蘭省共清風，鳴玉朝聯夜被同。", "肯信人間有兄弟，一生長在別離中。"]'),
('a6216d09-d483-41dc-9d17-0b06080cca81','梅','崔道融','唐','唐诗','tang','','[]','溪上寒梅初滿枝，夜來霜月透芳菲。',32,'全唐诗/poet.tang.40000.json','["溪上寒梅初滿枝，夜來霜月透芳菲。", "清光寂莫思無盡，應待琴尊與解圍。"]'),
('e1e02bad-41af-4ef2-93fd-18e5b496a648','天台陳逸人','崔道融','唐','唐诗','tang','','[]','絕粒空山秋復春，欲看滄海化成塵。',32,'全唐诗/poet.tang.40000.json','["絕粒空山秋復春，欲看滄海化成塵。", "近拋三井更深去，不怕虎狼唯怕人。"]'),
('a7691e6d-8859-45d2-b4c7-36554d206f51','雪竇禪師','崔道融','唐','唐诗','tang','','[]','雪竇峰前一派懸，雪竇五月無炎天。',32,'全唐诗/poet.tang.40000.json','["雪竇峰前一派懸，雪竇五月無炎天。", "客塵半日洗欲盡，師到白頭林下禪。"]'),
('f585e4de-95f0-45f7-a34e-7c4221b6d3d4','溪上遇雨二首 一','崔道融','唐','唐诗','tang','','[]','回塘雨脚如繰絲，野禽不起沈魚飛。',32,'全唐诗/poet.tang.40000.json','["回塘雨脚如繰絲，野禽不起沈魚飛。", "耕蓑釣笠取未暇，秋田有望從淋漓。"]'),
('df968053-5d06-4c13-ac3f-5b8cf26e433f','溪上遇雨二首 二','崔道融','唐','唐诗','tang','','[]','坐看黑雲銜猛雨，噴灑前山此獨晴。',32,'全唐诗/poet.tang.40000.json','["坐看黑雲銜猛雨，噴灑前山此獨晴。", "忽驚雲雨在頭上，却是山前晚照明。"]'),
('9cf0386a-3b8e-430c-937f-2c7bb5a88634','長門怨','崔道融','唐','唐诗','tang','','[]','長門花泣一枝春，爭奈君恩別處新。',32,'全唐诗/poet.tang.40000.json','["長門花泣一枝春，爭奈君恩別處新。", "錯把黃金買詞賦，相如自是薄情人。"]'),
('c4cbf5d5-0022-4269-8b56-9a96630563d2','秋夕','崔道融','唐','唐诗','tang','','[]','自憐三十未西遊，傍山尋水過却秋。',32,'全唐诗/poet.tang.40000.json','["自憐三十未西遊，傍山尋水過却秋。", "一夜雨聲多少事，不思量盡到心頭。"]'),
('f0e62035-a049-4814-b33b-06c0a39a1368','過隆中','崔道融','唐','唐诗','tang','','[]','玄德蒼黃起臥龍，鼎分天下一言中。',32,'全唐诗/poet.tang.40000.json','["玄德蒼黃起臥龍，鼎分天下一言中。", "可憐蜀國關張後，不見商量徐庶功。"]'),
('3d4e4652-222a-4e7c-aca6-2f7dcd113df6','關下','崔道融','唐','唐诗','tang','','[]','百二山河壯帝畿，關門何事更開遲。',32,'全唐诗/poet.tang.40000.json','["百二山河壯帝畿，關門何事更開遲。", "應從漏却田文後，每度聞雞不免疑。"]'),
('8aa7a4d3-1116-4528-a746-409f534c4af2','寒食客中有懷','崔道融','唐','唐诗','tang','','[]','江上聞鶯禁火時，百花開盡柳依依。',32,'全唐诗/poet.tang.40000.json','["江上聞鶯禁火時，百花開盡柳依依。", "故園兄弟別來久，應到清明猶望歸。"]'),
('1ea4c7c1-96de-468a-b4dc-2b7ae6e1679b','溪夜','崔道融','唐','唐诗','tang','','[]','積雪消來溪水寬，滿樓明月碎琅玕。',32,'全唐诗/poet.tang.40000.json','["積雪消來溪水寬，滿樓明月碎琅玕。", "漁人拋得釣筒盡，却放輕舟下急灘。"]'),
('4c6d58fb-45bb-4da0-9a27-c47b583dffc9','山居臥疾廣利大師見訪','崔道融','唐','唐诗','tang','','[]','桐谷孫枝已上弦，野人猶臥白雲邊。',32,'全唐诗/poet.tang.40000.json','["桐谷孫枝已上弦，野人猶臥白雲邊。", "九天飛錫應相誚，三到行朝二十年。"]'),
('b19282c0-6f4c-4824-a886-31587743db98','村墅','崔道融','唐','唐诗','tang','','[]','正月二月村墅閑，餘糧未乏人心寬。',32,'全唐诗/poet.tang.40000.json','["正月二月村墅閑，餘糧未乏人心寬。", "南鄰雨中揭屋笑，酒熟數家來相看。"]'),
('a3ba3aaa-56fb-4349-8f6c-993e59c02f11','悲李拾遺二首 一','崔道融','唐','唐诗','tang','','[]','故友從來匪石心，諫多難得主恩深。',32,'全唐诗/poet.tang.40000.json','["故友從來匪石心，諫多難得主恩深。", "行朝半夜煙塵起，曉殿吁嗟一鏡沈。"]'),
('0759e765-e492-4a53-86d3-adbd90226f36','悲李拾遺二首 二','崔道融','唐','唐诗','tang','','[]','天涯時有北來塵，因話它人及故人。',32,'全唐诗/poet.tang.40000.json','["天涯時有北來塵，因話它人及故人。", "也是先皇能罪己，殿前頻得觸龍鱗。"]'),
('e90db7a5-9194-43db-999b-321a6111b8db','題李將軍傳','崔道融','唐','唐诗','tang','','[]','猨臂將軍去似飛，彎弓百步虜無遺。',32,'全唐诗/poet.tang.40000.json','["猨臂將軍去似飛，彎弓百步虜無遺。", "漢文自與封侯得，何必傷嗟不遇時。"]'),
('9f3e021b-7f42-4a98-b8da-1cd77f15ba57','酒醒','崔道融','唐','唐诗','tang','','[]','酒醒撥剔殘灰火，多少淒涼在此中。',32,'全唐诗/poet.tang.40000.json','["酒醒撥剔殘灰火，多少淒涼在此中。", "爐畔自斟還自醉，打窗深夜雪兼風。"]'),
('a60dc4e6-debb-4173-b3a9-4860533b2dd7','郊居友人相訪','崔道融','唐','唐诗','tang','','[]','柴門深掩古城秋，背郭緣溪一徑幽。',32,'全唐诗/poet.tang.40000.json','["柴門深掩古城秋，背郭緣溪一徑幽。", "不有小園新竹色，君來那肯暫淹留。"]'),
('3493b6cf-3c6e-449e-977f-e318c970d58e','鏡湖雪霽貽方干','崔道融','唐','唐诗','tang','','[]','天外曉嵐和雪望，月中歸棹帶冰行。',32,'全唐诗/poet.tang.40000.json','["天外曉嵐和雪望，月中歸棹帶冰行。", "相逢半醉吟詩苦，應抵寒猨褭樹聲。"]'),
('e067dc71-805f-4574-90f0-8405411ec5a0','秋霽','崔道融','唐','唐诗','tang','','[]','雨霽長空蕩滌清，遠山初出未知名。',32,'全唐诗/poet.tang.40000.json','["雨霽長空蕩滌清，遠山初出未知名。", "夜來江上如鉤月，時有驚魚擲浪聲。"]'),
('df58e4c6-146a-4a87-8d30-73b746131439','謝朱常侍寄貺蜀茶剡紙二首 一','崔道融','唐','唐诗','tang','','[]','瑟瑟香塵瑟瑟泉，驚風驟雨起爐煙。',32,'全唐诗/poet.tang.40000.json','["瑟瑟香塵瑟瑟泉，驚風驟雨起爐煙。", "一甌解却山中醉，便覺身輕欲上天。"]'),
('9882b179-0e51-4177-a7bd-bcbed5160927','謝朱常侍寄貺蜀茶剡紙二首 二','崔道融','唐','唐诗','tang','','[]','百幅輕明雪未融，薛家凡紙漫深紅。',32,'全唐诗/poet.tang.40000.json','["百幅輕明雪未融，薛家凡紙漫深紅。", "不應點染閑言語，留記將軍蓋世功。"]'),
('6825dad7-653d-4a02-85c0-ce50569da4bd','讀杜紫微集','崔道融','唐','唐诗','tang','','[]','紫微才調復知兵，長覺風雷筆下生。',32,'全唐诗/poet.tang.40000.json','["紫微才調復知兵，長覺風雷筆下生。", "還有枉拋心力處，多於五柳賦閑情。"]'),
('745d0d5f-a3e4-4d37-a1a1-8dce3c7c8781','寓題','崔道融','唐','唐诗','tang','','[]','海上乘查便合仙，若無仙骨未如船。',32,'全唐诗/poet.tang.40000.json','["海上乘查便合仙，若無仙骨未如船。", "人間亦有支機石，虛被聲名到洞天。"]'),
('cd25b8b0-12a6-4e4a-afd5-6d8a81d814dd','寓吟集','崔道融','唐','唐诗','tang','','[]','陶集篇篇皆有酒，崔詩句句不無杯。',32,'全唐诗/poet.tang.40000.json','["陶集篇篇皆有酒，崔詩句句不無杯。", "醉來已共身安約，讓却詩人作酒魁。"]'),
('82bb1412-3207-44e7-befd-d3ee9f3d4b96','溪居即事','崔道融','唐','唐诗','tang','','["\u4e61\u6751", "\u6292\u60c5", "\u5199\u666f"]','籬外誰家不繫船，春風吹入釣魚灣。',32,'全唐诗/poet.tang.40000.json','["籬外誰家不繫船，春風吹入釣魚灣。", "小童疑是有村客，急向柴門去却關。"]'),
('061dfcc6-b614-4c62-a405-2316d5a108be','雞','崔道融','唐','唐诗','tang','','[]','買得晨雞共雞語，常時不用等閑鳴。',32,'全唐诗/poet.tang.40000.json','["買得晨雞共雞語，常時不用等閑鳴。", "深山月黑風雨夜，欲近曉天啼一聲。"]'),
('053c7b0a-88ca-451f-84dc-76df195bc167','獻浙東柳大夫','崔道融','唐','唐诗','tang','','[]','屬城甘雨幾經春，聖主全分付越人。',32,'全唐诗/poet.tang.40000.json','["屬城甘雨幾經春，聖主全分付越人。", "俗眼不知青瑣貴，江頭爭看碧油新。"]'),
('9c5a93c9-8486-4e2c-a496-e9512e5ea123','楊柳枝詞','崔道融','唐','唐诗','tang','','[]','霧撚煙搓一索春，年年長似染來新。',32,'全唐诗/poet.tang.40000.json','["霧撚煙搓一索春，年年長似染來新。", "應須喚作風流線，繫得東西南北人。"]'),
('07f43cb8-2a57-46e7-9037-da9b7c8c5f04','楚懷王','崔道融','唐','唐诗','tang','','[]','宮花一朵掌中開，緩急翻爲敵國媒。',32,'全唐诗/poet.tang.40000.json','["宮花一朵掌中開，緩急翻爲敵國媒。", "六里江山天下笑，張儀容易去還來。"]'),
('a8ff7592-9643-4cdc-a6c3-5a8bde83b40f','對早梅寄友人二首 一','崔道融','唐','唐诗','tang','','[]','憶得前年君寄詩，海邊三見早梅詞。',32,'全唐诗/poet.tang.40000.json','["憶得前年君寄詩，海邊三見早梅詞。", "與君猶是海邊客，又見早梅花發時。"]'),
('d8351dd2-c045-42a4-ac5b-6ae504f541be','對早梅寄友人二首 二','崔道融','唐','唐诗','tang','','[]','憶得去年有遺恨，花前未醉到無花。',32,'全唐诗/poet.tang.40000.json','["憶得去年有遺恨，花前未醉到無花。", "清芳一夜月通白，先脫寒衣送酒家。"]'),
('6266f79f-b404-4018-ae32-25d31a2eadd0','句','崔道融','唐','唐诗','tang','','[]','萬里一點白，長空鳥不飛。',28,'全唐诗/poet.tang.40000.json','["萬里一點白，長空鳥不飛。", "如今却羨相如富，猶有人間四壁居。"]'),
('3b947d6b-04dc-4edd-97f1-782fe327d022','苦吟','盧延讓','唐','唐诗','tang','','[]','莫話詩中事，詩中難更無。',48,'全唐诗/poet.tang.40000.json','["莫話詩中事，詩中難更無。", "吟安一箇字，撚斷數莖鬚。", "險覓天應悶，狂搜海亦枯。", "不同文賦易，爲著者之乎。"]'),
('11602a93-e149-48e0-9efb-8a0911951926','雪','盧延讓','唐','唐诗','tang','','[]','瑞雪落紛華，隨風一向斜。',48,'全唐诗/poet.tang.40000.json','["瑞雪落紛華，隨風一向斜。", "地平鋪作月，天迥撒成花。", "客滿燒煙舍，牛牽賣炭車。", "吾皇憂挾纊，猶自問君家。"]'),
('c9c61b9a-b463-43e2-b6cd-b50deb767676','松寺','盧延讓','唐','唐诗','tang','','[]','山寺取涼當夏夜，共僧蹲坐石堦前。',64,'全唐诗/poet.tang.40000.json','["山寺取涼當夏夜，共僧蹲坐石堦前。", "兩三條電欲爲雨，七八箇星猶在天。", "衣汗稍停牀上扇，茶香時撥澗中泉。", "通宵聽論蓮華義，不藉松窗一覺眠。"]'),
('dd011c73-a35f-47cf-a44a-5410db21f04f','贈僧','盧延讓','唐','唐诗','tang','','[]','浮世浮華一斷空，偶拋煩惱到蓮宮。',64,'全唐诗/poet.tang.40000.json','["浮世浮華一斷空，偶拋煩惱到蓮宮。", "高僧解語牙無水，老鶴能飛骨有風。", "野色吟餘生竹外，山陰坐久入池中。", "禪師莫問求名苦，滋味過於食蓼蟲。"]'),
('f1402199-f1c2-4457-8db1-fe4f31568caf','逢友人赴闕','盧延讓','唐','唐诗','tang','','[]','正當天下待雍熙，丹詔徴來早爲遲。',64,'全唐诗/poet.tang.40000.json','["正當天下待雍熙，丹詔徴來早爲遲。", "倚馬才高猶愛藝，問牛心在肯容私。", "吏開黃閣排班處，民擁青門看入時。", "却笑郡人留不得，感恩唯擬立生祠。"]'),
('f723ecc8-751a-4fb8-8ae0-ef1485c35d58','哭李郢端公','盧延讓','唐','唐诗','tang','','[]','軍門半掩槐花宅，每過猶聞哭臨聲。',64,'全唐诗/poet.tang.40000.json','["軍門半掩槐花宅，每過猶聞哭臨聲。", "北固暴亡兼在路，東都權葬未歸塋。", "漸窮老僕慵看馬，著慘佳人暗理箏。", "詩侶酒徒消散盡，一場春夢越王城。"]'),
('37752376-3872-4130-b9e9-ffaf2c9e6657','謝楊尚書惠櫻桃','盧延讓','唐','唐诗','tang','','[]','滿合虛紅怕動搖，尚書知重賜櫻桃。',64,'全唐诗/poet.tang.40000.json','["滿合虛紅怕動搖，尚書知重賜櫻桃。", "揉藍尚帶新鮮葉，潑血猶殘舊折條。", "萬顆真珠輕觸破，一團甘露軟含消。", "春來老病尤珍荷，併食中腸似火燒。"]'),
('5ca58cb9-dce4-4730-92d6-d12c5d50c81d','寒食日戲贈李侍御','盧延讓','唐','唐诗','tang','','[]','十二街如市，紅塵咽不開。',24,'全唐诗/poet.tang.40000.json','["十二街如市，紅塵咽不開。", "灑蹄驄馬汗，沒處看花來。"]'),
('79c5dff5-e887-460a-a766-002473728f95','樊川寒食二首 一','盧延讓','唐','唐诗','tang','','[]','寒食權豪盡出行，一川如畫雨初晴。',32,'全唐诗/poet.tang.40000.json','["寒食權豪盡出行，一川如畫雨初晴。", "誰家絡絡游春盛，擔入花間軋軋聲。"]'),
('7d6d512f-ab71-444b-a59a-57087be8ffec','樊川寒食二首 二','盧延讓','唐','唐诗','tang','','[]','鞍馬和花總是塵，歌聲處處有佳人。',32,'全唐诗/poet.tang.40000.json','["鞍馬和花總是塵，歌聲處處有佳人。", "五陵年少麤於事，栲栳量金買斷春。"]'),
('ca59afa8-a895-413f-8296-aa45f5c5e77e','句','盧延讓','唐','唐诗','tang','','[]','只訛些子緣，應耗沒多光。',156,'全唐诗/poet.tang.40000.json','["只訛些子緣，應耗沒多光。", "臂鷹健卒懸氈帽，騎馬佳人卷畫衫。", "每過私第邀看鶴，長著公裳送上驢。", "名紙毛生五門下，家僮骨立六街中。", "雲間鬧鐸騾駝至，雪裏殘骸虎拽來。", "樹上諮諏批頰鳥，窗間壁駮叩頭蟲。", "莫欺零落殘牙齒，曾吃紅綾餅餤來。", "渡水蹇驢雙耳直，避風羸僕一肩高。", "高據襄陽播盛名，問人人道是詩星。", "涼雨打低殘菡萏，急風吹散小蜻蜓。"]'),
('34c46af4-c563-4579-b9d5-ba21cc8c6e43','示門生馬侍郎胤孫','裴皞','唐','唐诗','tang','','[]','宦途最重是文衡，天與愚夫著盛名。',32,'全唐诗/poet.tang.40000.json','["宦途最重是文衡，天與愚夫著盛名。", "三主禮闈年八十，門生門下見門生。"]'),
('8eea7761-3835-4f12-a870-8f53367f2e49','贈杜荀鶴','王希羽','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','金榜曉懸生世日，玉書潛記上升時。',32,'全唐诗/poet.tang.40000.json','["金榜曉懸生世日，玉書潛記上升時。", "九華山色高千尺，未必高於第八枝。"]'),
('b26c5161-22f5-4a5f-b324-e9f2928a73e4','宮怨二首 一','柯崇','唐','唐诗','tang','','[]','塵滿金爐不炷香，黃昏獨自立重廊。',32,'全唐诗/poet.tang.40000.json','["塵滿金爐不炷香，黃昏獨自立重廊。", "笙歌何處承恩寵，一一隨風入上陽。"]'),
('032611ff-1328-4dba-b3cf-9c02c70f7033','宮怨二首 二','柯崇','唐','唐诗','tang','','[]','長門槐柳半蕭疎，玉輦沈思恨有餘。',32,'全唐诗/poet.tang.40000.json','["長門槐柳半蕭疎，玉輦沈思恨有餘。", "紅淚漸消傾國態，黃金誰爲達相如。"]'),
('a7c1f03c-ed0b-4f82-991d-c010c6de03c4','早春池亭獨游三首 一','劉象','唐','唐诗','tang','','[]','春意送殘臘，春晴融小洲。',48,'全唐诗/poet.tang.40000.json','["春意送殘臘，春晴融小洲。", "蒲茸纔簇岸，柳頰已遮樓。", "便有杯觴興，可攄羈旅愁。", "鳧鷖亦相狎，盡日戲清流。"]'),
('04abc7f9-21aa-40bb-90e0-d134b4dd008c','早春池亭獨游三首 二','劉象','唐','唐诗','tang','','[]','清流環綠篠，清景媚虹橋。',48,'全唐诗/poet.tang.40000.json','["清流環綠篠，清景媚虹橋。", "鶯刷初遷羽，莎拳擬拆苗。", "細沙擢暖岸，淑景動和飆。", "倍憶同袍侶，相歡倒一瓢。"]'),
('42037650-82e1-41bf-9242-4f15afa08db2','早春池亭獨游三首 三','劉象','唐','唐诗','tang','','[]','一瓢歡自足，一日興偏多。',48,'全唐诗/poet.tang.40000.json','["一瓢歡自足，一日興偏多。", "幽意人先賞，疎叢蝶未過。", "知音新句苦，窺沼醉顏酡。", "萬慮從相擬，今朝欲奈何。"]'),
('8e1dbe55-0d25-4eb7-84f5-85674dfc2951','鷺鷥','劉象','唐','唐诗','tang','','[]','潔白孤高生不同，頂絲清軟冷搖風。',64,'全唐诗/poet.tang.40000.json','["潔白孤高生不同，頂絲清軟冷搖風。", "窺魚翹立荷香裏，慕侶低翻柳影中。", "幾日下巢辭紫閣，多時凝目向晴空。", "摩霄志在潛修羽，會接鑾凰別葦叢。"]'),
('6fe73140-9715-4692-9f01-056a4beccf6a','春夜二首 一','劉象','唐','唐诗','tang','','[]','幾處兵戈阻路岐，憶山心切與山違。',32,'全唐诗/poet.tang.40000.json','["幾處兵戈阻路岐，憶山心切與山違。", "時難何處披懷抱，日日日斜空醉歸。"]'),
('10152af1-e8bf-4b0c-9c68-a4ef266f738a','春夜二首 二','劉象','唐','唐诗','tang','','[]','一別杜陵歸未期，秪憑魂夢接親知。',32,'全唐诗/poet.tang.40000.json','["一別杜陵歸未期，秪憑魂夢接親知。", "近來欲睡兼難睡，夜夜夜深聞子規。"]'),
('59e1c771-c1d1-47f4-bb5a-d5a56902892b','曉登迎春閣','劉象','唐','唐诗','tang','','[]','未櫛憑欄眺錦城，煙籠萬井二江明。',32,'全唐诗/poet.tang.40000.json','["未櫛憑欄眺錦城，煙籠萬井二江明。", "香風滿閣花盈戶，樹樹樹梢啼曉鶯。"]'),
('e35b0794-45a0-4f3a-a8a9-6b68d0f2a28a','詠仙掌','劉象','唐','唐诗','tang','','[]','萬古亭亭倚碧霄，不成擎亦不成招。',32,'全唐诗/poet.tang.40000.json','["萬古亭亭倚碧霄，不成擎亦不成招。", "何如掬取天池水，灑向人間救旱苗。"]'),
('63223863-df5d-4277-b245-4cff39f7c87f','郪中感舊','劉象','唐','唐诗','tang','','[]','頃年曾住此中來，今日重游事可哀。',32,'全唐诗/poet.tang.40000.json','["頃年曾住此中來，今日重游事可哀。", "憶得幾家歡宴處，家家家業盡成灰。"]'),
('dce6d5a0-b9b3-405d-9d6a-f4bb00c2808c','白髭','劉象','唐','唐诗','tang','','[]','到處逢人求至藥，幾回染了又成絲。',32,'全唐诗/poet.tang.40000.json','["到處逢人求至藥，幾回染了又成絲。", "素絲易染髭難染，墨翟當時合泣髭。"]'),
('acc0fa45-42bd-45b9-886e-394ce63f7770','題縣令范傳真化洽亭','沈顏','唐','唐诗','tang','','[]','前有淺山，屹然如屏。',40,'全唐诗/poet.tang.40000.json','["前有淺山，屹然如屏。", "後有卑嶺，繚然如城。", "跨池左右，足以建亭。", "斯亭何名，化洽而成。"]'),
('ef77519a-bf95-4d2d-82f8-6b45675ede51','書懷寄友人','沈顏','唐','唐诗','tang','','[]','江湖勞遍尋，祗自長愁襟。',48,'全唐诗/poet.tang.40000.json','["江湖勞遍尋，祗自長愁襟。", "到處慵開口，何人可話心。", "登樓得句遠，望月抒情深。", "却憶山齋後，猿聲相伴吟。"]'),
('c1847ed8-c71b-4e23-adb5-2cb4bdfeb836','題壁','楊凝式','唐','唐诗','tang','','[]','院似禪心靜，花如覺性圓。',24,'全唐诗/poet.tang.40000.json','["院似禪心靜，花如覺性圓。", "自然知了義，爭肯學神仙。"]'),
('b45062b3-208b-4629-83e4-b5cbb0545fb3','贈張全義','楊凝式','唐','唐诗','tang','','[]','洛陽風景實堪哀，昔日曾爲瓦子堆。',32,'全唐诗/poet.tang.40000.json','["洛陽風景實堪哀，昔日曾爲瓦子堆。", "不是我公重葺理，至今猶是一堆灰。"]'),
('f6b06b80-2106-478e-9d16-34454c4fb6a1','題懷素酒狂貼後','楊凝式','唐','唐诗','tang','','[]','十年揮素學臨池，始識王公學衛非。',32,'全唐诗/poet.tang.40000.json','["十年揮素學臨池，始識王公學衛非。", "草聖未須因酒發，筆端應解化龍飛。"]'),
('33709353-14db-44a6-8853-2abfcbfd6fdb','句','楊凝式','唐','唐诗','tang','','[]','押引蝗蟲到洛京，合消郡守遠相迎。',24,'全唐诗/poet.tang.40000.json','["押引蝗蟲到洛京，合消郡守遠相迎。", "到此今經三紀春。"]'),
('c08cf828-4af2-4026-8e3f-4ad565f219eb','奉試詔用拓拔思恭爲京北收復都統','李琪','唐','唐诗','tang','','[]','飛騎經巴棧，鴻恩及夏臺。',48,'全唐诗/poet.tang.40000.json','["飛騎經巴棧，鴻恩及夏臺。", "將從天上去，人自日邊來。", "此處金門遠，何時玉輦迴。", "早平關右賊，莫待詔書催。"]'),
('ea069414-3057-4b62-ace3-b1258ed5c167','題廣愛寺楞伽山','李琪','唐','唐诗','tang','','[]','善高天外遠，方丈海中遙。',48,'全唐诗/poet.tang.40000.json','["善高天外遠，方丈海中遙。", "自有山神護，應無劫火燒。", "壞文侵古壁，飛劍出寒霄。", "何似蒼蒼色，嚴妝十七朝。"]'),
('ac426724-c5fb-45a5-9438-4a294d2dcc82','句','李琪','唐','唐诗','tang','','[]','哀痛不下詔，登封誰上書。',12,'全唐诗/poet.tang.40000.json','["哀痛不下詔，登封誰上書。"]'),
('ebd38359-8583-4024-8d49-8c9d24b4e945','寄桂帥','劉崇龜','唐','唐诗','tang','','[]','碧幢仁施合洪鈞，桂樹林前倍得春。',32,'全唐诗/poet.tang.40000.json','["碧幢仁施合洪鈞，桂樹林前倍得春。", "莫戀此時好風景，磻溪不是釣漁人。"]'),
('5b6b5efd-247f-4458-ad94-8e91be044942','席上吟','劉崇魯','唐','唐诗','tang','','[]','南行忽見李深之，手舞如蜚令不疑。',32,'全唐诗/poet.tang.40000.json','["南行忽見李深之，手舞如蜚令不疑。", "任有風流兼蘊藉，天生不似鄭都知。"]'),
('7b9570d1-808c-4adb-b0ed-11ced6affb6a','寄孫儲','孫定','唐','唐诗','tang','','[]','行行血淚灑塵襟，事逐東流渭水深。',64,'全唐诗/poet.tang.40000.json','["行行血淚灑塵襟，事逐東流渭水深。", "秋跨蹇驢風尚緊，靜投孤店日初沈。", "一枝猶挂東堂夢，千里空馳北巷心。", "明月悲歌又前去，滿城煙樹噪春禽。"]'),
('15a8ebcd-bd40-495a-8d32-f2a4730d64e5','江南行','許晝','唐','唐诗','tang','','[]','江南蕭灑地，本自與君宜。',120,'全唐诗/poet.tang.40000.json','["江南蕭灑地，本自與君宜。", "固節還同我，虛心欲待誰。", "澗泉傍借響，山木共含滋。", "粉膩蟲難篆，叢疎鳥易窺。", "盡應逢野渡，中忽見村祠。", "葉掃秋空靜，根橫古塹危。", "影迷寒靄裏，聲出夜風時。", "客棹深深過，人家遠遠移。", "游邊曾結念，到此數題詩。", "莫恨成龍晚，成龍會有期。"]'),
('2e92858e-1b32-49fb-87d7-4ccd3f21e8d5','中秋月','許晝','唐','唐诗','tang','','[]','應是蟾宮別有情，每逢秋半倍澄清。',64,'全唐诗/poet.tang.40000.json','["應是蟾宮別有情，每逢秋半倍澄清。", "清光不向此中見，白髮爭教何處生？", "閑地占將真可惜，幽窗分得始爲明。", "殷勤好長來年桂，莫遣平人道不平。"]'),
('830c5d07-a36a-4250-a13a-f07414dd3915','臨終詩','薛凖','唐','唐诗','tang','','[]','舊國深恩不易酬，又離繼母出他州。',32,'全唐诗/poet.tang.40000.json','["舊國深恩不易酬，又離繼母出他州。", "誰知天怒無因息，積媿終身乞速休。"]'),
('d1ec7c49-9bfb-40ef-8272-280670328274','觀修處士畫桃花圖歌','裴諧','唐','唐诗','tang','','[]','一從天寶王維死，于今始遇修夫子。',128,'全唐诗/poet.tang.40000.json','["一從天寶王維死，于今始遇修夫子。", "能向鮫綃四幅中，丹青暗與春爭工。", "勾芒若見應羞殺，暈綠勻紅漸分別。", "堪憐彩筆似東風，一朵一枝隨手發。", "燕支乍溼如含露，引得嬌鶯癡不去。", "多少遊蜂盡日飛，看遍花心求入處。", "工夫妙麗實奇絕，似對韶光好時節。", "偏宜留著待深冬，鋪向樓前殛霜雪。"]'),
('1dd55721-a10f-45ce-9790-b3f92cef1c14','句','裴諧','唐','唐诗','tang','','[]','風回山火斷，朝落岸冰高。',24,'全唐诗/poet.tang.40000.json','["風回山火斷，朝落岸冰高。", "名終埋不得，骨任朽何妨。"]'),
('60e7f3f5-a13c-48c4-8577-59a84f02f5bd','長安春日','曹松','唐','唐诗','tang','','[]','浩浩看花晨，六街揚遠塵。',48,'全唐诗/poet.tang.40000.json','["浩浩看花晨，六街揚遠塵。", "塵中一丈日，誰是晏眠人。", "御柳舞着水，野鸎啼破春。", "徒云多失意，猶自惜離秦。"]'),
('209fa9c9-2ea4-48e8-90dc-32bc6b35515a','慈恩寺貽楚霄上人','曹松','唐','唐诗','tang','','[]','在秦生楚思，波浪接禪關。',48,'全唐诗/poet.tang.40000.json','["在秦生楚思，波浪接禪關。", "塔礙高林鳥，窗開白日山。", "樹陰移草上，岸色透庭間。", "入內談經徹，空攜講疏還。"]'),
('dce131be-63ca-4cf6-a119-1cedadf62d2a','崇義里言懷','曹松','唐','唐诗','tang','','[]','馬蹄京洛岐，復此少閑時。',48,'全唐诗/poet.tang.40000.json','["馬蹄京洛岐，復此少閑時。", "老積滄洲夢，秋乖白閣期。", "平生五字句，一夕滿頭絲。", "把向侯門去，侯門未可知。"]'),
('75cd3b4e-f5c8-4b8f-8702-2da48ea583b4','僧院松','曹松','唐','唐诗','tang','','[]','此木韻彌全，秋霄學瑟弦。',48,'全唐诗/poet.tang.40000.json','["此木韻彌全，秋霄學瑟弦。", "空知百餘尺，未定幾多年。", "古甲磨雲拆，孤根捉地堅。", "何當拋一幹，作蓋道場前。"]'),
('4cb54f2d-1806-450f-8367-6ea7d9caeb5d','貽世','曹松','唐','唐诗','tang','','[]','富者非義取，樸風爭肯還。',48,'全唐诗/poet.tang.40000.json','["富者非義取，樸風爭肯還。", "紅塵不待曉，白首有誰閒。", "淺度四溟水，平看諸國山。", "只消年作劫，俱到總無間。"]'),
('76035e48-29d5-4bf5-a24e-5d32279e8f1f','南遊','曹松','唐','唐诗','tang','','[]','直到南箕下，方諳漲海頭。',48,'全唐诗/poet.tang.40000.json','["直到南箕下，方諳漲海頭。", "君恩過銅柱，戎節限交州。", "犀占花陰臥，波衝瘴色流。", "遠夷非不樂，自是北人愁。"]'),
('4eba9433-c4e8-4ec2-8068-eb334a584a8c','送胡中丞使日東','曹松','唐','唐诗','tang','','[]','辭天理玉簪，指日使雞林。',48,'全唐诗/poet.tang.40000.json','["辭天理玉簪，指日使雞林。", "猶有中華戀，方同積浪深。", "張帆度鯨口，銜命見臣心。", "渥澤遐宣後，歸期抵萬金。"]'),
('1ef5d938-b410-448e-9349-0592d63d315f','哭陳陶處士','曹松','唐','唐诗','tang','','[]','園裏先生塚，鳥啼春更傷。',48,'全唐诗/poet.tang.40000.json','["園裏先生塚，鳥啼春更傷。", "空餘八封樹，尚對一茅堂。", "白日埋杜甫，皇天無耒陽。", "如何稽古力，報答甚茫茫。"]'),
('e65be977-d851-44bf-9d2d-2ea3acbd7cca','言懷','曹松','唐','唐诗','tang','','[]','冥心坐似癡，寢食亦如遺。',48,'全唐诗/poet.tang.40000.json','["冥心坐似癡，寢食亦如遺。", "爲覓出人句，秪求當路知。", "豈能窮到老，未信達無時。", "此道須天付，三光幸不私。"]'),
('bdb48263-ea8d-41b9-a4fa-bad775efa136','月','曹松','唐','唐诗','tang','','[]','寥寥天地內，夜魄爽何輕。',48,'全唐诗/poet.tang.40000.json','["寥寥天地內，夜魄爽何輕。", "頻見此輪滿，即應華髮生。", "不圓爭得破，纔正又須傾。", "人事還如此，因知倚伏情。"]'),
('a7c1295e-cd08-416e-a6ed-60b1d21f1607','答匡山僧贈榔栗杖','曹松','唐','唐诗','tang','','["\u5e90\u5c71"]','栗杖出匡頂，百中無一枝。',48,'全唐诗/poet.tang.40000.json','["栗杖出匡頂，百中無一枝。", "雖因野僧得，猶畏嶽神知。", "畫月冷光在，指雲秋片移。", "宜留引蹇步，他日訪峨嵋。"]'),
('b75395ac-9670-4d1e-b67c-e5b2abc63dab','商山夜聞泉','曹松','唐','唐诗','tang','','[]','瀉月聲不斷，坐來心益閑。',48,'全唐诗/poet.tang.40000.json','["瀉月聲不斷，坐來心益閑。", "無人知落處，萬木冷空山。", "遠憶雲容外，幽疑石縫間。", "那辭通曙聽，明日度藍關。"]'),
('2f33a2ef-e183-405b-ba8a-957fba2cae6a','書懷','曹松','唐','唐诗','tang','','[]','默默守吾道，望榮來替愁。',48,'全唐诗/poet.tang.40000.json','["默默守吾道，望榮來替愁。", "吟詩應有罪，當路却如讐。", "陸海儻難溺，九霄爭便休。", "敢言名譽出，天未白吾頭。"]'),
('64cae27d-747e-4e81-9087-ab66bf4e369e','道中','曹松','唐','唐诗','tang','','[]','出門嗟世路，何日樸風歸。',48,'全唐诗/poet.tang.40000.json','["出門嗟世路，何日樸風歸。", "是處太行險，□□應解飛。", "主人厚薄禮，客子新故衣。", "所以澆浮態，多令行者違。"]'),
('4a007048-dfed-40c8-920d-886f2e978b9f','夏雲','曹松','唐','唐诗','tang','','[]','勢能成岳仞，頃刻長崔嵬。',48,'全唐诗/poet.tang.40000.json','["勢能成岳仞，頃刻長崔嵬。", "瞑鳥飛不到，野風吹得開。", "一天分萬態，立地看忘回。", "欲結暑宵雨，先聞江上雷。"]'),
('4c1c0647-10d7-48b0-a4a4-bd88242b0354','塞上行','曹松','唐','唐诗','tang','','[]','上將擁黃鬚，安西逐指呼。',48,'全唐诗/poet.tang.40000.json','["上將擁黃鬚，安西逐指呼。", "離鄉俱少壯，到磧減肌膚。", "風雪夜防塞，腥羶朝繫胡。", "爲君樂戰死，誰喜作征夫。"]'),
('37de8672-2d8c-47da-b724-7370f6380c8b','晨起','曹松','唐','唐诗','tang','','[]','曉色教不睡，卷簾清氣中。',48,'全唐诗/poet.tang.40000.json','["曉色教不睡，卷簾清氣中。", "林殘數枝月，髮冷一梳風。", "竝鳥含鐘語，欹荷隔霧空。", "莫疑營白日，道路本無窮。"]'),
('dd9de589-d088-4345-a5d0-b10232a14ecf','感世','曹松','唐','唐诗','tang','','[]','觸目盡如幻，幻中能幾時。',48,'全唐诗/poet.tang.40000.json','["觸目盡如幻，幻中能幾時。", "愁來捨行樂，事去莫吞悲。", "白髮不由己，黃金留待誰。", "耕煙得銘誌，翻爲古人思。"]'),
('93935c72-328b-40e8-a1e1-1ca0359cf040','觀華夷圖','曹松','唐','唐诗','tang','','[]','落筆勝縮地，展圖當晏寧。',48,'全唐诗/poet.tang.40000.json','["落筆勝縮地，展圖當晏寧。", "中華屬貴分，遠裔占何星。", "分寸辨諸岳，斗升觀四溟。", "長疑未到處，一一似曾經。"]'),
('08dcdae3-ed35-4cc2-9d88-20c75ed9a219','山上寒夜呈進士許棠','曹松','唐','唐诗','tang','','[]','山寒草堂暖，寂夜有良朋。',48,'全唐诗/poet.tang.40000.json','["山寒草堂暖，寂夜有良朋。", "讀易分高燭，煎茶取折冰。", "庭垂河半角，窗露月微稜。", "俱入論心地，爭無俗者憎。"]'),
('80661f8b-56df-4243-af49-1cb526e62bad','滕王閣春日晚眺','曹松','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','凌春帝子閣，偶眺日移西。',48,'全唐诗/poet.tang.40000.json','["凌春帝子閣，偶眺日移西。", "浪勢平花塢，帆陰上柳堤。", "凝嵐藏宿翼，疊鼓碎歸蹄。", "只此長吟詠，因高思不迷。"]'),
('ae9376a3-4b2e-48bf-82af-21c4e6f0faf3','鍾陵野步','曹松','唐','唐诗','tang','','[]','岡扉聊自啓，信步出波邊。',48,'全唐诗/poet.tang.40000.json','["岡扉聊自啓，信步出波邊。", "野火風吹闊，春冰鶴啄穿。", "渚檣齊驛樹，山鳥入公田。", "未創孤雲勢，空思白閣年。"]'),
('393346d5-2332-4d13-82f6-09fcaf1798f2','哭胡處士','曹松','唐','唐诗','tang','','[]','故人江閣在，重到事悠悠。',48,'全唐诗/poet.tang.40000.json','["故人江閣在，重到事悠悠。", "無爾向潭上，爲吾傾甕頭。", "空餘赤楓葉，墮落釣魚舟。", "疑是沖虛去，不爲天地囚。"]'),
('5bb52dc6-8ed8-4ee2-bfd7-4ba4313c1688','青龍寺贈雲顥法師','曹松','唐','唐诗','tang','','[]','紫檀衣且香，春殿日尤長。',48,'全唐诗/poet.tang.40000.json','["紫檀衣且香，春殿日尤長。", "此地開新講，何山鏁舊房。", "僧名喧北闕，師印續南方。", "莫惜青蓮喻，秦人聽未忘。"]'),
('55717c36-2293-4f85-84e4-e0d4bd50f27a','薦福寺贈應制白公','曹松','唐','唐诗','tang','','[]','才子紫檀衣，明君寵顧時。',48,'全唐诗/poet.tang.40000.json','["才子紫檀衣，明君寵顧時。", "講昇高座懶，書荅重臣遲。", "瓶勢傾圓頂，刀聲落碎髭。", "還聞穿內去，隨駕進新詩。"]'),
('a1b460e5-29d2-4439-ac07-cd35622d53cb','觀山寺僧穿井','曹松','唐','唐诗','tang','','[]','雲僧鑿山井，寒碧在中庭。',48,'全唐诗/poet.tang.40000.json','["雲僧鑿山井，寒碧在中庭。", "況是分嵓眼，同來下石瓶。", "旁痕終變蘚，圓影即澄星。", "異夜天龍蟄，應聞說葉經。"]'),
('97f378f3-b451-45e9-ac96-ab1a8c7d2ac3','送德光禪師','曹松','唐','唐诗','tang','','[]','天涯緣事了，又造石霜微。',48,'全唐诗/poet.tang.40000.json','["天涯緣事了，又造石霜微。", "不以千峰險，唯將獨影歸。", "有爲嫌假佛，無境是真機。", "到後流沙錫，何時更有飛。"]'),
('79b83eff-5da9-4a0f-b98b-a2944af5bffb','贈南陵李主簿','曹松','唐','唐诗','tang','','[]','外邑官同隱，寧勞短吏趨。',48,'全唐诗/poet.tang.40000.json','["外邑官同隱，寧勞短吏趨。", "看雲情自足，愛酒逸應無。", "簟席彈碁子，衣裳惹印朱。", "仍聞陂水近，亦擬掉菰蒲。"]'),
('97569e1c-7bac-4799-a644-b84a7662e152','慈恩寺東樓','曹松','唐','唐诗','tang','','[]','寺樓涼出竹，非與曲江賒。',48,'全唐诗/poet.tang.40000.json','["寺樓涼出竹，非與曲江賒。", "野火流穿苑，秦山疊入巴。", "風梢離衆葉，岸角積虛沙。", "此地鐘聲近，令人思未涯。"]'),
('fe8d8b73-ef57-40b4-8133-59517170ad6a','古塚','曹松','唐','唐诗','tang','','[]','代遠已難問，纍纍次古城。',48,'全唐诗/poet.tang.40000.json','["代遠已難問，纍纍次古城。", "民田侵不盡，客路踏還平。", "作穴蛇分蟄，依岡鹿繞行。", "唯應風雨夕，鬼火出林明。"]'),
('b8919038-49ac-45eb-8fba-e2313a2b375d','訪山友','曹松','唐','唐诗','tang','','[]','一逕通高屋，重雲翳兩原。',48,'全唐诗/poet.tang.40000.json','["一逕通高屋，重雲翳兩原。", "山寒初宿頂，泉落未知根。", "急雨洗荒壁，驚風開靜門。", "聽君吟廢夜，苦却建溪猿。"]'),
('6fbbbd13-6d29-4128-952c-96d45e353fc8','林下書懷寄建州李頻員外','曹松','唐','唐诗','tang','','[]','一從諸事嬾，海上跡宜沉。',48,'全唐诗/poet.tang.40000.json','["一從諸事嬾，海上跡宜沉。", "吾道不當路，鄙人甘入林。", "雲垂方覓鶴，月濕始收琴。", "水石南州好，誰陪刻骨吟。"]'),
('6cf5fdd1-ff56-4375-b5c9-9ddb33684b1c','猿','曹松','唐','唐诗','tang','','[]','曾宿三巴路，今來不願聽。',48,'全唐诗/poet.tang.40000.json','["曾宿三巴路，今來不願聽。", "雲根啼片白，峰頂擲尖青。", "護果憎禽啄，栖霜覷葉零。", "唯應臥嵐客，憐爾傍嵒扃。"]'),
('6e77c0a3-b739-43dd-9417-08fa13f52370','秋日送方干遊上元','曹松','唐','唐诗','tang','','[]','天高淮泗白，料子趨修程。',48,'全唐诗/poet.tang.40000.json','["天高淮泗白，料子趨修程。", "汲水疑山動，揚帆覺岸行。", "雲離京口樹，鴈入石頭城。", "後夜分遙念，諸峰霜露生。"]'),
('d1b2e5e4-d3ba-4f01-a69f-ccda3d6d3b89','哭李頻員外','曹松','唐','唐诗','tang','','[]','出麾臨建水，下世在公堂。',48,'全唐诗/poet.tang.40000.json','["出麾臨建水，下世在公堂。", "苦集休開篋，清資罷轉郎。", "瘴中無子奠，嶺外一妻孀。", "定是浮香骨，東歸就故鄉。"]'),
('73c8b7df-b2f8-4e6c-b1c4-af0d7a7f57ed','山中言事','曹松','唐','唐诗','tang','','[]','嵐靄潤窗櫺，吟詩得冷癥。',48,'全唐诗/poet.tang.40000.json','["嵐靄潤窗櫺，吟詩得冷癥。", "教餐有效藥，多媿獨行僧。", "雲濕煎茶火，冰封汲井繩。", "片扉深著掩，經國自無能。"]'),
('97921cdd-7120-4631-939b-afb9bbdb0533','送左協律京西從事','曹松','唐','唐诗','tang','','[]','辟書來幾日，遂喜就嘉招。',48,'全唐诗/poet.tang.40000.json','["辟書來幾日，遂喜就嘉招。", "猶向風沙淺，非於甸服遙。", "時平無探騎，秋靜見盤雕。", "若遣關中使，煩君問寂寥。"]'),
('40d37f93-9193-4958-b422-d1261ed999c2','望九華寄池陽太守','曹松','唐','唐诗','tang','','[]','造化峰峰異，宜教岳德謙。',48,'全唐诗/poet.tang.40000.json','["造化峰峰異，宜教岳德謙。", "靈蹤載籍古，怪刃刺雲尖。", "盤蹙陵陽壯，孤標建鄴瞻。", "霽餘堪洗目，青出謝家簷。"]'),
('d2012d85-9666-4dbb-82ee-226b91edeb41','上廣州支使王拾遺','曹松','唐','唐诗','tang','','[]','明時應不諫，天幕稱仙才。',48,'全唐诗/poet.tang.40000.json','["明時應不諫，天幕稱仙才。", "聘入關中去，人從帝側來。", "詩窗盛島嶼，檄盾照風雷。", "幾度陪旄節，營巡海色迴。"]'),
('41a19895-989b-4734-ae7e-80874480b22d','題僧松禪','曹松','唐','唐诗','tang','','[]','空山澗畔枯松樹，禪老堂頭甲乙身。',32,'全唐诗/poet.tang.40000.json','["空山澗畔枯松樹，禪老堂頭甲乙身。", "傳是昔朝僧種著，下頭應有茯苓神。"]'),
('55600dcb-b3c1-4590-97fa-59fa121fd056','贈華陰李明府','曹松','唐','唐诗','tang','','[]','佩墨縣兼清，約關西近城。',48,'全唐诗/poet.tang.40000.json','["佩墨縣兼清，約關西近城。", "三峰豈不重，厚地戴猶輕。", "雪篠欹難直，風泉噴易橫。", "須知高枕外，長是勸民耕。"]'),
('6fc0eefb-b9a8-47a0-a95c-7be6a3b2d5cc','送人庭鶴','曹松','唐','唐诗','tang','','[]','度歲休籠閉，身輕好羽儀。',48,'全唐诗/poet.tang.40000.json','["度歲休籠閉，身輕好羽儀。", "白雲□是伴，滄海得因誰。", "唳起遺殘食，盤餘在逈枝。", "條風頻雨去，只恐更相隨。"]'),
('10115706-fe66-4c99-bc40-38af61f41da2','信州聞通寺題僧砌下泉','曹松','唐','唐诗','tang','','[]','細聲從嶠足，幽淡浸香墀。',48,'全唐诗/poet.tang.40000.json','["細聲從嶠足，幽淡浸香墀。", "此境未開日，何人初見時。", "耗痕延黑蘚，淨罅吐微澌。", "應有喬梢鶴，下來當飲之。"]'),
('f886e768-fe15-439c-b0fc-a92ae1aacfc2','山中','曹松','唐','唐诗','tang','','[]','此地似商嶺，雲霞空往還。',48,'全唐诗/poet.tang.40000.json','["此地似商嶺，雲霞空往還。", "衰條難定鳥，缺月易依山。", "野色耕不盡，溪容釣自閑。", "分因多臥退，百計少相關。"]'),
('19b8ff01-829b-4c21-9259-1490faa3ff09','寄崇聖寺僧','曹松','唐','唐诗','tang','','[]','不醉長安酒，冥心只似師。',48,'全唐诗/poet.tang.40000.json','["不醉長安酒，冥心只似師。", "望山吟過日，伴鶴立多時。", "溝遠流聲細，林寒綠色遲。", "菴西蘿月夕，重約語空期。"]'),
('e06eb027-c492-48ef-a60d-31a52ca2ac24','金陵道中寄','曹松','唐','唐诗','tang','','[]','忍苦待知音，無時省廢吟。',48,'全唐诗/poet.tang.40000.json','["忍苦待知音，無時省廢吟。", "始爲分路客，莫問向隅心。", "嶠翠藏幽瀑，枝風下曉禽。", "憶君秋欲盡，馬上秣陵砧。"]'),
('1846657b-f3c8-468b-bbd1-7cecc99e852f','都門送許棠東歸','曹松','唐','唐诗','tang','','["\u9ec4\u6cb3"]','舊客東歸遠，長安詩少朋。',48,'全唐诗/poet.tang.40000.json','["舊客東歸遠，長安詩少朋。", "去愁分磧鴈，行計逐鄉僧。", "華岳無時雪，黃河漫處冰。", "知辭國門路，片席認西陵。"]'),
('296599ef-2153-41b5-9935-7ec87711e0d1','送進士喻坦之遊太原','曹松','唐','唐诗','tang','','[]','北鄙征難盡，詩愁滿去程。',48,'全唐诗/poet.tang.40000.json','["北鄙征難盡，詩愁滿去程。", "廢巢侵燒色，荒塚入鋤聲。", "逗野河流濁，離雲磧日明。", "幷州戎壘地，角動引風生。"]'),
('01be89cd-516b-4fb0-a4ba-4a6af88d2c66','九江暮春書事','曹松','唐','唐诗','tang','','[]','楊柳城初鏁，輪蹄息去蹤。',48,'全唐诗/poet.tang.40000.json','["楊柳城初鏁，輪蹄息去蹤。", "春流無舊岸，夜色失諸峰。", "影動漁邊火，聲遲話後鐘。", "明朝廻去鴈，誰向北郊逢。"]'),
('cf601b26-e0ba-4acd-bda4-d6b786631b43','再到洪州望西山','曹松','唐','唐诗','tang','','[]','洪州向西顧，不忍暫忘君。',48,'全唐诗/poet.tang.40000.json','["洪州向西顧，不忍暫忘君。", "記得瀑泉落，省同幽鳥聞。", "一廻經雨雹，長有剩風雲。", "未定却栖息，前頭江海分。"]'),
('725fe5df-06bf-467d-9db2-1b37c9ec7130','與胡汾坐月期貫休上人不至','曹松','唐','唐诗','tang','','[]','掃庭秋漏滴，接話貴忘眠。',48,'全唐诗/poet.tang.40000.json','["掃庭秋漏滴，接話貴忘眠。", "靜夜人相語，低枝鳥暗遷。", "星圍南極定，月照斷河連。", "後會花宮子，應開石上禪。"]'),
('550ac225-1211-41b3-aafc-7b60bcf9303a','贈胡處士','曹松','唐','唐诗','tang','','[]','年光離岳色，帶疾臥南原。',48,'全唐诗/poet.tang.40000.json','["年光離岳色，帶疾臥南原。", "白日與無事，俗人嗔閉門。", "樵魚臨片水，野鹿入荒園。", "莫問榮華事，清霜點髮根。"]'),
('b3bb9f9e-afcd-494f-acfd-d97741107ae2','鉛山寫懷','曹松','唐','唐诗','tang','','[]','天涯兵火後，風景畏臨門。',48,'全唐诗/poet.tang.40000.json','["天涯兵火後，風景畏臨門。", "骨肉到時節，團圓因夢魂。", "池塘營水眼，嶺嶠結花根。", "耳縱聽歌吹，中心不可論。"]'),
('db7feb9c-1557-4c6c-ad74-3200eb898387','書翠巖寺壁','曹松','唐','唐诗','tang','','[]','何年話尊宿，瞻禮此堂中。',48,'全唐诗/poet.tang.40000.json','["何年話尊宿，瞻禮此堂中。", "入郭非無路，歸林自學空。", "濺瓶雲嶠水，逆磬雪川風。", "時說南廬事，知師用意同。"]'),
('962d8cdd-c257-404e-90f9-fca1c605d3f6','江西題東湖','曹松','唐','唐诗','tang','','[]','鑿出江湖思，涼多□□間。',48,'全唐诗/poet.tang.40000.json','["鑿出江湖思，涼多□□間。", "無風觸微浪，半日□秋山。", "客袖沙光滿，船窗荻影閑。", "時人見黃綬，應笑狎鷗還。"]'),
('2c8f8fb5-bd7c-4570-a04e-572d14b7b615','題湖南岳麓寺','曹松','唐','唐诗','tang','','[]','海雲山上寺，每到每開襟。',48,'全唐诗/poet.tang.40000.json','["海雲山上寺，每到每開襟。", "萬木長不住，細泉聽更深。", "蜩沾高雨斷，鳥遇夕嵐沈。", "此地良宵月，秋懷隔楚砧。"]'),
('50e7f8af-e26e-492f-882b-6d2c66c9b006','贈衡山麋明府','曹松','唐','唐诗','tang','','["\u8861\u5c71"]','爲縣瀟湘水，門前樹配苔。',48,'全唐诗/poet.tang.40000.json','["爲縣瀟湘水，門前樹配苔。", "晚吟公籍少，春醉積林開。", "滌硯松香起，擎茶岳影來。", "任官當此境，更莫夢天台。"]'),
('cd11f011-f6e5-4e30-b06e-6e9f5222675b','塞上','曹松','唐','唐诗','tang','','[]','邊寒來所闊，今日復明朝。',48,'全唐诗/poet.tang.40000.json','["邊寒來所闊，今日復明朝。", "河凌堅通馬，胡雲缺見雕。", "砂中程獨泣，鄉外隱誰招。", "廻首若經歲，靈州生柳條。"]'),
('6772e8e6-24c8-438e-86d5-e670bee44602','送邵安石及第歸連州覲省','曹松','唐','唐诗','tang','','[]','及第兼歸覲，宜忘涉驛勞。',48,'全唐诗/poet.tang.40000.json','["及第兼歸覲，宜忘涉驛勞。", "青雲重慶少，白日一飛高。", "轉楚聞啼狖，臨湘見疊濤。", "海陽沈飲罷，何地佐旌旄。"]'),
('33de29ff-0129-4ff6-a175-529713d046c0','邊上送友人歸寧','曹松','唐','唐诗','tang','','[]','鄉路穿京過，寧心去少同。',48,'全唐诗/poet.tang.40000.json','["鄉路穿京過，寧心去少同。", "日斜尋闊磧，春盡逐歸鴻。", "獨樹河聲外，凝笳塞色中。", "憐君到此處，却背老萊風。"]'),
('13271d26-4e05-4c92-9081-fc65dea31af2','除夜','曹松','唐','唐诗','tang','','[]','殘臘即又盡，東風應漸聞。',48,'全唐诗/poet.tang.40000.json','["殘臘即又盡，東風應漸聞。", "一宵猶幾許，兩歲欲平分。", "燎暗傾時斗，春通綻處芬。", "明朝遙捧酒，先合祝堯君。"]'),
('bf35e867-fc2c-4bee-9587-c0e55c19a102','題甘露寺','曹松','唐','唐诗','tang','','[]','香門接巨壘，畫角間清鐘。',48,'全唐诗/poet.tang.40000.json','["香門接巨壘，畫角間清鐘。", "北固一何峭，西僧多此逢。", "天垂無際海，雲白久晴峰。", "旦暮然燈外，濤頭振蟄龍。"]'),
('bffe88b3-c216-4a63-b137-87b8afe3abd4','貽住山僧','曹松','唐','唐诗','tang','','[]','罷講巡巖塢，無窮得野情。',48,'全唐诗/poet.tang.40000.json','["罷講巡巖塢，無窮得野情。", "臘高猶伴鹿，夏滿不歸城。", "雲朵緣崖發，峰陰截水清。", "自然雙洗耳，唯任白毫生。"]'),
('780c912d-bd36-4ad3-8df3-ae32333781ad','題鶴鳴泉','曹松','唐','唐诗','tang','','[]','仙鶴曾鳴處，泉兼半井苔。',48,'全唐诗/poet.tang.40000.json','["仙鶴曾鳴處，泉兼半井苔。", "直峰拋影入，片月瀉光來。", "瀲灩侵顏冷，深沉慰眼開。", "何因值舟頂，滿汲石瓶廻。"]'),
('4fc522fa-ef96-4126-a6f8-d6a2447f22e4','吊賈島二首 一','曹松','唐','唐诗','tang','','[]','先生不折桂，謫去抱何冤。',48,'全唐诗/poet.tang.40000.json','["先生不折桂，謫去抱何冤。", "已葬離燕骨，難招入劒魂。", "旅墳低却草，稚子哭勝猿。", "冥寞如搜句，宜邀賀監論。"]'),
('cd75d9b9-3cbb-4ae5-8d24-297b9ce2475f','吊賈島二首 二','曹松','唐','唐诗','tang','','[]','青斾低寒水，清笳出曉風。',48,'全唐诗/poet.tang.40000.json','["青斾低寒水，清笳出曉風。", "鳥來傷賈傅，馬立葬滕公。", "松柏青山上，城池白日中。", "一朝今古隔，惟有月明同。"]'),
('ff2789f2-da3b-47e1-803b-a1f9840a5516','憶江西幷悼亡友','曹松','唐','唐诗','tang','','[]','前心奈兵阻，悔作豫章分。',48,'全唐诗/poet.tang.40000.json','["前心奈兵阻，悔作豫章分。", "芳草未歸日，故人多是墳。", "帆行出岫雨，馬踐過江雲。", "此地一罇酒，當時皆以文。"]'),
('4186eec5-32e2-40c7-bf47-e1d5b43d06c1','九江送方干歸鏡湖','曹松','唐','唐诗','tang','','[]','一檣懸五兩，此日動歸風。',48,'全唐诗/poet.tang.40000.json','["一檣懸五兩，此日動歸風。", "客路拋湓口，家林入鏡中。", "譚餘雲出嶠，詠苦月欹空。", "更若看鳷鵲，何人夜坐同。"]'),
('be9ffd27-0274-40de-8b93-8f3ccaf5b3f4','廬山訪賈匡','曹松','唐','唐诗','tang','','["\u5e90\u5c71"]','西城疾病日，此地少尋君。',48,'全唐诗/poet.tang.40000.json','["西城疾病日，此地少尋君。", "古跡春猶在，遙泉夜盡聞。", "片時三處雨，九疊幾重雲。", "到者皆忘寐，神精與俗分。"]'),
('292ee42d-4b82-45b7-9b1a-c9abd0b7d389','顧少府池上','曹松','唐','唐诗','tang','','[]','池上分行種，公庭覺少塵。',48,'全唐诗/poet.tang.40000.json','["池上分行種，公庭覺少塵。", "根離潮水岸，韻爽判曹人。", "正午廻魚影，方昏息鷺身。", "無時不動詠，滄島思方頻。"]'),
('34fa182b-b19e-4847-b527-d42949e34b24','喜友人歸上元別業','曹松','唐','唐诗','tang','','[]','一檣千里外，隱者興宜孤。',48,'全唐诗/poet.tang.40000.json','["一檣千里外，隱者興宜孤。", "落日長邊海，秋風滿故都。", "掩關苔色老，盤逕葉聲枯。", "匡岳來時過，遲廻絕頂無。"]'),
('8be69b7d-175e-44f0-bd5a-7f1fe621029d','曲江暮春雪霽','曹松','唐','唐诗','tang','','[]','霽動江池色，春殘一去游。',48,'全唐诗/poet.tang.40000.json','["霽動江池色，春殘一去游。", "菰風生馬足，槐雪滴人頭。", "北闕塵未起，南山青欲流。", "如何多別地，却得醉汀洲。"]'),
('e7545c49-8015-4658-a29a-24c21e35a15b','立春日','曹松','唐','唐诗','tang','','[]','春飲一杯酒，便吟春日詩。',48,'全唐诗/poet.tang.40000.json','["春飲一杯酒，便吟春日詩。", "木梢寒未覺，地脉暖先知。", "鳥囀星沈後，山分雪薄時。", "賞心無處說，悵望曲江池。"]'),
('aacd7716-148f-4c14-a986-d5f80b59806d','宿溪僧院','曹松','唐','唐诗','tang','','[]','少年雲溪裏，禪心夜更閑。',48,'全唐诗/poet.tang.40000.json','["少年雲溪裏，禪心夜更閑。", "煎茶留靜者，靠月坐蒼山。", "露白鐘尋定，螢多戶未關。", "嵩陽大石室，何日譯經還。"]'),
('8bc793e3-a62f-4f09-ad26-aaac9155b867','石頭懷古','曹松','唐','唐诗','tang','','[]','日月出又沒，臺城空白雲。',48,'全唐诗/poet.tang.40000.json','["日月出又沒，臺城空白雲。", "雖寬百姓土，漸缺六朝墳。", "禾黍是亡國，山河歸聖君。", "松聲驟雨足，幾寺晚鐘聞。"]'),
('76e250b1-36a6-4409-bbc4-d1f972174fd6','浙右贈陸處士','曹松','唐','唐诗','tang','','[]','靜節灌園餘，得非成隱居。',48,'全唐诗/poet.tang.40000.json','["靜節灌園餘，得非成隱居。", "長當庚子日，獨拜五經書。", "白浪吹亡國，秋霜洗大虛。", "門前是京口，身外不營儲。"]'),
('814e7769-7855-4fbe-87a9-ad85e3f78933','哭胡處士','曹松','唐','唐诗','tang','','[]','丘中久不起，將謂詔書來。',48,'全唐诗/poet.tang.40000.json','["丘中久不起，將謂詔書來。", "及見凌雲說，方知掩夜臺。", "白衣歸北路，玄造亦遺才。", "世上亡君後，詩聲更大哉。"]'),
('d0eb8238-13ab-4dce-9ade-9fdc54d7da4e','贈餘干袁明府','曹松','唐','唐诗','tang','','[]','一雨西城色，陶家心自清。',48,'全唐诗/poet.tang.40000.json','["一雨西城色，陶家心自清。", "山銜中郭分，雲卷下湖程。", "公署聞流木，人煙入廢城。", "難忘楚盡處，新有越吟生。"]'),
('29f8767f-121a-4b06-a6e3-1c2ec9872e93','贈雷鄉張明府','曹松','唐','唐诗','tang','','[]','任官征戰後，度日寄閑身。',48,'全唐诗/poet.tang.40000.json','["任官征戰後，度日寄閑身。", "封卷還高客，飛書問野人。", "廢田教種糓，生路遣尋薪。", "若起柴桑興，無先漉酒巾。"]'),
('d6bfd7cb-d5b9-4e39-b847-d1fc8302e142','岳陽晚泊','曹松','唐','唐诗','tang','','[]','輕帆下闊流，便泊此沙洲。',48,'全唐诗/poet.tang.40000.json','["輕帆下闊流，便泊此沙洲。", "湖影撼山朵，日陽燒野愁。", "白波爭起倒，青嶼或沈浮。", "是際船中望，東南仞仞秋。"]'),
('3e188e47-e2bf-484a-b003-b09270b4e6ff','覽春牓喜孫鄠成名','曹松','唐','唐诗','tang','','[]','門外報春牓，喜君天子知。',48,'全唐诗/poet.tang.40000.json','["門外報春牓，喜君天子知。", "舊愁渾似雪，見日總消時。", "塔下牡丹氣，江頭楊柳絲。", "風光若有分，無處不相宜。"]'),
('24f669eb-0f37-456f-abfc-39cd19a2827b','己亥歲二首 一','曹松','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11"]','澤國江山入戰圖，生民何計樂樵蘇。',32,'全唐诗/poet.tang.40000.json','["澤國江山入戰圖，生民何計樂樵蘇。", "憑君莫話封侯事，一將功成萬骨枯。"]'),
('dab08f3b-40af-4386-8737-024c2e437746','己亥歲二首 二','曹松','唐','唐诗','tang','','[]','傳聞一戰百神愁，兩岸彊兵過未休。',32,'全唐诗/poet.tang.40000.json','["傳聞一戰百神愁，兩岸彊兵過未休。", "誰道滄江總無事，近來長共血爭流。"]'),
('440c408d-c86d-4e0c-8526-99eb7c6429d0','亂後入洪州西山','曹松','唐','唐诗','tang','','[]','寂寂陰溪水漱苔，塵中將得苦吟來。',32,'全唐诗/poet.tang.40000.json','["寂寂陰溪水漱苔，塵中將得苦吟來。", "東峰道士如相問，縣令而今不姓梅。"]'),
('9ccfc68d-2834-4aae-b4d1-5d6c16d65094','送僧入廬山','曹松','唐','唐诗','tang','','["\u5e90\u5c71"]','若到江州二林寺，遍遊應未出雲霞。',32,'全唐诗/poet.tang.40000.json','["若到江州二林寺，遍遊應未出雲霞。", "廬山瀑布三千仞，畫破青霄始落斜。"]'),
('2ad4fdb7-78f8-4346-a818-4aece9b30ece','送僧入蜀過夏','曹松','唐','唐诗','tang','','[]','師言結夏入巴峰，雲水廻頭幾萬重。',32,'全唐诗/poet.tang.40000.json','["師言結夏入巴峰，雲水廻頭幾萬重。", "五月峨眉須近火，木皮領重只如冬。"]'),
('16dae25b-9b11-426c-a12a-f6e8f3e92cee','江西逢僧省文 一','曹松','唐','唐诗','tang','','[]','閩地高僧楚地逢，僧遊蠻錫挂垂松。',32,'全唐诗/poet.tang.40000.json','["閩地高僧楚地逢，僧遊蠻錫挂垂松。", "白雲逸性都無定，纔出雙峰愛五峰。"]'),
('ae603c61-4407-42e2-ac48-531173ad84d2','江西逢僧省文 二','曹松','唐','唐诗','tang','','[]','高僧不負雪峰期，却伴青霞入翠微。',64,'全唐诗/poet.tang.40000.json','["高僧不負雪峰期，却伴青霞入翠微。", "百葉巖前霜欲降，九枝松上鶴初歸。", "風生碧澗魚龍躍，威振金樓燕雀飛。", "想得白蓮花上月，滿山猶帶舊光輝。"]'),
('c4f3de8c-3a99-4972-8b4f-5db1e3d842ff','水精念珠','曹松','唐','唐诗','tang','','[]','等量紅縷貫晶熒，盡道勻圓別未勝。',66,'全唐诗/poet.tang.40000.json','["等量紅縷貫晶熒，盡道勻圓別未勝。", "鑿斷玉潭盈尺水，琢成金地兩條冰。", "輪時秪恐星侵佛，掛處常疑露滴僧。", "幾度夜深尋不著，瑠[瓈]爲殿月爲燈。"]'),
('c6b6a68f-07a9-4a33-a026-712d302704ee','南海旅次','曹松','唐','唐诗','tang','','[]','憶歸休上越王臺，歸思臨高不易裁。',64,'全唐诗/poet.tang.40000.json','["憶歸休上越王臺，歸思臨高不易裁。", "爲客正當無鴈處，故園誰道有書來。", "城頭早角吹霜盡，郭裏殘潮蕩月回。", "心似百花開未得，年年爭發被春催。"]'),
('c76a81f0-8853-4e1e-b053-bcce57a84681','春草','曹松','唐','唐诗','tang','','[]','不獨滿池塘，夢中佳句香。',24,'全唐诗/poet.tang.40000.json','["不獨滿池塘，夢中佳句香。", "春風有餘力，引上古城牆。"]'),
('507eda7a-f94e-41cc-aefd-e6cbdec7c5a8','金谷園','曹松','唐','唐诗','tang','','[]','當年歌舞時，不說草離離。',24,'全唐诗/poet.tang.40000.json','["當年歌舞時，不說草離離。", "今日歌舞盡，滿園秋露垂。"]'),
('2d614385-94d5-4f15-b763-f186f2c39b8f','夏日東齋','曹松','唐','唐诗','tang','','[]','三庚到秋伏，偶來松檻立。',24,'全唐诗/poet.tang.40000.json','["三庚到秋伏，偶來松檻立。", "熱少清風多，開門放山入。"]'),
('2554156a-583a-4ea5-871a-818c402a71f4','南朝','曹松','唐','唐诗','tang','','[]','三籬蓋馳道，風烈一無取。',24,'全唐诗/poet.tang.40000.json','["三籬蓋馳道，風烈一無取。", "時見牧牛童，嗔牛喫禾黍。"]'),
('33b9e3f4-1b46-4ffc-81ef-fe000d21bba1','言懷','曹松','唐','唐诗','tang','','[]','出山不得意，謁帝值戈鋋。',24,'全唐诗/poet.tang.40000.json','["出山不得意，謁帝值戈鋋。", "豈料爲文日，翻成用武年。"]'),
('8c993f97-ee32-4756-8db7-df0514aa7c5d','寒食日題杜鵑花','曹松','唐','唐诗','tang','','[]','一朵又一朵，併開寒食時。',24,'全唐诗/poet.tang.40000.json','["一朵又一朵，併開寒食時。", "誰家不禁火，總在此花枝。"]'),
('cc3cb6b6-1b88-4007-91db-39554026921b','鍾陵寒食日郊外閑游','曹松','唐','唐诗','tang','','[]','可憐時節足風情，杏子粥香如冷餳。',32,'全唐诗/poet.tang.40000.json','["可憐時節足風情，杏子粥香如冷餳。", "無奈春風輸舊火，遍教人喚作山櫻。"]'),
('90d2bd20-6aa8-4d27-913d-67f63d889d4b','中秋對月','曹松','唐','唐诗','tang','','["\u6708\u4eae", "\u4e2d\u79cb\u8282"]','無雲世界秋三五，共看蟾盤上海涯。',32,'全唐诗/poet.tang.40000.json','["無雲世界秋三五，共看蟾盤上海涯。", "直到天頭天盡處，不曾私照一人家。"]'),
('27d31544-eddd-49ca-a1ea-a08dff1b37c9','陪湖南李中丞宴隱溪','曹松','唐','唐诗','tang','','[]','竹林啼鳥不知休，羅列飛橋水亂流。',64,'全唐诗/poet.tang.40000.json','["竹林啼鳥不知休，羅列飛橋水亂流。", "觸散柳絲回玉勒，約開蓮葉上蘭舟。", "酒邊舊侶真何遜，雲裏新聲是莫愁。", "若值主人嫌晝短，應陪秉燭夜深遊。"]'),
('65fad1eb-68f1-4230-9c76-baf6e4e55731','別湖上主人','曹松','唐','唐诗','tang','','[]','門繫釣舟雲滿岸，借君幽致坐移旬。',64,'全唐诗/poet.tang.40000.json','["門繫釣舟雲滿岸，借君幽致坐移旬。", "湖村夜呌白蕪鴈，菱市曉喧深浦人。", "遠水日邊重作雪，寒林燒後別生春。", "不辭更住醒還醉，太一東峰歸夢頻。"]'),
('252223d3-2767-494c-995c-0b4811e69549','贈廣宣大師','曹松','唐','唐诗','tang','','[]','憶昔同游紫閣雲，別來三十二回春。',32,'全唐诗/poet.tang.40000.json','["憶昔同游紫閣雲，別來三十二回春。", "白頭相見雙林下，猶是清朝未退人。"]'),
('a11911ea-7387-4848-a102-6c0808b9375d','鍾陵寒食日與同年裴顏李先輩鄭校書郊外閑游','曹松','唐','唐诗','tang','','[]','寒節鍾陵香騎隨，同年相命楚江湄。',64,'全唐诗/poet.tang.40000.json','["寒節鍾陵香騎隨，同年相命楚江湄。", "雲間影過鞦韆女，地上聲喧蹴踘兒。", "何處寄烟歸草色，誰家送火在花枝。", "銀瓶冷酒皆傾盡，半臥垂楊自不知。"]'),
('96b9012d-793b-4097-8ae8-e13582efb7bc','江外除夜','曹松','唐','唐诗','tang','','[]','千門庭燎照樓臺，總爲年光急急催。',64,'全唐诗/poet.tang.40000.json','["千門庭燎照樓臺，總爲年光急急催。", "半夜臘因風卷去，五更春被角吹來。", "寧無好鳥思花發，應有遊魚待凍開。", "不是多歧漸平穩，誰能呼酒祝昭回。"]'),
('a09a4098-9b28-418f-9eb3-4b279576c06f','七夕','曹松','唐','唐诗','tang','','[]','牛女相期七夕秋，相逢俱喜鵲橫流。',64,'全唐诗/poet.tang.40000.json','["牛女相期七夕秋，相逢俱喜鵲橫流。", "彤雲縹緲廻金輅，明月嬋娟掛玉鉤。", "燕羽幾曾添別恨，花容終不更含羞。", "更殘便是分襟處，曉箭東來射翠樓。"]'),
('ad43450a-e60d-4c45-8329-a5901ea0b063','羅浮山下書逸人壁','曹松','唐','唐诗','tang','','[]','海上亭臺山下烟，買時幽邃不爭錢。',64,'全唐诗/poet.tang.40000.json','["海上亭臺山下烟，買時幽邃不爭錢。", "莫言白日催華髮，自有丹砂駐少年。", "漁釣未歸深竹裏，琴壺猶戀落花邊。", "可中更踐無人境，知是羅浮第幾天。"]'),
('e3381503-fa01-421e-844d-f5001c50b7cc','天台瀑布','曹松','唐','唐诗','tang','','[]','萬仞得名云瀑布，遠看如織掛天台。',64,'全唐诗/poet.tang.40000.json','["萬仞得名云瀑布，遠看如織掛天台。", "休疑寶尺難量度，直恐金刀易剪裁。", "噴向林梢成夏雪，傾來石上作春雷。", "欲知便是銀河水，墮落人間合却廻。"]'),
('9002cdd8-2064-4d05-a6e1-3108c767644f','桂江','曹松','唐','唐诗','tang','','[]','未識佳人尋桂水，水雲先解傍壺觴。',64,'全唐诗/poet.tang.40000.json','["未識佳人尋桂水，水雲先解傍壺觴。", "笋林次第添斑竹，雛鳥參差護錦囊。", "乳洞此時連越井，石樓何日到僊鄉。", "如飛似墮皆青壁，畫手不強元化強。"]'),
('536de45e-a0e5-45ba-8b5c-a102944c3ef3','南海','曹松','唐','唐诗','tang','','[]','傾騰界漢沃諸蠻，立望何如畫此看。',64,'全唐诗/poet.tang.40000.json','["傾騰界漢沃諸蠻，立望何如畫此看。", "無地不同方覺遠，共天無別始知寬。", "文魮隔霧朝含碧，老蚌凌波夜吐丹。", "萬狀千形皆得意，長鯨獨自轉身難。"]'),
('52aacc69-47b6-499a-94a5-3b66eed1b276','洞庭湖','曹松','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','東西南北各連空，波上唯留小朵峰。',64,'全唐诗/poet.tang.40000.json','["東西南北各連空，波上唯留小朵峰。", "長與岳陽翻鼓角，不離雲夢轉魚龍。", "吸廻日月過千頃，鋪盡星河剩一重。", "直到劫餘還作陸，是時應有羽人逢。"]'),
('6b2223b1-f7db-4623-99e0-8b171cb0392c','霍山','曹松','唐','唐诗','tang','','[]','七千七百七十丈，丈丈藤蘿勢入天。',64,'全唐诗/poet.tang.40000.json','["七千七百七十丈，丈丈藤蘿勢入天。", "未必展來空似翅，不妨開去也成蓮。", "月將河漢分巖轉，僧與龍蛇共窟眠。", "直是畫工須閣筆，況無名畫可流傳。"]'),
('70d15de4-e38a-4449-bd14-86c7b60df075','巫峽','曹松','唐','唐诗','tang','','[]','巫山蒼翠峽通津，下有仙宮楚女真。',64,'全唐诗/poet.tang.40000.json','["巫山蒼翠峽通津，下有仙宮楚女真。", "不逐彩雲歸碧落，却爲暮雨撲行人。", "年年舊事音容在，日日誰家夢想頻。", "應是荆山留不住，至今猶得覩芳塵。"]'),
('baf9f108-31d6-40a5-b438-4bedd4d042d8','送陳樵校書歸泉州','曹松','唐','唐诗','tang','','[]','巨塔列名題，詩心亦罕齊。',72,'全唐诗/poet.tang.40000.json','["巨塔列名題，詩心亦罕齊。", "除官京下闕，乞假海門西。", "別席侵殘漏，歸程避戰鼙。", "關遙秦鴈斷，家近瘴雲低。", "候馬春風館，迎船曉月溪。", "帝京須早入，莫被刺桐迷。"]'),
('58e3fe8d-2241-4e07-b8d6-586e4a84820d','贈鏡湖處士方干二首 一','曹松','唐','唐诗','tang','','[]','包含教化剩搜羅，句出東甌奈峭何。',64,'全唐诗/poet.tang.40000.json','["包含教化剩搜羅，句出東甌奈峭何。", "世路不妨平處少，才人唯是屈聲多。", "雲來島上便幽石，月到湖心忌白波。", "後輩難爲措機杼，先生織字得龍梭。"]'),
('9b79b3b7-65f4-4447-b261-71104bc2c748','贈鏡湖處士方干二首 二','曹松','唐','唐诗','tang','','[]','秪擬應星眠越絕，唯將麗什當高勳。',64,'全唐诗/poet.tang.40000.json','["秪擬應星眠越絕，唯將麗什當高勳。", "磨礱清濁人難會，織絡虛無帝亦聞。", "鳥道未知山足雨，漁家已沒鏡中雲。", "他時莫爲三徴起，門外沙鷗解笑君。"]'),
('48507ceb-70ba-4016-a16d-757fca6588f8','拜訪陸處士','曹松','唐','唐诗','tang','','[]','萬卷書邊人半白，再來惟恐降玄纁。',64,'全唐诗/poet.tang.40000.json','["萬卷書邊人半白，再來惟恐降玄纁。", "性靈比鶴爭多少，氣力登山較幾分。", "吟鬢漸無前度漆，寢衣猶有昨宵雲。", "將知谷口耕烟者，低視齊梁楚趙君。"]'),
('6c5021cd-f042-408b-8dc8-9055635a8b69','嶺南道中','曹松','唐','唐诗','tang','','[]','百花成實未成歸，未必歸心與志違。',64,'全唐诗/poet.tang.40000.json','["百花成實未成歸，未必歸心與志違。", "但有壺觴資逸詠，盡交風景入清機。", "半川陰霧藏高木，一道晴蜺雜落暉。", "遊子馬前芳草合，鷓鴣啼歇又南飛。"]'),
('170982ce-64fe-49ab-8864-3be563f53501','春日自吳門之陽羨道中書事','曹松','唐','唐诗','tang','','[]','勝異恣遊應未遍，路岐猶去幾時還。',64,'全唐诗/poet.tang.40000.json','["勝異恣遊應未遍，路岐猶去幾時還。", "浪花湖闊虹蜺斷，柳線村深鳥雀閑。", "千室綺羅浮畫檝，兩州絲竹會茶山。", "眼前便是神僊事，何必須言洞府間。"]'),
('73de3c4b-708f-4016-a4d9-e1b5423f8f20','將入關行次湘陰','曹松','唐','唐诗','tang','','[]','背顧秦城在何處，圖書作伴過湘東。',64,'全唐诗/poet.tang.40000.json','["背顧秦城在何處，圖書作伴過湘東。", "神鵶亂噪黃陵近，候鴈斜沈夢澤空。", "打槳天連晴水白，燒田雲隔夜山紅。", "也知漸老巖棲穩，爭奈文闈有至公。"]'),
('5be55448-af23-40b4-967f-8429af5ff42a','題昭州山寺常寂上人水閣','曹松','唐','唐诗','tang','','[]','常寂常居常寂裏，年年月月是空空。',64,'全唐诗/poet.tang.40000.json','["常寂常居常寂裏，年年月月是空空。", "堦前未放巖根斷，屋下長教海眼通。", "本爲入來尋佛窟，不期行處踏龍宮。", "他時憶著堪圖畫，一朵雲山二水中。"]'),
('3350f07b-4161-4507-bcd5-90f107c08feb','廣州貽匡緒法師','曹松','唐','唐诗','tang','','[]','口宣微密不思議，不是除貪即誡癡。',64,'全唐诗/poet.tang.40000.json','["口宣微密不思議，不是除貪即誡癡。", "祗待外方緣了日，爭看內殿詔來時。", "週廻海樹侵階疾，迢遞江潮應井遲。", "必竟懶過高坐寺，未能全讓法雲師。"]'),
('c1bed828-6a98-40cf-8348-3bab4960fdaf','贈道人','曹松','唐','唐诗','tang','','[]','住山因以福爲庭，便向山中隱姓名。',64,'全唐诗/poet.tang.40000.json','["住山因以福爲庭，便向山中隱姓名。", "閬苑駕將雕羽去，洞天贏得綠毛生。", "日邊腸胃餐霞火，月裏肌膚飲露英。", "顧我從來斷浮濁，擬驅雞犬上三清。"]'),
('46f8982b-2cde-4694-b016-e49ef7f7ad35','送乞雨禪師臨遇南遊','曹松','唐','唐诗','tang','','[]','活得枯樵耕者知，巡方又欲向天涯。',64,'全唐诗/poet.tang.40000.json','["活得枯樵耕者知，巡方又欲向天涯。", "珠穿閩國菩提子，杖把靈峰榔栗枝。", "春蘚任封降虎石，夜雷從傍養龍池。", "生緣在地南浮去，自此孤雲不可期。"]'),
('5a3b965c-327c-4c51-82d7-a441012584de','南海陪鄭司空遊荔園','曹松','唐','唐诗','tang','','[]','荔枝時節出旌斿，南國名園盡興遊。',64,'全唐诗/poet.tang.40000.json','["荔枝時節出旌斿，南國名園盡興遊。", "亂結羅紋照襟袖，別含瓊露爽咽喉。", "葉中新火欺寒食，樹上丹砂勝錦州。", "他日爲霖不將去，也須圖畫取風流。"]'),
('11fe4bfb-12c3-49ff-be32-c2d0c0eb526d','李郎中林亭','曹松','唐','唐诗','tang','','[]','秪向砌邊流野水，樽前上下看魚兒。',64,'全唐诗/poet.tang.40000.json','["秪向砌邊流野水，樽前上下看魚兒。", "筍蹊已長過人竹，藤徑從添拂面絲。", "若許白猿垂近戶，即無紅果壓低枝。", "大才必擬逍遙去，更遣何人佐盛時。"]'),
('5503150e-71dc-49a7-8def-13caa36391a7','夜飲','曹松','唐','唐诗','tang','','[]','良宵公子宴蘭堂，濃麝薰人獸吐香。',64,'全唐诗/poet.tang.40000.json','["良宵公子宴蘭堂，濃麝薰人獸吐香。", "雲帶金龍銜畫燭，星羅銀鳳瀉瓊漿。", "滿屏珠樹開春景，一曲歌聲遶翠梁。", "席上未知簾幕曉，青娥低語指東方。"]'),
('ba81e09d-ed44-4ed2-bcae-f88890f28e48','駙馬宅宴罷','曹松','唐','唐诗','tang','','[]','粉牆殘月照宮祠，宴闋銀瓶一半欹。',32,'全唐诗/poet.tang.40000.json','["粉牆殘月照宮祠，宴闋銀瓶一半欹。", "學語鸎兒飛未穩，放身斜墜綠楊枝。"]'),
('e0f13058-08c4-43b1-bfd7-6208b6800009','弔建州李員外','曹松','唐','唐诗','tang','','[]','銘旌歸故里，猿鳥亦悽然。',48,'全唐诗/poet.tang.40000.json','["銘旌歸故里，猿鳥亦悽然。", "已葬桐江月，空廻建水船。", "客傳爲郡日，僧說讀書年。", "恐有吟魂在，深山古木邊。"]'),
('a2a16189-8aba-4ec6-98d5-cd9edd8b995a','弔李翰林','曹松','唐','唐诗','tang','','[]','李白雖然成異物，逸名猶與萬方傳。',64,'全唐诗/poet.tang.40000.json','["李白雖然成異物，逸名猶與萬方傳。", "昔朝曾侍玄宗側，大夜應歸賀監邊。", "山木易高迷故壠，國風長在見遺篇。", "投金渚畔春楊柳，自此何人繫酒船。"]'),
('129c3a1c-96d6-4dfc-8970-9aa1c8f2c12a','山中','曹松','唐','唐诗','tang','','[]','要路豪家非往還，巖門先有不曾關。',64,'全唐诗/poet.tang.40000.json','["要路豪家非往還，巖門先有不曾關。", "衆心惟恐地無剩，吾意亦憂天惜閑。", "白練曳泉窗下石，絳羅垂果枕前山。", "樵夫豈解營生業，貴欲自安麋鹿間。"]'),
('35bf1e0a-9707-4eb4-ad1f-7f12cf2b1e04','山寺引泉','曹松','唐','唐诗','tang','','[]','劈碎琅玕意有餘，細泉高引入香廚。',32,'全唐诗/poet.tang.40000.json','["劈碎琅玕意有餘，細泉高引入香廚。", "山僧未肯言根本，莫是銀河漏泄無。"]'),
('3a0cb981-3fb4-4aa1-80c0-88632650daad','友人池上詠蘆','曹松','唐','唐诗','tang','','[]','秋聲誰種得，蕭瑟在池欄。',48,'全唐诗/poet.tang.40000.json','["秋聲誰種得，蕭瑟在池欄。", "葉澀栖蟬穩，叢疎宿鷺難。", "歛煙宜下□，颯吹省先寒。", "此物生蒼島，令人憶釣竿。"]'),
('c40c07ba-f6f5-4de8-a182-5c4fdcd71f47','商山','曹松','唐','唐诗','tang','','[]','垂白商於原下住，兒孫共死一身忙。',32,'全唐诗/poet.tang.40000.json','["垂白商於原下住，兒孫共死一身忙。", "木弓未得長離手，猶與官家射麝香。"]'),
('849ae158-1eb5-40e2-a2a8-6d57fcdec8b3','荆南道中','曹松','唐','唐诗','tang','','[]','十月荒郊雪氣催，依稀愁色認陽臺。',64,'全唐诗/poet.tang.40000.json','["十月荒郊雪氣催，依稀愁色認陽臺。", "遊秦分繫三條燭，出楚心殊一寸灰。", "高柳莫遮寒月落，空桑不放夜風廻。", "如何住在猿聲裏，却被蟬吟引下來。"]'),
('174237fd-4a64-4bd7-81af-113eddea3303','武德殿朝退望九衢春色','曹松','唐','唐诗','tang','','[]','玉殿朝初退，天街一看春。',72,'全唐诗/poet.tang.40000.json','["玉殿朝初退，天街一看春。", "南山初過雨，北闕淨無塵。", "夾道夭桃滿，連溝御柳新。", "蘇舒同舜澤，煦嫗竝堯仁。", "佳氣浮軒蓋，和風襲縉紳。", "自茲憐萬物，同入發生辰。"]'),
('19b757c5-c8d8-4907-ab69-62dc827c5ab6','弔北邙','曹松','唐','唐诗','tang','','[]','山下望山上，夕陽看又曛。',48,'全唐诗/poet.tang.40000.json','["山下望山上，夕陽看又曛。", "無人醫白髮，少地著新墳。", "歲代殊相遠，賢愚旋不分。", "東歸聊一弔，亂木倚寒雲。"]'),
('db0840e1-56d4-4c22-9502-85d506741dec','及第勅下宴中獻座主杜侍郎','曹松','唐','唐诗','tang','','[]','得召丘牆淚却頻，若無公道也無因。',64,'全唐诗/poet.tang.40000.json','["得召丘牆淚却頻，若無公道也無因。", "門前送勅朱衣吏，席上銜杯碧落人。", "半夜笙歌教泥月，平明桃杏放燒春。", "南山雖有歸溪路，爭那酬恩未殺身。"]'),
('cf796e44-b7cd-4e4d-b198-a2596a92375d','梢雲','曹松','唐','唐诗','tang','','[]','殊質資靈貺，陵空發瑞雲。',72,'全唐诗/poet.tang.40000.json','["殊質資靈貺，陵空發瑞雲。", "梢梢含樹影，郁郁動霞文。", "不比因風起，全非觸石分。", "葉光閑泛灩，枝彩靜氛氳。", "隱見心無宰，裴回慶自君。", "翻飛如可託，長願在橫汾。"]'),
('8b58dc5e-2f51-407b-afde-157926ac4449','白角簟','曹松','唐','唐诗','tang','','[]','角簟工夫已到頭，夏來全占滿牀秋。',64,'全唐诗/poet.tang.40000.json','["角簟工夫已到頭，夏來全占滿牀秋。", "若言保惜歸華屋，秪合封題寄列侯。", "學卷曉冰長怕綻，解鋪寒水不教流。", "蒲桃錦是瀟湘底，曾得王孫價倍酬。"]'),
('86ed60df-bb60-4663-98c4-008fc8facbae','碧角簟','曹松','唐','唐诗','tang','','[]','細皮重疊織霜紋，滑膩鋪牀勝錦茵。',64,'全唐诗/poet.tang.40000.json','["細皮重疊織霜紋，滑膩鋪牀勝錦茵。", "八尺碧天無點翳，一方青玉絕纖塵。", "蠅行只恐煙黏足，客臥混疑水浸身。", "五月不教炎氣入，滿堂秋色冷龍鱗。"]'),
('0cd6589c-7911-43a4-ada3-c572208724ca','滕王閣春日晚望','曹松','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','凌春帝子閣，偶眺日移西。',24,'全唐诗/poet.tang.40000.json','["凌春帝子閣，偶眺日移西。", "浪勢平花塢，帆陰上柳堤。"]'),
('fba1af05-9c11-4788-977a-ce57b1890810','句','曹松','唐','唐诗','tang','','["\u534e\u5c71"]','追遊若遇三清樂，行從應妨一日春。',64,'全唐诗/poet.tang.40000.json','["追遊若遇三清樂，行從應妨一日春。", "石脉水流泉滴沙，鬼燈然點松柏花。", "鹿眠荒圃寒蕪白，鴉噪殘陽敗葉飛。", "華嶽影寒清露掌，海門風急白潮頭。"]'),
('0a59d92e-c696-4f97-a7c5-236df0419bba','頌魯','蘇拯','唐','唐诗','tang','','[]','天推魯仲尼，周游布典墳。',84,'全唐诗/poet.tang.40000.json','["天推魯仲尼，周游布典墳。", "遊遍七十國，不令遇一君。", "一國如一遇，單車不轉輪。", "良由至化力，爲國不爲身。", "禮樂行未足，邅迴厄於陳。", "禮樂今有餘，袞旒當聖人。", "傷哉絕糧議，千載誤云云。"]'),
('627090b2-5064-4c69-9150-abb3e70451fe','醫人','蘇拯','唐','唐诗','tang','','[]','古人醫在心，心正藥自真。',60,'全唐诗/poet.tang.40000.json','["古人醫在心，心正藥自真。", "今人醫在手，手濫藥不神。", "我願天地鑪，多銜扁鵲身。", "遍行君臣藥，先從凍餒均。", "自然六合內，少聞貧病人。"]'),
('c8621171-5488-4eec-9716-861c79c1df63','西施','蘇拯','唐','唐诗','tang','','[]','吳王從驕佚，天產西施出。',84,'全唐诗/poet.tang.40000.json','["吳王從驕佚，天產西施出。", "豈徒伐一人，所希救羣物。", "良由上天意，惡盈戒奢侈。", "不獨破吳國，不獨生越水。", "在周名襃姒，在紂名妲己。", "變化本多塗，生殺亦如此。", "君王政不修，立地生西子。"]'),
('73295826-245f-4fb0-b4bc-4b3be383313f','金谷園','蘇拯','唐','唐诗','tang','','[]','積金累作山，山高小於址。',60,'全唐诗/poet.tang.40000.json','["積金累作山，山高小於址。", "栽花比綠珠，花落還相似。", "徒有敵國富，不能買東市。", "徒有絕世容，不能樓上死。", "秪此上高樓，何如在平地。"]'),
('93e52142-9415-4dba-bd3f-8822a8d15bf4','巫山','蘇拯','唐','唐诗','tang','','[]','昔時亦雲雨，今時亦雲雨。',48,'全唐诗/poet.tang.40000.json','["昔時亦雲雨，今時亦雲雨。", "自是荒淫多，夢得巫山女。", "從來聖明君，可聽妖魅語。", "只今峰上雲，徒自生容與。"]'),
('c1ee0ff4-7f70-4dab-a4f7-a20f32cadd13','賈客','蘇拯','唐','唐诗','tang','','[]','長帆挂短舟，所願疾如箭。',48,'全唐诗/poet.tang.40000.json','["長帆挂短舟，所願疾如箭。", "得喪一驚飄，生死無良賤。", "不謂天不祐，自是人苟患。", "嘗言海利深，利深不如淺。"]'),
('4863a586-8671-4df3-acbe-ef1133bae5a5','狡兔行','蘇拯','唐','唐诗','tang','','[]','秋來無骨肥，鷹犬遍原野。',28,'全唐诗/poet.tang.40000.json','["秋來無骨肥，鷹犬遍原野。", "草中三穴無處藏，何況平田無穴者。"]'),
('5f5d4639-6caf-4a12-90a5-c30b98e8c770','長城','蘇拯','唐','唐诗','tang','','[]','嬴氏設防胡，烝沙築冤壘。',96,'全唐诗/poet.tang.40000.json','["嬴氏設防胡，烝沙築冤壘。", "蒙公取勳名，豈算生民死。", "運畚力不禁，碎身砂磧裏。", "黔黎欲半空，長城舂未已。", "皇天潛鼓怒，力化一女子。", "遂使萬雉崩，不盡數行淚。", "自古進身者，本非陷物致。", "當時文德修，不到三世地。"]'),
('bffd0608-68af-4b82-9f2f-b5539066a68d','織婦女','蘇拯','唐','唐诗','tang','','[]','伊余盡少女，一種飾螓首。',64,'全唐诗/poet.tang.40000.json','["伊余盡少女，一種飾螓首。", "徒能事機杼，與之作歌舞。", "歌舞片時間，黃金翻袖取。", "秪看舞者樂，豈念織者苦。", "感此嘗憶古人言，一婦不織天下寒。"]'),
('54935912-4030-4fa7-8722-6502cb26b8a3','古塞下','蘇拯','唐','唐诗','tang','','[]','百戰已休兵，寒雲愁未歇。',48,'全唐诗/poet.tang.40000.json','["百戰已休兵，寒雲愁未歇。", "血染長城沙，馬踏征人骨。", "早得用蛾眉，免陷邊戍卒。", "始知髦頭星，不在彎弓沒。"]'),
('3260b4ef-89e7-4942-87d7-45c7d1d6c630','水旱禱','蘇拯','唐','唐诗','tang','','[]','禱祈勿告天，酒漿勿澆地。',44,'全唐诗/poet.tang.40000.json','["禱祈勿告天，酒漿勿澆地。", "陰陽和也無妖氣，陰陽愆期乃人致。", "病生心腹不自醫，古屋澄潭何神祟。"]'),
('9e1ca461-7267-41ca-b2ef-d8bbe5df888c','鄒律','蘇拯','唐','唐诗','tang','','[]','鄒律暖燕谷，青史徒編錄。',76,'全唐诗/poet.tang.40000.json','["鄒律暖燕谷，青史徒編錄。", "人心不變遷，空吹閑草木。", "世患有三惑，爾律莫能抑。", "邊苦有長征，爾律莫能息。", "斯術未濟時，斯律亦何益。", "爭如至公一開口，吹起賢良霸邦國。"]'),
('6c94e69f-461f-46fd-83f6-d4cc44001edf','蜘蛛諭','蘇拯','唐','唐诗','tang','','[]','春蠶吐出絲，濟世功不絕。',84,'全唐诗/poet.tang.40000.json','["春蠶吐出絲，濟世功不絕。", "蜘蛛吐出絲，飛蟲成聚血。", "蠶絲何專利，爾絲何專孽。", "映日張網羅，遮天亦何別。", "儻居要地門，害物可堪說。", "網成雖福己，網敗還禍爾。", "小人與君子，利害一如此。"]'),
('ef1f83b2-8784-48ac-bac1-0c37bd587dc7','獵犬行','蘇拯','唐','唐诗','tang','','[]','獵犬未成行，狐兔無奈何。',100,'全唐诗/poet.tang.40000.json','["獵犬未成行，狐兔無奈何。", "獵犬今盈羣，狐兔依舊多。", "自爾初跳躍，人言多拏躩。", "常指天外狼，立可口中嚼。", "骨長毛衣重，燒殘烟草薄。", "狡兔何曾擒，時把家雞捉。", "食盡者飯翻，增養者惡壯。", "可嗟獵犬壯復壯，不堪兔絕良弓喪。"]'),
('9b4fe8ad-ec28-4e02-b811-6d0be1debfe4','斷火謠','蘇拯','唐','唐诗','tang','','[]','誰謂之推賢，於世何功果。',100,'全唐诗/poet.tang.40000.json','["誰謂之推賢，於世何功果。", "絕爾晉侯交，禁我唐虞火。", "國閉檀榆煙，大禮成隳墮。", "暗室枯槁飯，冷面相看坐。", "陽昇既非佑，陰伏若爲佐。", "焉凍羣生腹，將止天下禍。", "但究冤濫刑，天道無不可。", "鄙哉前朝翊贊臣，訏謨之規何瑣瑣。"]'),
('58279968-e510-4460-9a4c-d807cb0845e4','思婦吟','蘇拯','唐','唐诗','tang','','[]','秋風雁又歸，邊信一何早。',52,'全唐诗/poet.tang.40000.json','["秋風雁又歸，邊信一何早。", "攬衣出門望，落葉滿長道。", "一從秉箕箒，十載孤懷抱。", "可堪日日醉寵榮，不說思君令人老。"]'),
('cf708e15-02b2-4888-ac58-8bf8e53cc007','雉兔者','蘇拯','唐','唐诗','tang','','[]','所獵一何酷，終年耗林麓。',88,'全唐诗/poet.tang.40000.json','["所獵一何酷，終年耗林麓。", "飛走如未空，貪殘豈知足。", "嘗聞獵書史，可以鑒榮辱。", "嘗聞獵賢良，可以霸邦國。", "如何縱網羅，空成肥骨肉。", "和濟俱不聞，曷所禳顛覆。", "誰能爲扣天地鑪，鑄此傷生其可乎。"]'),
('7ec18a32-d556-46e2-912d-f8077493b3fa','藥草','蘇拯','唐','唐诗','tang','','[]','天子卹疲瘵，坤靈奉其職。',96,'全唐诗/poet.tang.40000.json','["天子卹疲瘵，坤靈奉其職。", "年年濟世功，貴賤相兼植。", "因產衆草中，所希採者識。", "一枝當若神，千金亦何直。", "生草不生藥，無以彰土德。", "生藥不生草，無以彰奇特。", "國忠在臣賢，民患憑藥力。", "靈草猶如此，賢人豈多得。"]'),
('694dd661-36ca-4673-8071-6d604ec97dcd','凡草誡','蘇拯','唐','唐诗','tang','','[]','野草凡不凡，亦應生和出。',72,'全唐诗/poet.tang.40000.json','["野草凡不凡，亦應生和出。", "鉏夫耘藥欄，根不留其一。", "良由本蕪穢，著地成棄物。", "人生行不修，何門可容膝。", "不唯不爾容，得無凡草嫉。", "賢愚偃仰間，鑒之宜日日。"]'),
('e38631da-4d38-4af7-ad60-f7e6195edbbe','明禁忌','蘇拯','唐','唐诗','tang','','[]','陰陽家有書，卜築多禁忌。',120,'全唐诗/poet.tang.40000.json','["陰陽家有書，卜築多禁忌。", "土中若有神，穴處何無祟。", "我識先賢意，本誡驕侈地。", "恣欲剏樓臺，率情染朱翠。", "四面興土功，四時妨農事。", "可以沒凶災，四隅通一二。", "一年省修營，萬民停困躓。", "動若契於理，福匪神之遺。", "動若越於常，禍乃身之致。", "神在虛無間，土中非神位。"]'),
('56286f96-de44-48ef-aa70-35560c092656','傷彩飾','蘇拯','唐','唐诗','tang','','[]','朝見亦光彩，暮見亦光彩。',72,'全唐诗/poet.tang.40000.json','["朝見亦光彩，暮見亦光彩。", "一旦風雨飄，十分無一在。", "爾形才似削，爾貌不如昨。", "本爲是凡姿，誰教染丹雘。", "虛飾片時間，天意以爲惡。", "物假猶如此，人假爭堪作。"]'),
('bfc5efde-fe98-46d9-b095-33d0453b6fd3','世迷','蘇拯','唐','唐诗','tang','','[]','烏兔日夜行，與人運枯榮。',96,'全唐诗/poet.tang.40000.json','["烏兔日夜行，與人運枯榮。", "爲善不常缺，爲惡不常盈。", "天道無阿黨，人心自覆傾。", "所以多遷變，寧合天地情。", "我願造化手，莫放狐兔走。", "恣海產珍奇，縱地生花柳。", "美者一齊美，醜者一齊醜。", "民心歸大朴，戰爭亦何有。"]'),
('4275eea0-31db-4c75-bec8-e7d23267c688','鴟梟','蘇拯','唐','唐诗','tang','','[]','爲害未爲害，其如汚物類。',96,'全唐诗/poet.tang.40000.json','["爲害未爲害，其如汚物類。", "斯言之一玷，流傳極天地。", "良木不得栖，清波不得戲。", "曾戲水堪疑，曾栖樹終棄。", "天不殲爾族，與夫惡相濟。", "地若默爾聲，與夫妖爲諱。", "一時懷害心，千古不能替。", "傷哉醜行人，茲禽亦爲譬。"]'),
('dccaae80-d48f-4071-bab5-52a00fc01ce7','山中道者','蘇拯','唐','唐诗','tang','','[]','筇杖六尺許，坐石流泉所。',48,'全唐诗/poet.tang.40000.json','["筇杖六尺許，坐石流泉所。", "舉頭看古松，似對仙鶴語。", "是時天氣清，四迥無塵侶。", "顧我笑相迎，知有丹砂異。"]'),
('4c72f1b5-15ab-4ae9-b452-75ce94cf8e2a','漁人','蘇拯','唐','唐诗','tang','','[]','垂竿朝與暮，披簑臥橫楫。',48,'全唐诗/poet.tang.40000.json','["垂竿朝與暮，披簑臥橫楫。", "不問清平時，自樂滄波業。", "長畏不得閑，幾度避遊畋。", "當笑釣臺上，逃名名却傳。"]'),
('82364db2-abc9-4de7-8d21-13c8475f4f63','聞猨','蘇拯','唐','唐诗','tang','','[]','秋風颯颯猨聲起，客恨猨哀一相似。',32,'全唐诗/poet.tang.40000.json','["秋風颯颯猨聲起，客恨猨哀一相似。", "漫向孤危驚客心，何曾解入笙歌耳。"]'),
('91d26328-ead6-40ce-b16e-6c4b8c9fbfb6','經馬嵬坡','蘇拯','唐','唐诗','tang','','[]','一從殺貴妃，春來花無意。',48,'全唐诗/poet.tang.40000.json','["一從殺貴妃，春來花無意。", "此地縱千年，土香猶破鼻。", "寵既出常理，辱豈同常死。", "一等異於衆，傾覆皆如此。"]'),
('4200b0b9-0667-4174-980e-a58517214821','經鶴臺','蘇拯','唐','唐诗','tang','','[]','築臺非謂賢，獨聚乘軒鶴。',72,'全唐诗/poet.tang.40000.json','["築臺非謂賢，獨聚乘軒鶴。", "六馬不能馭，九臯欲何託。", "一旦敵兵來，萬民同隕濩。", "如何警露禽，不似銜環雀。", "一物欲誤時，衆類皆成惡。", "至今臺基上，飛鳥不至泊。"]'),
('e049b8b7-d011-4a51-bf9f-f4c4ef51f4ac','寄遠','蘇拯','唐','唐诗','tang','','[]','游子雖惜別，一去何時見。',48,'全唐诗/poet.tang.40000.json','["游子雖惜別，一去何時見。", "飛鳥猶戀巢，萬里亦何遠。", "妾願化爲霜，日日下河梁。", "若能侵鬢色，先染薄情郎。"]'),
('5d38c844-8c30-457e-a689-2a008c0a2143','芭蕉','路德延','唐','唐诗','tang','','[]','一種靈苗異，天然體性虛。',24,'全唐诗/poet.tang.40000.json','["一種靈苗異，天然體性虛。", "葉如斜界紙，心似倒抽書。"]'),
('a5cf5238-0407-4e47-8c22-f996188dc327','感舊詩','路德延','唐','唐诗','tang','','[]','初騎竹馬詠芭蕉，嘗忝名卿誦滿朝。',64,'全唐诗/poet.tang.40000.json','["初騎竹馬詠芭蕉，嘗忝名卿誦滿朝。", "五字便容趨絳帳，一枝尋許折丹霄。", "豈知流落萍蓬遠，不覺推遷歲月遙。", "國境未安身未立，至今顏巷守簞瓢。"]'),
('f3ee511a-64e6-42ec-8637-1c6d098e6178','小兒詩','路德延','唐','唐诗','tang','','[]','情態任天然，桃紅兩頰鮮。',288,'全唐诗/poet.tang.40000.json','["情態任天然，桃紅兩頰鮮。", "乍行人共看，初語客多憐。", "臂膊肥如瓠，肌膚軟勝綿。", "長頭纔覆額，分角漸垂肩。", "散誕無塵慮，逍遙占地仙。", "排衙朱閣上，喝道畫堂前。", "合調歌楊柳，齊聲踏採蓮。", "走隄行細雨，奔巷趁輕煙。", "嫩竹乘爲馬，新蒲折作鞭。", "鶯雛金鏇繫，猫自綵絲牽。", "擁鶴歸晴島，驅鵝入暖泉。", "楊花爭弄雪，榆葉共收錢。", "錫鏡當胸挂，銀珠對耳懸。", "頭依蒼鶻裹，袖學柘枝揎。", "酒殢丹砂暖，茶催小玉煎。", "頻邀籌箸掙，時乞繡鍼穿。", "寶篋拏紅豆，妝奩拾翠鈿。", "戲袍披按褥，劣帽戴靴氈。", "展畫趍三聖，開屏笑七賢。", "貯懷青杏小，垂額綠荷圓。", "驚滴霑羅淚，嬌流汚錦涎。", "倦書饒婭姹，憎藥巧遷延。", "弄帳鸞綃映，藏衾鳳綺纏。", "指敲迎使鼓，筋撥賽神弦。"]'),
('324ec432-94b4-4fe1-b253-0bfc3f5797c8','句','路德延','唐','唐诗','tang','','[]','不是上台知姓字，五花賓館敢從容。',16,'全唐诗/poet.tang.40000.json','["不是上台知姓字，五花賓館敢從容。"]'),
('90203085-be1b-4eff-a131-8375081baed1','及第後呈朝中知己','李旭','唐','唐诗','tang','','[]','凌晨曉鼓奏嘉音，雷擁龍迎出陸沈。',64,'全唐诗/poet.tang.40000.json','["凌晨曉鼓奏嘉音，雷擁龍迎出陸沈。", "金榜高懸當玉闕，錦衣即著到家林。", "真珠每被塵泥陷，病鶴多遭螻蟻侵。", "今日始知天有意，還教雪得一生心。"]'),
('9c5514cb-0c95-4b12-ba4e-fde332be34d1','題惠嚴寺','崔庸','唐','唐诗','tang','','[]','人莫嫌山小，僧還愛寺靈。',24,'全唐诗/poet.tang.40000.json','["人莫嫌山小，僧還愛寺靈。", "殿高神氣力，龍活客丹青。"]'),
('f5d28ce3-202c-4072-a26c-7d7100cae796','經費拾遺舊隱','胡駢','唐','唐诗','tang','','[]','林下茅齋已半傾，九華幽逕少人行。',64,'全唐诗/poet.tang.40000.json','["林下茅齋已半傾，九華幽逕少人行。", "不將冠劒爲榮事，只向煙蘿寄此生。", "松竹漸荒池上色，琴書徒立世間名。", "白楊風起秋山暮，時復哀猨啼一聲。"]'),
('e5deb79e-b7ec-48f3-9d7e-9264792cea70','失題','周祚','唐','唐诗','tang','','[]','莫道春花獨照人，秋花未必怯青春。',32,'全唐诗/poet.tang.40000.json','["莫道春花獨照人，秋花未必怯青春。", "四時風雨沒時節，共保松筠根底塵。"]'),
('53388d6f-5bc5-4836-9a5f-8aa4fddb31ac','蛺蝶行','盧頻','唐','唐诗','tang','','[]','東園宮草綠，上下飛相逐。',24,'全唐诗/poet.tang.40000.json','["東園宮草綠，上下飛相逐。", "君恩不禁春，昨夜花中宿。"]'),
('2915a943-3f25-4f92-8b13-3868693f9440','東西行','盧頻','唐','唐诗','tang','','[]','種荷玉盆裏，不及溝中水。',24,'全唐诗/poet.tang.40000.json','["種荷玉盆裏，不及溝中水。", "養雉黃金籠，見草心先喜。"]'),
('b67abe08-3ab7-40eb-9faf-a8322a7af4ad','失題 一','盧頻','唐','唐诗','tang','','[]','春淚爛羅綺，泣聲抽恨多。',24,'全唐诗/poet.tang.40000.json','["春淚爛羅綺，泣聲抽恨多。", "莫滴芙蓉池，愁傷連蔕荷。"]'),
('0e6695be-23c6-497f-b756-c82bb5321e3b','失題 二','盧頻','唐','唐诗','tang','','[]','一朵花葉飛，一枝花光彩。',24,'全唐诗/poet.tang.40000.json','["一朵花葉飛，一枝花光彩。", "美人惜花心，但願春長在。"]'),
('b5ab00ce-47a8-423b-80f8-acccfe48dc27','晚泊漢江渡','劉畋','唐','唐诗','tang','','[]','末秋雲木輕，蓮折晚香清。',48,'全唐诗/poet.tang.40000.json','["末秋雲木輕，蓮折晚香清。", "雨下侵苔色，雲涼出浪聲。", "疊帆依岸盡，微照夾隄明。", "渡吏已頭白，遙知客姓名。"]'),
('fa0104b2-3fd9-4f07-a71d-19083ff0fee9','句','劉畋','唐','唐诗','tang','','[]','殘陽來霽岫，獨興起滄洲。',12,'全唐诗/poet.tang.40000.json','["殘陽來霽岫，獨興起滄洲。"]'),
('38690232-17dc-4a98-99d6-07f8c59e37e3','遊洞庭湖','裴說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','楚雲團翠八百里，澧蘭吹香墮春水。',112,'全唐诗/poet.tang.40000.json','["楚雲團翠八百里，澧蘭吹香墮春水。", "白頭漁子搖蒼煙，鸂鶒眠沙曉驚起。", "沙頭龍叟夜歎憂，鐵笛未響春風羞。", "露寒紫藟結新愁，城角泣斷關河秋。", "謫仙欲識雷斧手，剗却古今愁共醜。", "鯨遊碧落杳無踪，作詩三歎君知否。", "瀛洲一櫂何時還，滿江宮錦看湖山。"]'),
('e6ff1e2f-0e01-4459-a5db-51239ab4345c','懷素臺歌','裴說','唐','唐诗','tang','','[]','我呼古人名，鬼神側耳聽。',119,'全唐诗/poet.tang.40000.json','["我呼古人名，鬼神側耳聽。", "杜甫李白與懷素，文星酒星草書星。", "永州東郭有奇怪，筆冢墨池遺跡在。", "筆冢低低高如山，墨池淺淺深如海。", "我來恨不已，爭得青天化爲一張紙。", "高聲喚起懷素書，搦管研朱點湘水。", "欲歸家，重歎嗟。", "眼前有三箇字，枯樹槎，烏梢蛇，墨老鵶。"]'),
('04517228-74f6-41af-bcba-9bda057ed296','聞砧','裴說','唐','唐诗','tang','','[]','深閨乍冷鑑開篋，玉筯微微濕紅頰。',160,'全唐诗/poet.tang.40000.json','["深閨乍冷鑑開篋，玉筯微微濕紅頰。", "一陣霜風殺柳條，濃煙半夜成黃葉。", "垂垂白練明如雪，獨下閑堦轉淒切。", "祗知抱杵搗秋砧，不覺高樓已無月。", "時聞寒雁聲相喚，紗窓只有燈相伴。", "幾展齊紈又嬾裁，離腸恐逐金刀斷。", "細想儀形執牙尺，回刀剪破澄江色。", "愁捻銀鍼信手縫，惆悵無人試寬窄。", "時時舉袖勻紅淚，紅牋謾有千行字。", "書中不盡心中事，一片慇懃寄邊使。"]'),
('37bfc9c1-4135-4ba0-854a-2d0f1a2f5cf5','春早寄華下同人','裴說','唐','唐诗','tang','','[]','正是花時節，思君寢復興。',48,'全唐诗/poet.tang.40000.json','["正是花時節，思君寢復興。", "市沽終不醉，春夢亦無憑。", "岳面懸青雨，河心走濁冰。", "東門一條路，離恨鎮相仍。"]'),
('76f9562f-aa08-4257-9634-c3e714326076','贈衡山令','裴說','唐','唐诗','tang','','["\u8861\u5c71"]','君吟十二載，辛苦必能官。',48,'全唐诗/poet.tang.40000.json','["君吟十二載，辛苦必能官。", "造化猶難隱，生靈豈易謾。", "猿跳高岳靜，魚擺大江寬。", "與我爲同道，相留夜話闌。"]'),
('37a66d45-bfe5-4fc7-a629-6918b79ee8b4','南中縣令','裴說','唐','唐诗','tang','','[]','寂寥雖下邑，良宰有清威。',48,'全唐诗/poet.tang.40000.json','["寂寥雖下邑，良宰有清威。", "苦節長如病，爲官豈肯肥。", "山多村地狹，水淺客舟稀。", "上國搜賢急，陶公早晚歸。"]'),
('5779950b-aa62-4bcb-a185-429204d80b7c','寄曹松','裴說','唐','唐诗','tang','','[]','莫怪苦吟遲，詩成鬢亦絲。',48,'全唐诗/poet.tang.40000.json','["莫怪苦吟遲，詩成鬢亦絲。", "鬢絲猶可染，詩病却難醫。", "山暝雲橫處，星沈月側時。", "冥搜不可得，一句至公知。"]'),
('1084793e-4e3a-41b7-9808-259e0be11113','贈賓貢','裴說','唐','唐诗','tang','','[]','惟君懷至業，萬里信悠悠。',50,'全唐诗/poet.tang.40000.json','["惟君懷至業，萬里信悠悠。", "路向東[溟]出，枝來北闕求。", "家無一夜夢，帆挂隔年秋。", "鬢髮爭禁得，孤舟往復愁。"]'),
('822840b5-ff7a-448a-95ec-801b555d16a7','漢南郵亭','裴說','唐','唐诗','tang','','[]','高閣水風清，開門日送迎。',48,'全唐诗/poet.tang.40000.json','["高閣水風清，開門日送迎。", "帆張獨鳥起，樂奏大魚驚。", "驟雨拖山過，微風拂面生。", "閑吟雖得句，留此謝多情。"]'),
('ae3e162f-6d07-4f90-ab29-9751c747d535','棋','裴說','唐','唐诗','tang','','[]','十九條平路，言平又嶮巇。',48,'全唐诗/poet.tang.40000.json','["十九條平路，言平又嶮巇。", "人心無算處，國手有輸時。", "勢逈流星遠，聲乾下雹遲。", "臨軒才一局，寒日又西垂。"]'),
('f67ae712-e29a-4d5c-a18b-1ce75aba14a4','夏日即事','裴說','唐','唐诗','tang','','[]','僻居門巷靜，竟日坐階墀。',48,'全唐诗/poet.tang.40000.json','["僻居門巷靜，竟日坐階墀。", "鵲喜雖傳信，蛩吟不見詩。", "筍抽通舊竹，梅落立閑枝。", "此際無塵撓，僧來稱所宜。"]'),
('93a2ad3c-7dc2-46bc-8114-d7d5e4b27c76','送人宰邑','裴說','唐','唐诗','tang','','[]','官小任還重，命官難偶然。',48,'全唐诗/poet.tang.40000.json','["官小任還重，命官難偶然。", "皇恩輕一邑，赤子病三年。", "瘦馬稀飡粟，羸童不識錢。", "如君清苦節，到處有人傳。"]'),
('49968c68-8693-4c90-b3e4-6ffda80f18ba','春暖送人下第','裴說','唐','唐诗','tang','','[]','相送短亭前，知君愚復賢。',48,'全唐诗/poet.tang.40000.json','["相送短亭前，知君愚復賢。", "事多憑夜夢，老爲待明年。", "春樹添山脊，晴雲學曉煙。", "雄文有公道，此別莫澘然。"]'),
('0b710d4a-a537-4ac6-96fd-c327adbfbfb1','湖外送何崇入閣','裴說','唐','唐诗','tang','','[]','因詩相識久，忽此告臨途。',48,'全唐诗/poet.tang.40000.json','["因詩相識久，忽此告臨途。", "便是有船發，也須容市沽。", "精吟五箇字，穩泛兩重湖。", "長短逢公道，清名振帝都。"]'),
('6976d145-9fe3-47a1-ae82-a7614e6c5161','送進士蘇瞻亂後出家','裴說','唐','唐诗','tang','','[]','因亂事空王，孤心亦不傷。',48,'全唐诗/poet.tang.40000.json','["因亂事空王，孤心亦不傷。", "梵僧爲骨肉，柏寺作家鄉。", "眼閉千行淚，頭梳一把霜。", "詩書不得力，誰與問蒼蒼。"]'),
('8a7f41d9-d8e2-40d4-8757-79c19029a616','秋日送河北從事','裴說','唐','唐诗','tang','','[]','北風沙漠地，吾子遠從軍。',48,'全唐诗/poet.tang.40000.json','["北風沙漠地，吾子遠從軍。", "官路雖非遠，詩名要且聞。", "蟬悲欲落日，鵰下擬陰雲。", "此去難相戀，前山摻袂分。"]'),
('db5620d2-67d1-4e8a-b39b-bb9e0ccf9b84','喜友人再面','裴說','唐','唐诗','tang','','[]','一別幾寒暄，迢迢隔塞垣。',48,'全唐诗/poet.tang.40000.json','["一別幾寒暄，迢迢隔塞垣。", "相思長有事，及見却無言。", "靜坐將茶試，閑書把葉翻。", "依依又留宿，圓月上東軒。"]'),
('1386a44a-bc5a-43e7-bf89-846bad3140e9','對雪','裴說','唐','唐诗','tang','','[]','大片向空舞，出門肌骨寒。',48,'全唐诗/poet.tang.40000.json','["大片向空舞，出門肌骨寒。", "路岐平即易，溝壑滿應難。", "兔穴歸時失，禽枝宿處乾。", "豪家寧肯厭，五月畫圖看。"]'),
('3515d0f8-7d6b-41c8-9f98-77366eb6b9ef','冬日後作','裴說','唐','唐诗','tang','','[]','寂寞掩荆扉，昏昏坐欲癡。',48,'全唐诗/poet.tang.40000.json','["寂寞掩荆扉，昏昏坐欲癡。", "事無前定處，愁有併來時。", "日影纔添線，鬢根已半絲。", "明庭正公道，應許苦心詩。"]'),
('8d47db03-2ee3-4555-8cb3-5bcb164cdf2c','冬日作','裴說','唐','唐诗','tang','','[]','糲食擁敗絮，苦吟吟過冬。',48,'全唐诗/poet.tang.40000.json','["糲食擁敗絮，苦吟吟過冬。", "稍寒人却健，太飽事多慵。", "樹老生煙薄，牆陰貯雪重。", "安能只如此，公道會相容。"]'),
('71080d30-4dd4-4b3b-a73c-d4308bc0b956','中秋月','裴說','唐','唐诗','tang','','[]','一歲幾盈虧，當軒重此期。',48,'全唐诗/poet.tang.40000.json','["一歲幾盈虧，當軒重此期。", "幸無偏照處，剛有不明時。", "色靜雲歸早，光寒鶴睡遲。", "相看吟未足，皎皎下疎籬。"]'),
('126d88a2-367a-45c0-b8ab-160868b02fe4','塞上曲','裴說','唐','唐诗','tang','','["\u8fb9\u585e"]','極目望空闊，馬羸程又賒。',48,'全唐诗/poet.tang.40000.json','["極目望空闊，馬羸程又賒。", "月生方見樹，風定始無沙。", "楚水辭魚窟，燕山到雁家。", "如斯名利役，爭不老天涯。"]'),
('3e35b895-4e09-4684-b145-c10fa5e6279a','終南山','裴說','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','九衢南面色，蒼翠絕纖塵。',48,'全唐诗/poet.tang.40000.json','["九衢南面色，蒼翠絕纖塵。", "寸步有閑處，百年無到人。", "禁林寒對望，太華淨相鄰。", "誰與羣峰並，祥雲瑞露頻。"]'),
('ce876e0a-68ac-4ffe-b735-02546c4639a8','訪道士','裴說','唐','唐诗','tang','','[]','高岡微雨後，木脫草堂新。',48,'全唐诗/poet.tang.40000.json','["高岡微雨後，木脫草堂新。", "惟有疎慵者，來看淡薄人。", "竹牙生礙路，松子落敲巾。", "麤得玄中趣，當期宿話頻。"]'),
('237f07cc-729b-4af7-af21-cae00a44bf52','道林寺','裴說','唐','唐诗','tang','','[]','獨立憑危闌，高低落照間。',48,'全唐诗/poet.tang.40000.json','["獨立憑危闌，高低落照間。", "寺分一派水，僧鎖半房山。", "對面浮世隔，垂簾到老閑。", "煙雲與塵土，寸步不相關。"]'),
('4dc15366-2770-4a69-a4bc-279e51c306c5','般若寺','裴說','唐','唐诗','tang','','["\u8861\u5c71"]','南嶽古般若，自來天下知。',48,'全唐诗/poet.tang.40000.json','["南嶽古般若，自來天下知。", "翠籠無價寺，光射有名詩。", "一水湧獸跡，五峰排鳳儀。", "高僧引閑步，晝出夕陽歸。"]'),
('70c5664f-c775-48d1-9a55-301a4e3b6ef7','兜率寺','裴說','唐','唐诗','tang','','[]','一片無塵地，高連夢澤南。',48,'全唐诗/poet.tang.40000.json','["一片無塵地，高連夢澤南。", "僧居跨鳥道，佛影照魚潭。", "朽枿雲斜映，平蕪日半涵。", "行行不得住，回首望煙嵐。"]'),
('c04e408e-84bb-4e11-8a4c-59881a0cabfa','鹿門寺','裴說','唐','唐诗','tang','','[]','鹿門山上寺，突兀盡無塵。',48,'全唐诗/poet.tang.40000.json','["鹿門山上寺，突兀盡無塵。", "到此修行者，應非取次人。", "鳥過驚石磬，日出礙金身。", "何計生煩惱，虛空是四鄰。"]'),
('41c23948-3d4b-4b52-8489-153143a1e6ac','題岳州僧舍','裴說','唐','唐诗','tang','','[]','喜到重湖北，孤州橫晚煙。',48,'全唐诗/poet.tang.40000.json','["喜到重湖北，孤州橫晚煙。", "鷺銜魚入寺，鵶接飯隨船。", "松檜君山逈，菰蒲夢澤連。", "與師吟論處，秋水浸遙天。"]'),
('f223bcbc-bd70-44cc-8380-ef38958ebe2b','過洞庭湖','裴說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','浪高風力大，挂席亦言遲。',48,'全唐诗/poet.tang.40000.json','["浪高風力大，挂席亦言遲。", "及到堪憂處，爭如未濟時。", "魚龍侵莫測，雷雨動須疑。", "此際情無賴，何門寄所思。"]'),
('5568477b-3eed-4b6c-9def-910a3cefd20d','旅行聞寇','裴說','唐','唐诗','tang','','[]','動步憂多事，將行問四鄰。',48,'全唐诗/poet.tang.40000.json','["動步憂多事，將行問四鄰。", "深山不畏虎，當路却防人。", "豪富田園廢，疲羸屋舍新。", "自慙爲旅客，無計避煙塵。"]'),
('9eef7cd5-886a-4803-8516-72c333ffc4c4','旅中作','裴說','唐','唐诗','tang','','[]','妄動遠拋山，其如餒與寒。',48,'全唐诗/poet.tang.40000.json','["妄動遠拋山，其如餒與寒。", "投人言去易，開口說貧難。", "澤國雲千片，湘江竹一竿。", "時明未忍別，猶待計窮看。"]'),
('513fc384-eca0-493e-897b-3b4a722e8f86','旅次衡陽','裴說','唐','唐诗','tang','','[]','欲往幾經年，今來意豁然。',48,'全唐诗/poet.tang.40000.json','["欲往幾經年，今來意豁然。", "江風長借客，岳雨不因天。", "戲鷺飛輕雪，驚鴻呌亂煙。", "晚秋紅藕裏，十宿寄漁船。"]'),
('363bff95-6035-4d1c-b674-2947238a8164','不出院僧','裴說','唐','唐诗','tang','','[]','四遠參尋徧，修行却不行。',48,'全唐诗/poet.tang.40000.json','["四遠參尋徧，修行却不行。", "耳邊無俗語，門外是前生。", "塔見移來影，鐘聞過去聲。", "一齋唯默坐，應笑我營營。"]'),
('c19deb7c-c7a6-424a-aa6f-97666066b8ab','湖外寄處賓上人','裴說','唐','唐诗','tang','','[]','怪得意相親，高攜一軸新。',48,'全唐诗/poet.tang.40000.json','["怪得意相親，高攜一軸新。", "能搜大雅句，不似小乘人。", "嶽麓擎枯檜，瀟湘吐白蘋。", "他年遇同道，爲我話風塵。"]'),
('618ec44f-ba5c-4aa7-8ab6-1c26b7f97774','寄貫休','裴說','唐','唐诗','tang','','[]','憶昔與吾師，山中靜論時。',48,'全唐诗/poet.tang.40000.json','["憶昔與吾師，山中靜論時。", "總無方是法，難得始爲詩。", "凍犬眠乾葉，飢禽啄病梨。", "他年白蓮社，猶許重相期。"]'),
('c014ac81-7f9e-4c12-9e83-fbd91cea1d83','寄僧尚顏','裴說','唐','唐诗','tang','','[]','曾居五老峰，所得共誰同。',48,'全唐诗/poet.tang.40000.json','["曾居五老峰，所得共誰同。", "才大天全與，吟精楚欲空。", "客來庭減日，鳥過竹生風。", "早晚搖輕拂，重歸瀑布中。"]'),
('46f45c84-1a15-47c7-abd0-d4b888af9309','哭處默上人','裴說','唐','唐诗','tang','','[]','淒涼繐幕下，香吐一燈分。',48,'全唐诗/poet.tang.40000.json','["淒涼繐幕下，香吐一燈分。", "鬬老輸寒檜，留閑與白雲。", "挈盂曾幾度，傳衲不教焚。", "泣罷重回首，暮山鐘半聞。"]'),
('2859f8e7-e2e5-41b1-af95-f9b28c61626a','廬山瀑布','裴說','唐','唐诗','tang','','["\u5e90\u5c71"]','靜景憑高望，光分翠嶂開。',48,'全唐诗/poet.tang.40000.json','["靜景憑高望，光分翠嶂開。", "嶮飛千尺雪，寒撲一聲雷。", "過去雲衝斷，旁來燒隔廻。", "何當住峰下，終歲絕塵埃。"]'),
('c25a3e47-051d-4b17-b729-1328e5583a39','華山上方','裴說','唐','唐诗','tang','','[]','獨上上方上，立高聊稱心。',48,'全唐诗/poet.tang.40000.json','["獨上上方上，立高聊稱心。", "氣衝雲易黑，影落縣多陰。", "有雲草不死，無風松自吟。", "會當求大藥，他日復追尋。"]'),
('97582184-21c7-4f82-9f49-a80c8e30d0df','詠鸚鵡','裴說','唐','唐诗','tang','','[]','常貴西山鳥，銜恩在玉堂。',48,'全唐诗/poet.tang.40000.json','["常貴西山鳥，銜恩在玉堂。", "語傳明主意，衣拂美人香。", "緩步尋珠網，高飛上畫梁。", "長安頻道樂，何日從君王。"]'),
('3cb2e663-bb27-40b3-abec-ba6ff12afce9','鷺鷥','裴說','唐','唐诗','tang','','[]','秋江清淺時，魚過亦頻窺。',48,'全唐诗/poet.tang.40000.json','["秋江清淺時，魚過亦頻窺。", "却爲分明極，翻成所得遲。", "浴偎紅日色，棲壓碧蘆枝。", "會共鵷同侶，翺翔應可期。"]'),
('b3ac669f-ef56-4e7a-b4f6-7da96f54a069','牡丹','裴說','唐','唐诗','tang','','[]','數朵欲傾城，安同桃李榮。',48,'全唐诗/poet.tang.40000.json','["數朵欲傾城，安同桃李榮。", "未嘗貧處見，不似地中生。", "此物疑無價，當春獨有名。", "遊蜂與蝴蝶，來往自多情。"]'),
('d84a1d6c-b0a6-43a0-83f7-b3c5dabdbcf0','見王貞白','裴說','唐','唐诗','tang','','[]','共賀登科後，明宣入紫宸。',48,'全唐诗/poet.tang.40000.json','["共賀登科後，明宣入紫宸。", "又看重試榜，還見苦吟人。", "此得名渾別，歸來話亦新。", "分明一枝桂，堪動楚江濱。"]'),
('8c64fb66-2c36-4866-a2a7-3508dd901c49','經杜工部墳','裴說','唐','唐诗','tang','','[]','騷人久不出，安得國風清。',48,'全唐诗/poet.tang.40000.json','["騷人久不出，安得國風清。", "擬掘孤墳破，重教大雅生。", "皇天高莫問，白酒恨難平。", "悒怏寒江上，誰人知此情。"]'),
('4ccce8e3-1f79-44bf-bf27-39db091ba39d','寄僧知乾','裴說','唐','唐诗','tang','','[]','貌高清入骨，帝里舊臨壇。',24,'全唐诗/poet.tang.40000.json','["貌高清入骨，帝里舊臨壇。", "出語經相似，行心佛證安。"]'),
('2d37902f-1d76-4551-9b1a-a78ea50a0400','亂中偷路入故鄉','裴說','唐','唐诗','tang','','[]','愁看賊火起諸烽，偷得餘程悵望中。',32,'全唐诗/poet.tang.40000.json','["愁看賊火起諸烽，偷得餘程悵望中。", "一國半爲亡國燼，數城俱作古城空。"]'),
('d09bc622-2cbb-4bc2-b44e-2025bb97c356','薔薇','裴說','唐','唐诗','tang','','[]','一架長條萬朵春，嫩紅深綠小窠勻。',32,'全唐诗/poet.tang.40000.json','["一架長條萬朵春，嫩紅深綠小窠勻。", "只應根下千年土，曾葬西川織錦人。"]'),
('8f218ba8-5435-41c9-9157-7bdd2f8e6cfc','春日山中竹','裴說','唐','唐诗','tang','','[]','數竿蒼翠擬龍形，峭拔須教此地生。',32,'全唐诗/poet.tang.40000.json','["數竿蒼翠擬龍形，峭拔須教此地生。", "無限野花開不得，半山寒色與春爭。"]'),
('e603c101-a23a-413b-ad14-b08e218c117e','柳','裴說','唐','唐诗','tang','','[]','高拂危樓低拂塵，灞橋攀折一何頻。',32,'全唐诗/poet.tang.40000.json','["高拂危樓低拂塵，灞橋攀折一何頻。", "思量却是無情樹，不解迎人只送人。"]'),
('bd280271-92d4-4466-b715-39c75b5f45e7','岳陽兵火後題僧舍','裴說','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','十年兵火真多事，再到禪扉却破顏。',32,'全唐诗/poet.tang.40000.json','["十年兵火真多事，再到禪扉却破顏。", "唯有兩般燒不得，洞庭湖水老僧閑。"]'),
('678c0799-cd43-43c0-9503-26d4645ff022','句','裴說','唐','唐诗','tang','','[]','讀書貧裏樂，搜句靜中忙。',134,'全唐诗/poet.tang.40000.json','["讀書貧裏樂，搜句靜中忙。", "苦吟僧入定，得句將成功。", "是事精皆易，唯詩會却難。", "因攜一家住，贏得半年吟。", "吟餘潮入浦，坐久燒移山。", "三年清似水，六月冷如冰。", "一通紅錦重，三事紫羅輕。", "瘦肌寒帶粟，病眼餒生花。", "避亂一生多，雪留寒竹寺舍冷。", "風撼早梅城郭香，畫毬輕蹴壺中地。", "綵索高飛掌上身。"]'),
('8e3f6a3d-0c41-4ec7-804d-97d138241a24','贈唐山人','李洞','唐','唐诗','tang','','[]','垂鬚長似髮，七十色如黳。',48,'全唐诗/poet.tang.40000.json','["垂鬚長似髮，七十色如黳。", "醉眼青天小，吟情太華低。", "千年松繞屋，半夜雨連溪。", "邛蜀路無限，往來琴獨攜。"]'),
('73cf71e9-a558-4a5c-a6b4-ea8f5a49d16a','送雲卿上人游安南','李洞','唐','唐诗','tang','','[]','春往海南邊，秋聞半夜蟬。',48,'全唐诗/poet.tang.40000.json','["春往海南邊，秋聞半夜蟬。", "鯨吞洗鉢水，犀觸點燈船。", "島嶼分諸國，星河共一天。", "長安却迴日，松偃舊房前。"]'),
('1e6b17a7-2c56-49cc-9262-aee91d573587','鄭補闕山居','李洞','唐','唐诗','tang','','[]','高節諫垣客，白雲居靜坊。',48,'全唐诗/poet.tang.40000.json','["高節諫垣客，白雲居靜坊。", "馬飢餐落葉，鶴病曬殘陽。", "野霧昏朝燭，溪牋惹御香。", "相招倚蒲壁，論句夜何長。"]'),
('d9e89292-9e3a-485e-bb3a-8fd48ffe253f','送曹郎中南歸時南中用軍','李洞','唐','唐诗','tang','','[]','桂水淨和天，南歸似謫仙。',48,'全唐诗/poet.tang.40000.json','["桂水淨和天，南歸似謫仙。", "繫絛輕象笏，買布接蠻船。", "海氣蒸鼙軟，江風激箭偏。", "罷郎吟亂裏，帝遠豈知賢。"]'),
('c54c4e5d-cb5e-4176-9f7d-07da3468aac4','錦江陪兵部鄭侍郎話詩著棊','李洞','唐','唐诗','tang','','[]','落葉濺吟身，會棊雲外人。',48,'全唐诗/poet.tang.40000.json','["落葉濺吟身，會棊雲外人。", "海枯搜不盡，天定著長新。", "月上分題遍，鐘殘布子勻。", "忘餐二絕境，取意鑄陶鈞。"]'),
('a5bb6110-6129-49a8-8a26-ee3eb12815d6','中秋月','李洞','唐','唐诗','tang','','[]','四十五秋宵，月分千里毫。',48,'全唐诗/poet.tang.40000.json','["四十五秋宵，月分千里毫。", "冷沈中嶽短，光溢太行高。", "不寐清人眼，移棲濕鶴毛。", "露華臺上別，吟望十年勞。"]'),
('788f1ad1-15c9-4b5d-8e9d-53509c83abc1','送沈光赴福幕','李洞','唐','唐诗','tang','','[]','泉齊嶺鳥飛，雨熟荔枝肥。',48,'全唐诗/poet.tang.40000.json','["泉齊嶺鳥飛，雨熟荔枝肥。", "南斗看應近，北人來恐稀。", "潮浮廉使宴，珠照島僧歸。", "幕下逢遷拜，何官着茜衣。"]'),
('82ae295e-360d-4e4e-be5a-1ed9f27e7cd7','鄠郊山舍題趙處士林亭','李洞','唐','唐诗','tang','','[]','圭峰秋後疊，亂葉落寒墟。',48,'全唐诗/poet.tang.40000.json','["圭峰秋後疊，亂葉落寒墟。", "四五百竿竹，二三千卷書。", "雲深猿拾栗，雨霽蟻緣蔬。", "只隔門前水，如同萬里餘。"]'),
('8f73ea87-0ea1-4cdc-b224-ca76236abe77','賦得送賈島謫長江','李洞','唐','唐诗','tang','','["\u957f\u6c5f"]','敲驢吟雪月，謫出國西門。',48,'全唐诗/poet.tang.40000.json','["敲驢吟雪月，謫出國西門。", "行傍長江影，愁深汨水魂。", "笻攜過竹寺，琴典在花村。", "飢拾山松子，誰知賈傅孫。"]'),
('a076c629-99c0-4c67-b662-1a2b8fa54210','河陽道中','李洞','唐','唐诗','tang','','[]','衝風仍躡凍，提轡手頻呵。',48,'全唐诗/poet.tang.40000.json','["衝風仍躡凍，提轡手頻呵。", "得事應須早，愁人不在多。", "雪田平入塞，煙郭曲隨河。", "飜憶江濤裏，船中睡蓋蓑。"]'),
('fd0603b1-22cb-455c-87e2-f15a07470843','送知己赴濮州','李洞','唐','唐诗','tang','','[]','中路行僧謁，郵亭話海濤。',48,'全唐诗/poet.tang.40000.json','["中路行僧謁，郵亭話海濤。", "劒搖林狖落，旗閃岳禽高。", "苔長空州獄，花開夢省曹。", "濮陽流政化，一半布風騷。"]'),
('1affd2e2-07c9-4c11-acd5-e63213a6ccf2','送行脚僧','李洞','唐','唐诗','tang','','[]','缾枕繞腰垂，出門何所之。',48,'全唐诗/poet.tang.40000.json','["缾枕繞腰垂，出門何所之。", "毳衣霑雨重，椶笠看山欹。", "夜觀入枯樹，野眠逢斷碑。", "鄰房母淚下，相課別離詞。"]'),
('5c98dcd1-a93e-4664-a63c-df62b04ca798','龍州送人赴舉','李洞','唐','唐诗','tang','','[]','獻策赴招攜，行宮積翠西。',48,'全唐诗/poet.tang.40000.json','["獻策赴招攜，行宮積翠西。", "挈囊秋卷重，轉棧晚峰齊。", "踏月趨金闕，拂雲看御題。", "飛鳴豈回顧，獨鶴困江泥。"]'),
('43455d60-ad4a-4531-ba0e-3452c72c5e5a','送安撫從兄夷偶中丞','李洞','唐','唐诗','tang','','[]','奉詔向軍前，朱袍暎雪鮮。',48,'全唐诗/poet.tang.40000.json','["奉詔向軍前，朱袍暎雪鮮。", "河橋吹角凍，嶽月卷旗圓。", "僧救焚經火，人修著釣船。", "六州安撫後，萬戶解衣眠。"]'),
('4aa267cd-08ab-419b-8259-a0fbbc3bcaa4','送遠上人','李洞','唐','唐诗','tang','','[]','海嶽兩無邊，去來都偶然。',48,'全唐诗/poet.tang.40000.json','["海嶽兩無邊，去來都偶然。", "齒因吟後冷，心向靜中圓。", "蟲網花間井，鴻鳴雨後天。", "葉書歸舊寺，應附載鐘船。"]'),
('de2bfa12-cd5f-41e3-859d-af38ed2d3b34','宿鳳翔天柱寺窮易玄上人房','李洞','唐','唐诗','tang','','[]','天柱暮相逢，吟思天柱峰。',48,'全唐诗/poet.tang.40000.json','["天柱暮相逢，吟思天柱峰。", "墨研青露月，茶吸白雲鐘。", "臥語身黏蘚，行禪頂拂松。", "探玄爲一決，明日去臨邛。"]'),
('6cee609d-a344-4284-9c33-38d3bc06cf5d','下第送張霞歸覲江南','李洞','唐','唐诗','tang','','[]','此道背於時，攜歸一軸詩。',48,'全唐诗/poet.tang.40000.json','["此道背於時，攜歸一軸詩。", "樹沈孤鳥遠，風逆蹇驢遲。", "草入吟房壞，潮衝釣石移。", "恐傷歡覲意，半路摘愁髭。"]'),
('d1c3e41d-abbf-493d-857b-1310850859b3','送人之天台','李洞','唐','唐诗','tang','','[]','行李一枝藤，雲邊曉扣冰。',48,'全唐诗/poet.tang.40000.json','["行李一枝藤，雲邊曉扣冰。", "丹經如不謬，白髮亦何能。", "淺井仙人鏡，明珠海客燈。", "乃知真隱者，笑就漢廷徴。"]'),
('cce0f37e-2e0b-43d8-ba1c-bd7ff2650a8e','維摩暢林居','李洞','唐','唐诗','tang','','[]','諸方游幾臘，五夏五峰銷。',48,'全唐诗/poet.tang.40000.json','["諸方游幾臘，五夏五峰銷。", "越講迎騎象，蕃齋懺射鵰。", "冷筇和雪倚，朽櫟帶雲燒。", "從此西林老，瞥然三萬朝。"]'),
('7d00b4df-f560-4cb3-92e9-eb2282038793','送張喬下第歸宣州','李洞','唐','唐诗','tang','','[]','詩道世難通，歸寧楚浪中。',48,'全唐诗/poet.tang.40000.json','["詩道世難通，歸寧楚浪中。", "早程殘嶽月，夜泊隔淮鐘。", "一鏡隨雙鬢，全家老半峰。", "無成來往過，折盡謝亭松。"]'),
('a245422b-ea2b-4e25-a4de-0dc2970a095b','送盧郎中赴金州','李洞','唐','唐诗','tang','','[]','雲明天嶺高，刺郡輟仙曹。',48,'全唐诗/poet.tang.40000.json','["雲明天嶺高，刺郡輟仙曹。", "危棧窺猿頂，公庭埽鶴毛。", "出軍青壁罅，話道白眉毫。", "遠集歌謠客，州前泊幾艘。"]'),
('440a89da-70cd-4130-99f3-7fa5c608ba48','江干即事','李洞','唐','唐诗','tang','','[]','病臥四更後，愁聞報早衙。',48,'全唐诗/poet.tang.40000.json','["病臥四更後，愁聞報早衙。", "隔關沈水鳥，侵郭噪園鴉。", "吏瘦餐溪栢，身羸憑海槎。", "滿朝吟五字，應不老煙霞。"]'),
('42482ecf-6871-4a95-9df5-85b908fd216c','寄賀鄭常侍','李洞','唐','唐诗','tang','','[]','山亦懷恩地，高禽盡下飛。',48,'全唐诗/poet.tang.40000.json','["山亦懷恩地，高禽盡下飛。", "吏穿霞片望，僧埽月稜歸。", "省拜墀煙近，林居玉漏微。", "曾令駐錫話，聊用慰攀依。"]'),
('b7549405-8160-48a2-8865-273176c65a27','登樓','李洞','唐','唐诗','tang','','[]','川上值樓開，寒山四面來。',48,'全唐诗/poet.tang.40000.json','["川上值樓開，寒山四面來。", "竹吹人語遠，峰礙鳥飛迴。", "生死別離陌，朝昏雲雨堆。", "誰知獨立意，濺淚落莓苔。"]'),
('5db456e2-61e3-4a28-85a3-d0414914f964','贈禪友','李洞','唐','唐诗','tang','','[]','散花留內殿，宮女夢談禪。',48,'全唐诗/poet.tang.40000.json','["散花留內殿，宮女夢談禪。", "樹杪開樓鎖，雲中認嶽蓮。", "溪聲過長耳，筇節出羸肩。", "飛句相招宿，多逢有月天。"]'),
('f59a4e1e-75f9-4a09-afe6-79ff58e72d86','早春友人訪別南歸','李洞','唐','唐诗','tang','','[]','南歸來取別，窮巷坐青苔。',48,'全唐诗/poet.tang.40000.json','["南歸來取別，窮巷坐青苔。", "一盞薄醨酒，數枝零落梅。", "潮生楚驛閉，星在越樓開。", "明日望君處，前臨風月臺。"]'),
('d55f4392-a769-4209-8db3-77cdabb9c8fd','題雲際寺','李洞','唐','唐诗','tang','','[]','開門風雪頂，上徹困飛禽。',48,'全唐诗/poet.tang.40000.json','["開門風雪頂，上徹困飛禽。", "猿戲青冥裏，人行紫閣陰。", "臘泉冰下出，夜磬月中尋。", "盡欲居巖室，如何不住心。"]'),
('23b6c370-2632-4abd-9b15-df6c3b68079f','山寺老僧','李洞','唐','唐诗','tang','','[]','雲際衆僧裏，獨攢眉似愁。',48,'全唐诗/poet.tang.40000.json','["雲際衆僧裏，獨攢眉似愁。", "護茶高夏臘，愛火老春秋。", "海浪南曾病，河冰北苦遊。", "歸來諸弟子，白徧後生頭。"]'),
('df3a7185-1a73-43d5-845a-ec90ffea8d2a','同僧宿道者院','李洞','唐','唐诗','tang','','[]','攜文過水宿，拂席四廊塵。',48,'全唐诗/poet.tang.40000.json','["攜文過水宿，拂席四廊塵。", "墜果敲樓瓦，高螢暎鶴身。", "點燈吹葉火，談佛悟山人。", "盡有棲霞志，好謀三教鄰。"]'),
('8582267f-f885-4180-9db3-5eb53f5eeb68','古栢','李洞','唐','唐诗','tang','','[]','手植知何代，年齊偃蓋松。',48,'全唐诗/poet.tang.40000.json','["手植知何代，年齊偃蓋松。", "結根生別樹，吹子落鄰峰。", "古榦經龍嗅，高煙過雁衝。", "可佳繁葉盡，聲不礙秋鐘。"]'),
('a70a6053-647e-4820-bb38-469574cc23d9','贈王鳳二山人','李洞','唐','唐诗','tang','','[]','山兄望鶴信，山弟聽烏占。',48,'全唐诗/poet.tang.40000.json','["山兄望鶴信，山弟聽烏占。", "養藥同開鼎，休棊各枕奩。", "相逢九江底，共到五峰尖。", "願許爲三友，羞將白髮撏。"]'),
('89c72bd8-2294-46de-9d7f-34391e8b6daf','避地冬夜與二三禪侶吟集茅齋','李洞','唐','唐诗','tang','','[]','四海通禪客，搜吟會草亭。',48,'全唐诗/poet.tang.40000.json','["四海通禪客，搜吟會草亭。", "撚髭孤燭白，閉目衆山青。", "松挂敲冰杖，罏溫注月缾。", "獨愁懸舊斾，笏冷立殘星。"]'),
('c777b9b0-bb9f-4726-8308-e28cfd16b014','贈道微禪師','李洞','唐','唐诗','tang','','[]','銅缾澀瀉水，出磧躡蓮層。',48,'全唐诗/poet.tang.40000.json','["銅缾澀瀉水，出磧躡蓮層。", "猛虎降低鼠，盤鵰望小蠅。", "通禪五天日，照祖幾朝燈。", "短髮歸林白，何妨剃未能。"]'),
('b1556fc7-e7f6-40d4-a2a5-fc62fd7720b7','弔草堂禪師','李洞','唐','唐诗','tang','','[]','杖屨疑師在，房關四壁蛬。',48,'全唐诗/poet.tang.40000.json','["杖屨疑師在，房關四壁蛬。", "貯缾經臘水，響塔隔山鐘。", "乳鴿沿苔井，齋猿散雪峰。", "如何不見性，倚徧寺前松。"]'),
('b4829580-dddf-4cec-8191-e08d9bc3b17d','宿長安蘇雍主簿廳','李洞','唐','唐诗','tang','','[]','縣對數峰雲，官清主簿貧。',48,'全唐诗/poet.tang.40000.json','["縣對數峰雲，官清主簿貧。", "聽更池上鶴，伴值岳陽人。", "井鎖煎茶水，廳關擣藥塵。", "往來多屣步，同舍即諸鄰。"]'),
('94f119dd-4200-4f1e-b881-53c7ece90744','秋宿潤州劉處士江亭','李洞','唐','唐诗','tang','','[]','北夢風吹斷，江邊處士亭。',48,'全唐诗/poet.tang.40000.json','["北夢風吹斷，江邊處士亭。", "吟生萬井月，見盡一天星。", "浪靜魚衝鎖，窗高鶴聽經。", "東西渺無際，世界半滄溟。"]'),
('2acb8579-dd39-4dd4-b10c-40e543e01d43','秋日曲江書事','李洞','唐','唐诗','tang','','[]','門搖枯葦影，落日共鷗歸。',48,'全唐诗/poet.tang.40000.json','["門搖枯葦影，落日共鷗歸。", "園近鹿來熟，江寒人到稀。", "片雲穿塔過，枯葉入城飛。", "翻怕賓鴻至，無才動禮闈。"]'),
('065f277f-9101-4a32-bb53-1707e1d645f8','秋宿經上人房','李洞','唐','唐诗','tang','','[]','江房無葉落，松影帶山高。',48,'全唐诗/poet.tang.40000.json','["江房無葉落，松影帶山高。", "滿寺中秋月，孤窗入夜濤。", "舊真懸石壁，衰髮落銅刀。", "臥聽曉耕者，與師知苦勞。"]'),
('6a45b118-e85d-4ce0-add0-278bcd03e410','冬日題覺公牛頭蘭若','李洞','唐','唐诗','tang','','[]','天寒高木靜，一磬隔川聞。',48,'全唐诗/poet.tang.40000.json','["天寒高木靜，一磬隔川聞。", "鼎水看山汲，臺香埽雪焚。", "鶴歸惟認剎，僧步不離雲。", "石室開禪後，輪珠謝聖君。"]'),
('b8d06c55-e532-4ffe-9b70-a9dcdaf4a26a','送皇甫校書自蜀下峽歸覲襄陽','李洞','唐','唐诗','tang','','[]','蜀道波不竭，巢烏出浪痕。',48,'全唐诗/poet.tang.40000.json','["蜀道波不竭，巢烏出浪痕。", "松陰蓋巫峽，雨色徹荆門。", "宿寺青山盡，歸林綵服翻。", "苦吟懷凍餒，爲弔浩然魂。"]'),
('28e73374-417f-47d0-b8c8-f3b625bacdac','題西明寺攻文僧林復上人房','李洞','唐','唐诗','tang','','[]','誰寄湘南信，陰窗硯起津。',48,'全唐诗/poet.tang.40000.json','["誰寄湘南信，陰窗硯起津。", "燒痕碑入集，海角寺留真。", "樓憩長空鳥，鐘驚半闕人。", "御溝圓月會，似在草堂身。"]'),
('be9ade49-49c4-45d9-9de9-3108b177d077','寄翠微無可上人','李洞','唐','唐诗','tang','','[]','遠近衆心歸，居然占翠微。',48,'全唐诗/poet.tang.40000.json','["遠近衆心歸，居然占翠微。", "展經猿識字，聽法虎知非。", "泉注城池夢，霞生侍衛衣。", "玄機不可學，何似總無機。"]'),
('6273b28e-8b6c-4b08-9302-885586d9ba97','喜鸞公自蜀歸','李洞','唐','唐诗','tang','','[]','禁院對生臺，尋師到綠槐。',48,'全唐诗/poet.tang.40000.json','["禁院對生臺，尋師到綠槐。", "寺高猿看講，鐘動鳥知齋。", "埽石月盈箒，濾泉花滿篩。", "歸來逢聖節，吟步上堯階。"]'),
('13d229d0-4297-4936-bf0a-bb367ad0ddc9','題新安國寺','李洞','唐','唐诗','tang','','[]','佛亦遇艱難，重興疊廢壇。',48,'全唐诗/poet.tang.40000.json','["佛亦遇艱難，重興疊廢壇。", "偃松枝舊折，畫竹粉新乾。", "開講宮娃聽，拋生禁鳥餐。", "鐘聲入帝夢，天竺化長安。"]'),
('3ef9d355-5660-432b-8830-15a93ceaeccf','蕃寇侵逼南歸道中','李洞','唐','唐诗','tang','','[]','雲州三萬騎，南走疾飛鷹。',48,'全唐诗/poet.tang.40000.json','["雲州三萬騎，南走疾飛鷹。", "迴磧星低雁，孤城月伴僧。", "敲關通漢節，傾府守河冰。", "無處論邊事，歸溪夜結罾。"]'),
('e2f44a78-837b-4c98-b408-ae2b4d390986','送東宮賈正字之蜀','李洞','唐','唐诗','tang','','[]','南朝獻晉史，東蜀瞰巴樓。',48,'全唐诗/poet.tang.40000.json','["南朝獻晉史，東蜀瞰巴樓。", "長棧懷宮樹，疎峰露劒州。", "半空飛雪化，一道白雲流。", "若次江邊邑，宗詩爲徧搜。"]'),
('7677e92d-b452-4be4-b832-f1955446dd23','弔侯圭常侍','李洞','唐','唐诗','tang','','[]','我重君能賦，君褒我解詩。',48,'全唐诗/poet.tang.40000.json','["我重君能賦，君褒我解詩。", "三堂一拜遇，四海兩心知。", "影挂僧挑燭，名傳鶴拂碑。", "涪江弔孤塚，片月下峨嵋。"]'),
('1173c565-dccf-4130-af5d-d3cf435e1950','顏上人房','李洞','唐','唐诗','tang','','[]','御溝臨岸行，遠岫見雲生。',48,'全唐诗/poet.tang.40000.json','["御溝臨岸行，遠岫見雲生。", "松下度三伏，磬中銷五更。", "雨淋經閣白，日閃剃刀明。", "海畔終須去，燒燈老國清。"]'),
('6d497fa6-0750-471d-b66a-25ecffb4931f','題薛少府莊','李洞','唐','唐诗','tang','','[]','何須鑿井飲，門占古溪居。',48,'全唐诗/poet.tang.40000.json','["何須鑿井飲，門占古溪居。", "寂寞苔牀臥，寒虛玉柄書。", "有期登白閣，又得賞紅蕖。", "清淺蒲根水，時看鷺啄魚。"]'),
('4c180b32-7be1-49fa-b26e-fc184487b4e5','寄太白隱者','李洞','唐','唐诗','tang','','[]','開闢已來雪，爲山長欠春。',48,'全唐诗/poet.tang.40000.json','["開闢已來雪，爲山長欠春。", "高遮辭磧雁，寒噤入川人。", "棧閣交冰柱，耕樵隔日輪。", "此中棲息者，不識兩京塵。"]'),
('070c44d2-e6e2-4040-83c2-5f6c18123917','秋宿青龍禪閣','李洞','唐','唐诗','tang','','[]','前山不可望，暮色漸沉規。',48,'全唐诗/poet.tang.40000.json','["前山不可望，暮色漸沉規。", "日轉須彌北，蟾來渤海西。", "風鈴亂僧語，霜枿欠猿啼。", "閣外千家月，分明見裏迷。"]'),
('61df8469-edba-4292-852e-8d743861e055','登圭峰舊隱寄薦福棲白上人','李洞','唐','唐诗','tang','','[]','返照塔輪邊，殘霖滴幾懸。',48,'全唐诗/poet.tang.40000.json','["返照塔輪邊，殘霖滴幾懸。", "夜寒吟病甚，秋健講聲圓。", "粟穗乾燈焰，苔根濁水泉。", "西峰埋蘚石，秋月即師禪。"]'),
('b827bdb6-d44d-485f-8f39-7d7e6bb1384b','將之蜀別友人','李洞','唐','唐诗','tang','','[]','嘉陵雨色青，澹別酌參苓。',48,'全唐诗/poet.tang.40000.json','["嘉陵雨色青，澹別酌參苓。", "到蜀高諸嶽，窺天合四溟。", "書來應隔雪，夢覺已無星。", "若遇多吟友，何妨勘竺經。"]'),
('aaaf4ca3-6213-4e85-833e-ae6758078cd1','弔膳曹從叔郎中','李洞','唐','唐诗','tang','','[]','華省支殘俸，寒蔬辦祭稀。',48,'全唐诗/poet.tang.40000.json','["華省支殘俸，寒蔬辦祭稀。", "安墳對白閣，買石折朱衣。", "蜀客彈琴哭，江鷗入宅飛。", "帆吹佳句遠，不獨徧王畿。"]'),
('766f02dc-0b86-4d47-8575-1ba6c4f0c0a5','亂後龍州送鄭郎中兼寄鄭侍御','李洞','唐','唐诗','tang','','["\u5e90\u5c71"]','待車登疊嶂，經亂集鴒原。',48,'全唐诗/poet.tang.40000.json','["待車登疊嶂，經亂集鴒原。", "省壞蘭終潔，臺寒栢有根。", "縣清江入峽，樓靜雪連村。", "莫隱匡山社，機雲受晉恩。"]'),
('8e75e0fc-0852-401a-9f09-4365e037e481','段秀才溪居送從弟遊涇隴','李洞','唐','唐诗','tang','','[]','抱疾寒溪臥，因循草木青。',48,'全唐诗/poet.tang.40000.json','["抱疾寒溪臥，因循草木青。", "相留開夏蜜，辭去見秋螢。", "朔雪痕侵雍，邊烽焰照涇。", "煙沈隴山色，西望涕交零。"]'),
('dff982ae-5bd7-437a-868d-02accbf13d5f','題劉相公光德里新搆茅亭','李洞','唐','唐诗','tang','','[]','野色迷亭曉，龍墀待押班。',48,'全唐诗/poet.tang.40000.json','["野色迷亭曉，龍墀待押班。", "帶涎移海木，兼雪寫湖山。", "月白吟牀冷，河清直印閑。", "唐封三萬里，人偃翠微間。"]'),
('b84c0775-9833-4cdb-b343-72ffcf86a65d','江峽寇亂寄懷吟僧','李洞','唐','唐诗','tang','','[]','半錫探寒流，別師猿鶴洲。',48,'全唐诗/poet.tang.40000.json','["半錫探寒流，別師猿鶴洲。", "二三更後雨，四十字邊秋。", "立塞吟霞石，敲鼙看雪樓。", "扶親何處隱，驚夢入嵩丘。"]'),
('8cd02cdc-e770-4791-ba47-6c81e32d600e','賀昭國從叔員外轉本曹郎中','李洞','唐','唐诗','tang','','[]','苔砌塔陰濃，朝回尚叫蛬。',48,'全唐诗/poet.tang.40000.json','["苔砌塔陰濃，朝回尚叫蛬。", "粟徴山縣欠，官轉水曹重。", "燈照樓中雨，書求海上峰。", "詩家無驟顯，一一古人蹤。"]'),
('2b34d928-9b89-4465-8381-77ba57d561a1','贈宋校書','李洞','唐','唐诗','tang','','[]','曾伴元戎獵，寒來夢北軍。',50,'全唐诗/poet.tang.40000.json','["曾伴元戎獵，寒來夢北軍。", "閑身不計日，病鶴放歸[雲]。", "石上鋪碁勢，船中賭酒分。", "長言買天姥，高臥謝人羣。"]'),
('e0b8de07-28a5-44c2-8fb1-a70c701ba2a0','越公上人洛中歸寄南孟家兄弟','李洞','唐','唐诗','tang','','[]','洛下因歸去，官西憶二龍。',48,'全唐诗/poet.tang.40000.json','["洛下因歸去，官西憶二龍。", "笠漫河岸雪，衣着虢城鍾。", "睡鴨浮寒水，樵人出遠峰。", "賀當化閭俗，護取草堂松。"]'),
('1a58cbe0-fba9-40a3-a18e-061ca501090b','龍州送裴秀才','李洞','唐','唐诗','tang','','[]','違拜斾旗前，松陰路半千。',48,'全唐诗/poet.tang.40000.json','["違拜斾旗前，松陰路半千。", "樓衝高雪會，驛閉亂雲眠。", "牓挂臨江省，名題赴宅筵。", "人求新蜀賦，應貴浣花牋。"]'),
('37cfad11-da30-423f-9224-6c221edf8cf7','題慈恩友人房','李洞','唐','唐诗','tang','','[]','賈生耽此寺，勝事入詩多。',48,'全唐诗/poet.tang.40000.json','["賈生耽此寺，勝事入詩多。", "鶴宿星千樹，僧歸燒一坡。", "塔稜垂雪水，江色暎茶鍋。", "長久堪棲息，休言憶鏡波。"]'),
('7a805bb5-b15f-4ea5-aa59-b2b16557c22d','寄竇禪山薛秀才','李洞','唐','唐诗','tang','','[]','竇嶺吟招隱，新詩滿集賢。',48,'全唐诗/poet.tang.40000.json','["竇嶺吟招隱，新詩滿集賢。", "白衫春絮暖，紅紙夏雲鮮。", "琴纏江絲細，棊分海石圓。", "因知醉公子，虛寫世人傳。"]'),
('e9d564dd-0a6a-423e-b98d-3fd45bea0193','西蜀與崔先生話東洛舊遊','李洞','唐','唐诗','tang','','[]','王屋峭難名，三刀夢四更。',48,'全唐诗/poet.tang.40000.json','["王屋峭難名，三刀夢四更。", "日升當地缺，星盡未天明。", "度雪雲林濕，穿松角韻清。", "崔家開錦浪，憶着水窗聲。"]'),
('f4dda8e3-7ac1-462e-ab9e-4593596eecc2','上昭國水部從叔郎中','李洞','唐','唐诗','tang','','[]','極南極北游，東汎復西流。',48,'全唐诗/poet.tang.40000.json','["極南極北游，東汎復西流。", "行匝中華地，魂銷四海秋。", "題詩在瓊府，附舶出青州。", "不遇一公子，彈琴弔古丘。"]'),
('b37e3f31-0c0c-478f-aaba-c943468ba8ab','題玉芝趙尊師院','李洞','唐','唐诗','tang','','[]','曉起磬房前，真經誦百篇。',48,'全唐诗/poet.tang.40000.json','["曉起磬房前，真經誦百篇。", "漱流星入齒，照鏡石差肩。", "靜閉街西觀，存思海上仙。", "閑聽說五嶽，窮徧一根蓮。"]'),
('05a2426e-5d9f-4885-9377-136bcea01baa','送盧少府之任鞏洛','李洞','唐','唐诗','tang','','[]','從知東甸尉，銓注似恩除。',48,'全唐诗/poet.tang.40000.json','["從知東甸尉，銓注似恩除。", "帶土移嵩朮，和泉送尹魚。", "印牀寒鷺宿，壁記醉僧書。", "堂下諸昆在，無妨候起居。"]'),
('196421be-d298-4d04-9a42-4fee18aa0bf5','送人歸覲河中','李洞','唐','唐诗','tang','','[]','青門塚前別，道路武關西。',48,'全唐诗/poet.tang.40000.json','["青門塚前別，道路武關西。", "有寺雲連石，無僧葉滿溪。", "河長隨鳥盡，山遠與人齊。", "覲省波濤縣，寒窗響曙雞。"]'),
('49ecf9e9-21e3-43cc-9ba1-bc6ecdc511cc','錦城秋寄懷弘播上人','李洞','唐','唐诗','tang','','[]','極頂雲兼凍，孤城露洗初。',48,'全唐诗/poet.tang.40000.json','["極頂雲兼凍，孤城露洗初。", "共辭嵩少雪，久絕貝多書。", "遠照雁行細，寒條狖挂虛。", "分泉煎月色，憶就茗林居。"]'),
('6c0c647e-a20a-4e77-8cd5-cde9dcb5ad0a','圭峰溪居寄懷韋曲曹秀才','李洞','唐','唐诗','tang','','[]','南北飛山雪，萬片寄相思。',48,'全唐诗/poet.tang.40000.json','["南北飛山雪，萬片寄相思。", "東西曲流水，千聲瀉別離。", "巴猿學導引，隴鳥解吟詩。", "翻羨家林賞，世人那得知。"]'),
('ed485855-5eae-4ebd-8ea4-33bfbb77161a','送舍弟之山南','李洞','唐','唐诗','tang','','[]','南山入谷遊，去徹山南州。',48,'全唐诗/poet.tang.40000.json','["南山入谷遊，去徹山南州。", "下馬雲未盡，聽猿星正稠。", "印茶泉遶石，封國角吹樓。", "遠宦有何興，貧兄無計留。"]'),
('821466f3-94f7-4479-9bab-43ed2e50618a','題南鑒公山房','李洞','唐','唐诗','tang','','[]','竹房開處峭，迥挂半山燈。',48,'全唐诗/poet.tang.40000.json','["竹房開處峭，迥挂半山燈。", "石磬敲來穴，不知何代僧。", "講歸雙袖雪，禪起一盂冰。", "唯說黃桑屐，當時着秣陵。"]'),
('8e245793-b89f-4f6c-af9b-e4ebae04d43b','送知己','李洞','唐','唐诗','tang','','[]','郡清官舍冷，枕席濺山泉。',48,'全唐诗/poet.tang.40000.json','["郡清官舍冷，枕席濺山泉。", "藥氣來人外，燈光到鶴邊。", "夢秦書印斗，思越畫漁船。", "擲笏南歸去，波濤路幾千。"]'),
('3b34a812-5f3e-491d-a5c0-afb8c1a056e3','送人赴職湘潭','李洞','唐','唐诗','tang','','[]','南征雖赴辟，其奈負高科。',48,'全唐诗/poet.tang.40000.json','["南征雖赴辟，其奈負高科。", "水合湘潭住，山分越國多。", "梅花雪共下，文□□相和。", "白髮陪官宴，紅旗影裏歌。"]'),
('c0d33584-1e67-430c-81be-254464c30f9b','過野叟居','李洞','唐','唐诗','tang','','[]','野人居止處，竹色與山光。',48,'全唐诗/poet.tang.40000.json','["野人居止處，竹色與山光。", "留客羞蔬飯，灑泉開草堂。", "雨餘松子落，風過朮苗香。", "盡日無炎暑，眠君青石牀。"]'),
('8224cdc5-7b60-453b-91df-39acf303ef5f','弔鄭賓客','李洞','唐','唐诗','tang','','[]','朝行喪名節，嶽色慘天風。',48,'全唐诗/poet.tang.40000.json','["朝行喪名節，嶽色慘天風。", "待漏秋吟斷，焚香夜直空。", "骨寒依壠草，家盡逐邊鴻。", "一弔知音後，歸來碎嶧桐。"]'),
('2d407782-78ed-452d-86b6-868500553a1f','送從叔書記山陰隱居','李洞','唐','唐诗','tang','','[]','山頂絕茅居，雲泉遶枕虛。',48,'全唐诗/poet.tang.40000.json','["山頂絕茅居，雲泉遶枕虛。", "燒移僧影瘦，風展鷺行疎。", "卷箔清江月，敲松紫閣書。", "由來簪組貴，不信教猿鋤。"]'),
('71761812-4214-4b3c-ada0-9a14e823b1ef','避暑莊嚴禪院','李洞','唐','唐诗','tang','','[]','定裏無煩熱，吟中達性情。',48,'全唐诗/poet.tang.40000.json','["定裏無煩熱，吟中達性情。", "入林逢客話，上塔接僧行。", "八水皆知味，諸翁盡得名。", "常論冰井近，莫便厭浮生。"]'),
('7022a1b5-a280-47d9-a8ff-b1516c7bad5a','寄清演','李洞','唐','唐诗','tang','','[]','忽聞清演病，可料苦吟身。',48,'全唐诗/poet.tang.40000.json','["忽聞清演病，可料苦吟身。", "不見近詩久，徒言華髮新。", "別來山已破，住處月爲鄰。", "幾遶庭前樹，于今四十春。"]'),
('9097e41b-17a5-4c09-b333-9b151c31dec8','遷村居二首 一','李洞','唐','唐诗','tang','','[]','移居入村宇，樹闕見城隍。',48,'全唐诗/poet.tang.40000.json','["移居入村宇，樹闕見城隍。", "雲水雖堪畫，恩私不可忘。", "猿涎滴鶴氅，麈尾拂僧牀。", "棄逐隨樵牧，何由報稻粱。"]'),
('2a6939fb-2fee-4449-b77c-92a68aa8a848','遷村居二首 二','李洞','唐','唐诗','tang','','[]','歌樂聽常稀，茅亭靜掩扉。',48,'全唐诗/poet.tang.40000.json','["歌樂聽常稀，茅亭靜掩扉。", "槎來垂釣次，月落問安歸。", "遠客傳燒研，幽禽看衲衣。", "眼前無俗事，松雨蜀山輝。"]'),
('faadd68b-ac78-4c56-a848-b81d2ef186e4','出山覩春牓','李洞','唐','唐诗','tang','','[]','未老鬢毛焦，心歸向石橋。',48,'全唐诗/poet.tang.40000.json','["未老鬢毛焦，心歸向石橋。", "指霞辭二紀，吟雪遇三朝。", "連席頻登相，分廊尚祝堯。", "迴眸舊行侶，免使負嵩樵。"]'),
('716ef179-df7b-43dd-84f5-c94c2eef8350','賈島墓','李洞','唐','唐诗','tang','','[]','一第人皆得，先生豈不銷。',48,'全唐诗/poet.tang.40000.json','["一第人皆得，先生豈不銷。", "位卑終蜀士，詩絕占唐朝。", "旅葬新墳小，魂歸故國遙。", "我來因奠灑，立石用爲標。"]'),
('e3ac6a86-084d-41b6-9da2-008ddffddc02','觀水墨障子','李洞','唐','唐诗','tang','','[]','若非神助筆，硯水恐藏龍。',72,'全唐诗/poet.tang.40000.json','["若非神助筆，硯水恐藏龍。", "研盡一寸墨，埽成千仞峰。", "壁根堆亂石，牀罅插枯松。", "嶽麓穿因鼠，湘江綻爲蛬。", "挂衣嵐氣濕，夢枕浪頭舂。", "只爲少顏色，時人著意慵。"]'),
('495f3de9-f8db-4adf-8d96-e063aa4b1183','對棊','李洞','唐','唐诗','tang','','[]','小檻明高雪，幽人鬬智棊。',72,'全唐诗/poet.tang.40000.json','["小檻明高雪，幽人鬬智棊。", "日斜拋作劫，月午蹙成遲。", "倚杖湘僧筭，翹松野鶴窺。", "側楸敲醒睡，片石夾吟詩。", "雨點匳中漬，燈花局上吹。", "秋濤寒竹寺，此興謝公知。"]'),
('d4259dda-feda-45e3-ae62-a291f46b45e4','題竹溪禪院','李洞','唐','唐诗','tang','','[]','溪邊山一色，水擁竹千竿。',72,'全唐诗/poet.tang.40000.json','["溪邊山一色，水擁竹千竿。", "鳥觸翠微濕，人居酷暑寒。", "風搖缾影碎，沙陷履痕端。", "爽極青崖樹，平流綠峽灘。", "閑來披衲數，漲後卷經看。", "三境通禪寂，囂塵染著難。"]'),
('7408843f-9a6a-4493-9cf9-6a5ad62727cf','投獻吏部張侍郎十韻','李洞','唐','唐诗','tang','','[]','苔染馬蹄青，何曾似在城。',120,'全唐诗/poet.tang.40000.json','["苔染馬蹄青，何曾似在城。", "不於僧院宿，多傍御溝行。", "隱岫侵巴疊，租田帶渭平。", "肩囊尋省寺，袖軸徧公卿。", "夢入連濤郡，書來積雪營。", "淚隨邊雁墮，魂逐夜蟬驚。", "發憤巡江塔，無眠數縣更。", "玄都一病客，興善幾回鶯。", "貢藝披沙細，酬恩戴嶽輕。", "心期公子念，滴酒在雕楹。"]'),
('89ae4258-c461-4233-a056-15791abd415a','終南山二十韻','李洞','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','關內平田窄，東西截杳冥。',240,'全唐诗/poet.tang.40000.json','["關內平田窄，東西截杳冥。", "雨侵諸縣黑，雲破九門青。", "暫看猶無暇，長棲信有靈。", "古苔秋漬斗，積霧夜昏螢。", "怒恐撞天漏，深疑隱地形。", "盤根連北嶽，轉影落南溟。", "窮穴何山出，遮蠻上國寧。", "殘陽高照蜀，敗葉遠浮涇。", "斸竹煙嵐凍，偷湫雨雹腥。", "閑房僧灌頂，浴澗鶴遺翎。", "梯滑危緣索，雲深靜唱經。", "放泉驚鹿睡，聞磬得人醒。", "踏著神仙宅，敲開洞府扃。", "棊殘秦士局，字缺晉公銘。", "一谷勢當午，孤峰聳起丁。", "遠平丹鳳闕，冷射五侯廳。", "萬丈冰聲折，千尋樹影停。", "望中仙島動，行處月輪馨。", "疊石移臨砌，研膠潑上屏。", "明時獻君壽，不假老人星。"]'),
('216c4a17-acf7-4d0e-ab84-84390a7a84fc','秋日同覺公上人眺慈恩塔六韻','李洞','唐','唐诗','tang','','[]','九級聳蓮宮，晴登袖拂虹。',72,'全唐诗/poet.tang.40000.json','["九級聳蓮宮，晴登袖拂虹。", "房廊窺井底，世界出籠中。", "照牖三山火，吹鈴八極風。", "細聞槎客語，遙辨海魚沖。", "禁靜聲連北，江寒影在東。", "謁師開秘鎖，塵日閉虛空。"]'),
('3d9e6808-2ce1-426f-ba0c-ad22b0c403db','感知上刑部鄭侍郎','李洞','唐','唐诗','tang','','[]','寄掩白雲司，蜀都高臥時。',144,'全唐诗/poet.tang.40000.json','["寄掩白雲司，蜀都高臥時。", "鄰僧照寒竹，宿鳥動秋池。", "帝誦嘉蓮表，人吟寶劒詩。", "石渠流月斷，畫角截江吹。", "閑出黃金勒，前飛白鷺鶿。", "公心外國說，重望兩朝推。", "靜蘚斜圭影，孤窗響錫枝。", "興幽松雪見，心苦硯冰知。", "緣杖蟲聲切，過門馬足遲。", "漏殘終卷讀，日下大名垂。", "平磧容鵰上，仙山許狖窺。", "數聯金口出，死免愧丘爲。"]'),
('8f84a4f0-2c45-4e99-85a9-dcb7eb6ffcad','敘事寄薦福栖白','李洞','唐','唐诗','tang','','[]','險倚石屏風，秋濤夢越中。',96,'全唐诗/poet.tang.40000.json','["險倚石屏風，秋濤夢越中。", "前朝吟會散，故國講流終。", "北地聞巴狖，南山見磧鴻。", "樓高驚雨闊，木落覺城空。", "兔滿期姚監，蟬稀別楚公。", "淨缾光照客，拄杖朽生蟲。", "平地塔千尺，半空燈一籠。", "祝堯談幾句，旋瀉海濤東。"]'),
('16056a74-0783-4a8a-a0bb-7f1ae4b63231','送龍州田使君舊詩家','李洞','唐','唐诗','tang','','[]','御札軫西陲，龍州出牧時。',72,'全唐诗/poet.tang.40000.json','["御札軫西陲，龍州出牧時。", "度關雲作雪，挂棧水成澌。", "劒淬號猿岸，弓懸宿鶴枝。", "江燈混星斗，山木亂槍旗。", "鎖庫休秤藥，開樓又見詩。", "無心陪宴集，吟苦憶京師。"]'),
('0b14afa9-99b9-4d28-a344-f5278fd4de26','和知己赴任華州','李洞','唐','唐诗','tang','','[]','東門罷相郡，此拜動京華。',120,'全唐诗/poet.tang.40000.json','["東門罷相郡，此拜動京華。", "落日開宵印，初燈見早麻。", "鶴身紅斾拂，仙掌白雲遮。", "塞色侵三縣，河聲聒兩衙。", "松根醒客酒，蓮座隱僧家。", "一道帆飛直，中筵嶽影斜。", "書名尋雪石，澄鼎露金沙。", "鎖合眠關吏，杯寒啄廟鴉。", "分臺話嵩洛，賽雨戀煙霞。", "樹谷期招隱，吟詩煮栢茶。"]'),
('7e6623bd-1282-4089-806f-990b5060dca5','題咸陽樓','李洞','唐','唐诗','tang','','[]','晚亞古城門，憑高黯客魂。',144,'全唐诗/poet.tang.40000.json','["晚亞古城門，憑高黯客魂。", "塞侵秦舊國，河浸漢荒村。", "客路颺書燼，人家帶水痕。", "獵頻虛塚穴，耕苦露松根。", "牆外峰黏漢，冰中日晃原。", "斷碑移作砌，廣第灌成園。", "北馬疑眠磧，南人憶釣湓。", "橋閑野鹿過，街靜禁鴉翻。", "灘鼓城隍動，雲衝太白昏。", "標衣多呂裔，荷鍤或劉孫。", "弔問難知主，登攀強滴罇。", "不能扶壯勢，冠劒惜乾坤。"]'),
('825c52dd-8429-49ad-bfb8-c392320d4765','贈興善徹公上人','李洞','唐','唐诗','tang','','[]','師資懷劒外，徒步管街東。',60,'全唐诗/poet.tang.40000.json','["師資懷劒外，徒步管街東。", "九里山橫燒，三條木落風。", "古池曾看鶴，新塔未吟蟲。", "夜久龍髯冷，年多麈尾空。", "心宗本無礙，問學豈難同。"]'),
('a48e607f-f9e9-414c-b9f8-ef456d4a0fa6','龍池春草','李洞','唐','唐诗','tang','','[]','龍池清禁裏，芳草傍池春。',72,'全唐诗/poet.tang.40000.json','["龍池清禁裏，芳草傍池春。", "旋長方遮岸，全生不染塵。", "和風輕動色，湛露靜流津。", "淺得承天步，深疑遶御輪。", "魚尋倒影沒，花帶濕光新。", "肯學長河畔，綿綿思遠人。"]'),
('a6edb679-6cf8-406b-bc7a-83015607e0cd','秋宿梓州牛頭寺','李洞','唐','唐诗','tang','','[]','月去簷三尺，川雲入寺樓。',120,'全唐诗/poet.tang.40000.json','["月去簷三尺，川雲入寺樓。", "靈山頓離衆，列宿不多稠。", "篆字焚初缺，翻經誦若流。", "窗閑二江冷，簾卷半空秋。", "詔散松梢別，棊終竹節收。", "靜增雙闕念，高並五翁遊。", "鶴夢生紅日，雲閑鎖梓州。", "望空工部眼，搔亂廣文頭。", "石室僧調馬，銀河客問牛。", "曉樓歸下界，大地一浮漚。"]'),
('2ace05bd-36ee-4de0-b802-33393cdea931','送韋太尉自坤維除廣陵','李洞','唐','唐诗','tang','','[]','全蜀拜揚州，征東輟武侯。',72,'全唐诗/poet.tang.40000.json','["全蜀拜揚州，征東輟武侯。", "直來萬里月，旁到五峰秋。", "幢冷遮高雪，旗閑卓亂流。", "謝朝明主喜，登省舊寮愁。", "隔海城通舶，連河市響樓。", "千官倚元老，虛夢法雲遊。"]'),
('25ce9f0c-a1d0-4e39-bd2b-c4f5165cc5d1','贈曹郎中崇賢所居','李洞','唐','唐诗','tang','','["\u534e\u5c71"]','閑坊宅枕穿宮水，聽水分衾蓋蜀繒。',64,'全唐诗/poet.tang.40000.json','["閑坊宅枕穿宮水，聽水分衾蓋蜀繒。", "藥杵聲中擣殘夢，茶鐺影裏煮孤燈。", "刑曹樹蔭千年井，華嶽樓開萬仞冰。", "詩句變風官漸緊，夜濤舂斷海邊藤。"]'),
('bbda892d-7948-48f7-8ffe-3e9414389a00','贈昭應沈少府','李洞','唐','唐诗','tang','','[]','行宮接縣判雲泉，袍色雖青骨且仙。',64,'全唐诗/poet.tang.40000.json','["行宮接縣判雲泉，袍色雖青骨且仙。", "鄠杜憶過梨栗墅，瀟湘曾棹雪霜天。", "華山僧別留茶鼎，渭水人來鎖釣船。", "東送西迎終幾考，新詩覓得兩三聯。"]'),
('9ed6b88f-5f36-488a-94e9-7bf067da6a56','上司空員外','李洞','唐','唐诗','tang','','[]','禪心高臥似疎慵，詩客經過不厭重。',64,'全唐诗/poet.tang.40000.json','["禪心高臥似疎慵，詩客經過不厭重。", "藤杖幾攜量磧雪，玉鞭曾把數嵩峰。", "夜眠古巷當城月，秋直清曹入省鐘。", "禹鑿故山歸未得，河聲暗老兩三松。"]'),
('28d46479-8ac0-44cf-befa-8d8c7ac61307','敘舊遊寄栖白','李洞','唐','唐诗','tang','','[]','老着重袍坐石房，竺經休講白眉長。',64,'全唐诗/poet.tang.40000.json','["老着重袍坐石房，竺經休講白眉長。", "省衝鼉沒投江島，曾看魚飛倚海檣。", "曉炙凍盂原日氣，夜挑蓮椀禁燈光。", "吟詩五嶺尋無可，倏忽如今四十霜。"]'),
('1eeb7ca0-1fc0-4dfa-94ca-f496d5f3eab6','哭栖白供奉','李洞','唐','唐诗','tang','','[]','聞說孤窗坐化時，白莎蘿雨滴空池。',64,'全唐诗/poet.tang.40000.json','["聞說孤窗坐化時，白莎蘿雨滴空池。", "吟詩堂裏秋關影，禮佛燈前夜照碑。", "賀雪已成金殿夢，看濤終負石橋期。", "逢山對月還惆悵，爭得無言似祖師。"]'),
('91082a1f-75d5-48ca-b617-9fcfbe53434c','贈入內供奉僧','李洞','唐','唐诗','tang','','[]','內殿談經愜帝懷，沃州歸隱計全乖。',64,'全唐诗/poet.tang.40000.json','["內殿談經愜帝懷，沃州歸隱計全乖。", "數條雀尾來南海，一道蟬聲噪御街。", "石枕紋含山裏葉，銅缾口塞井中柴。", "因逢夏日西明講，不覺宮人拔鳳釵。"]'),
('93b94e5a-79fe-4be1-ad71-75734f27c984','感恩書事寄上集義司徒相公','李洞','唐','唐诗','tang','','[]','積雪峰西遇獎稱，半家寒骨起溝塍。',64,'全唐诗/poet.tang.40000.json','["積雪峰西遇獎稱，半家寒骨起溝塍。", "鎮時賢相回人鏡，報德慈親點佛燈。", "授鉞已聞諸國靜，坐籌重見大河澄。", "功居第一圖烟閣，依舊終南滿杜陵。"]'),
('4bdfd85c-9868-42a1-9e01-301eb9283f63','贈永崇李將軍充襄陽制置使','李洞','唐','唐诗','tang','','[]','拜官門外發輝光，宿衛陰符注幾行。',64,'全唐诗/poet.tang.40000.json','["拜官門外發輝光，宿衛陰符注幾行。", "行處近天龍尾滑，獵時陪帝馬鬃香。", "九城王氣生旗隊，萬里寒風入箭瘡。", "從此浩然聲價歇，武中還有李襄陽。"]'),
('9b5a02f7-f098-4c6a-bd23-7065bb9b627c','寄淮海惠澤上人','李洞','唐','唐诗','tang','','[]','海濤痕滿舊征衣，長憶初程宿翠微。',64,'全唐诗/poet.tang.40000.json','["海濤痕滿舊征衣，長憶初程宿翠微。", "竹裏橋鳴知馬過，塔中燈露見鴻飛。", "眉毫別後應盈尺，嵒木居來定幾圍。", "他日願師容一榻，煎茶埽地學忘機。"]'),
('f7a14e8d-7e63-48c7-8369-64b727157def','春日隱居官舍感懷','李洞','唐','唐诗','tang','','[]','風吹燒燼雜汀沙，還似青溪舊寄家。',64,'全唐诗/poet.tang.40000.json','["風吹燒燼雜汀沙，還似青溪舊寄家。", "入戶竹生牀下葉，隔窗蓮謝鏡中花。", "苔房毳客論三學，雪嶺巢禽看兩衙。", "銷得人間無限事，江亭月白誦南華。"]'),
('2b7a378e-2e3e-4703-9c05-dd92295c2453','春日即事寄一二知己','李洞','唐','唐诗','tang','','[]','浴馬池西一帶泉，開門景物似樊川。',64,'全唐诗/poet.tang.40000.json','["浴馬池西一帶泉，開門景物似樊川。", "朱衣暎水人歸縣，白羽遺泥鶴上天。", "索米夜燒風折木，無車春養雪藏鞭。", "縉紳處士知章句，忍使孤窗枕淚眠。"]'),
('ed88beca-d778-42ee-82f5-cfbaa3bc0e3b','廢寺閑居寄懷一二罷舉知己','李洞','唐','唐诗','tang','','[]','病居廢廟冷吟煙，無力爭飛類病蟬。',64,'全唐诗/poet.tang.40000.json','["病居廢廟冷吟煙，無力爭飛類病蟬。", "槐省老郎蒙主棄，月陂孤客望誰憐。", "稅房兼得調猿石，租地仍分浴鶴泉。", "處世堪驚又堪媿，一坡山色不論錢。"]'),
('db0e4213-7be3-4785-9958-3d482f3ec4e3','題尼大德院','李洞','唐','唐诗','tang','','[]','雲鬟早歲斷金刀，戒律曾持五百條。',64,'全唐诗/poet.tang.40000.json','["雲鬟早歲斷金刀，戒律曾持五百條。", "臺上燈紅蓮葉密，眉間毫白黛痕銷。", "繡成佛國銀爲地，畫出王城雪覆橋。", "清淨高樓松檜寺，世雄翻媿自低腰。"]'),
('704294cd-98b8-40fc-a4bf-8603d87e6bea','懷張喬張霞','李洞','唐','唐诗','tang','','[]','西風吹雨葉還飄，憶我同袍隔海濤。',64,'全唐诗/poet.tang.40000.json','["西風吹雨葉還飄，憶我同袍隔海濤。", "江塔眺山青入佛，邊城履雪白連鵰。", "身離世界歸天竺，影挂虛空度石橋。", "應念無成獨流轉，嬾磨銅片鬢毛焦。"]'),
('5db6190c-5a02-426f-882e-68c044218069','贈徐山人','李洞','唐','唐诗','tang','','[]','徐生何代降坤維，曾伴園公採紫芝。',64,'全唐诗/poet.tang.40000.json','["徐生何代降坤維，曾伴園公採紫芝。", "瓦礫變黃憂世換，髭鬚放白怕人疑。", "山房古竹麄於樹，海島靈童壽等龜。", "知歎有唐三百載，光陰未抵一先棊。"]'),
('a35c5025-4e0f-45f4-a0f8-c496a2b717a5','寄南嶽僧','李洞','唐','唐诗','tang','','["\u8861\u5c71"]','新秋日後曬書天，白日當松影却圓。',64,'全唐诗/poet.tang.40000.json','["新秋日後曬書天，白日當松影却圓。", "五字句求方寸佛，一條街擘兩行蟬。", "不曾著事於機內，長合教山在眼前。", "花落儔公房外石，調猿弄虎歎無緣。"]'),
('a7c7b8e9-5cfc-4c0a-9ad3-bfcb665712c1','華山','李洞','唐','唐诗','tang','','[]','碧山長凍地長秋，日夕泉源聒華州。',64,'全唐诗/poet.tang.40000.json','["碧山長凍地長秋，日夕泉源聒華州。", "萬戶煙侵關令宅，四時雲在使君樓。", "風驅雷電臨河震，鶴引神仙出月遊。", "峰頂高眠靈藥熟，自無霜雪上人頭。"]'),
('1322dfff-9b67-47ed-aeea-0081c50a596b','和曹監春晴見寄','李洞','唐','唐诗','tang','','[]','竺廟鄰鐘震曉鴉，春陰蓋石似仙家。',64,'全唐诗/poet.tang.40000.json','["竺廟鄰鐘震曉鴉，春陰蓋石似仙家。", "蘭臺架列排書目，顧渚香浮瀹茗花。", "膠溜石松粘鶴氅，泉離冰井熨僧牙。", "功成名著扁舟去，愁覩前題罩碧紗。"]'),
('2db05d4a-a627-4bbd-b852-c3e8a94bbfce','贈三惠大師','李洞','唐','唐诗','tang','','[]','楓猿嶠角別多時，二教兼修內學師。',64,'全唐诗/poet.tang.40000.json','["楓猿嶠角別多時，二教兼修內學師。", "藥樹影中頻綴偈，蓮峰朵下幾窺棊。", "遊歸筍長齊童子，病起巢成露鶴兒。", "詔落五天開夏講，兩街人競禮長眉。"]'),
('657d4c9f-abdc-42b4-a9c0-de4e41151adf','送醉畫王處士','李洞','唐','唐诗','tang','','[]','幾年乘興住南吳，狂醉蘭舟夜落湖。',64,'全唐诗/poet.tang.40000.json','["幾年乘興住南吳，狂醉蘭舟夜落湖。", "別後鶴毛描轉細，近來牛角飲還麄。", "同餐夏果山何處，共釣秋濤石在無。", "關下相逢怪予老，篇章役思繞寰區。"]'),
('c721b230-ed06-4ca6-9eb7-59d5fd1e0955','聞杜鵑','李洞','唐','唐诗','tang','','[]','萬古瀟湘波上雲，化爲流血杜鵑身。',64,'全唐诗/poet.tang.40000.json','["萬古瀟湘波上雲，化爲流血杜鵑身。", "長疑啄破青山色，秪恐啼穿白日輪。", "花落玄宗迴蜀道，雨收工部宿江津。", "聲聲猶得到君耳，不見千秋一甑塵。"]'),
('a36c47a8-15ee-41bc-8593-8b7887144bce','賦得送軒轅先生歸羅浮山','李洞','唐','唐诗','tang','','[]','舊山歸隱浪搖青，綠鬢山童一帙經。',64,'全唐诗/poet.tang.40000.json','["舊山歸隱浪搖青，綠鬢山童一帙經。", "詩帖布帆猿鳥看，藥煎金鼎鬼神聽。", "洞深頭上聆仙語，船靜鼻中聞海腥。", "此處先生應不住，吾君南望漫勞形。"]'),
('fe6b29e6-4c01-42e2-9674-ece98049ba4e','送包處士','李洞','唐','唐诗','tang','','[]','秋思枕月臥瀟湘，寄宿慈恩竹裏房。',64,'全唐诗/poet.tang.40000.json','["秋思枕月臥瀟湘，寄宿慈恩竹裏房。", "性急却於棊上慢，身閑未免藥中忙。", "休拋手網驚龍睡，曾挂頭巾拂鳥行。", "聞說石門君舊隱，寒峰濺瀑壞書堂。"]'),
('c9047879-30dc-496e-95fc-ccf2264c6adc','贈龐鍊師','李洞','唐','唐诗','tang','','[]','家住涪江漢語嬌，一聲歌戛玉樓簫。',64,'全唐诗/poet.tang.40000.json','["家住涪江漢語嬌，一聲歌戛玉樓簫。", "睡融春日柔金縷，妝發秋霞戰翠翹。", "兩臉酒醺紅杏妬，半胸酥嫩白雲饒。", "若能攜手隨仙令，皎皎銀河渡鵲橋。"]'),
('7e7da502-6168-406e-ade2-441de4fb5a16','送友罷舉赴邊職','李洞','唐','唐诗','tang','','[]','出剡篇章入洛文，無人細讀歎俱焚。',64,'全唐诗/poet.tang.40000.json','["出剡篇章入洛文，無人細讀歎俱焚。", "莫辭秉笏隨紅斾，便好攜家住白雲。", "過水象浮蠻境見，隔江猿呌漢州聞。", "高談闊略陳從事，盟誓邊庭壯我軍。"]'),
('26e2b407-6cf6-47be-aa10-efd2af622d72','病猿','李洞','唐','唐诗','tang','','[]','瘦纏金鎖惹朱樓，一別巫山樹幾秋。',64,'全唐诗/poet.tang.40000.json','["瘦纏金鎖惹朱樓，一別巫山樹幾秋。", "寒想蜀門清露滴，暖懷湘岸白雲流。", "罷拋簷果沉僧井，休拗崖冰濺客舟。", "啼過三聲應有淚，畫堂深不徹王侯。"]'),
('fd2def7f-4ef3-43d5-990f-18061c5c2df7','斃驢','李洞','唐','唐诗','tang','','[]','蹇驢秋斃瘞荒田，忍把敲吟舊竹鞭。',64,'全唐诗/poet.tang.40000.json','["蹇驢秋斃瘞荒田，忍把敲吟舊竹鞭。", "三尺焦桐背殘月，一條藜杖卓寒煙。", "通吳白浪寬圍果，倚蜀青山峭入天。", "如畫海門搘肘望，阿誰家賣釣魚船。"]'),
('0eaf80f5-5cbe-4075-9e50-793cfa66c8f5','宿葉公棋閣','李洞','唐','唐诗','tang','','[]','帶風棊閣竹相敲，局瑩無塵拂樹梢。',64,'全唐诗/poet.tang.40000.json','["帶風棊閣竹相敲，局瑩無塵拂樹梢。", "日到長天征未斷，鐘來嶽頂劫須拋。", "挑燈雪客棲寒店，供茗溪僧爇廢巢。", "因悟修身試貪教，不須焚火向三茅。"]'),
('e6ae71b0-28e1-4c6e-9c94-f5eec4b3e3c2','送郄先輩歸覲華陰','李洞','唐','唐诗','tang','','[]','桂枝博得鳳棲枝，歡覲家僮舞翠微。',64,'全唐诗/poet.tang.40000.json','["桂枝博得鳳棲枝，歡覲家僮舞翠微。", "僧向瀑泉聲裏賀，鳥穿仙掌指間飛。", "休停硯筆吟荒廟，永別燈籠赴鎖闈。", "騷雅近來頹喪甚，送君傍覺有光輝。"]'),
('8ec6188a-cfae-416e-b48f-5906b2877810','贈可上人','李洞','唐','唐诗','tang','','[]','寺門和鶴倚香杉，月吐秋光到思嚵。',64,'全唐诗/poet.tang.40000.json','["寺門和鶴倚香杉，月吐秋光到思嚵。", "將法傳來穿泱漭，把詩吟去入嵌巖。", "糢糊書卷煙嵐滴，狼籍衣裳瀑布緘。", "不斷清風牙底嚼，無因內殿得名銜。"]'),
('2d6d5d10-d845-48d1-9500-17dc436a889b','東川高僕射','李洞','唐','唐诗','tang','','[]','油幢影裏拜清風，十里貔貅一片雄。',64,'全唐诗/poet.tang.40000.json','["油幢影裏拜清風，十里貔貅一片雄。", "三印鎖開霜滿地，四門關定月當空。", "泉浮山葉人家過，詔惹罏香鳥道通。", "新起畫樓攜客上，絃歌筵內海榴紅。"]'),
('4f414440-934e-4b25-88db-4459ca7bcd36','宿成都松溪院','李洞','唐','唐诗','tang','','[]','松持節操溪澄性，一炷煙嵐壓寺隅。',64,'全唐诗/poet.tang.40000.json','["松持節操溪澄性，一炷煙嵐壓寺隅。", "翡翠鳥飛人不見，琉璃缾貯水疑無。", "夜聞子落真山雨，曉汲波圓入畫圖。", "塵擁蜀城抽鎖後，此中猶夢在江湖。"]'),
('c160c462-c0bb-4878-8a4b-758c79f0d692','弔曹監','李洞','唐','唐诗','tang','','[]','宅上愁雲吹不散，桂林詩骨葬雲根。',64,'全唐诗/poet.tang.40000.json','["宅上愁雲吹不散，桂林詩骨葬雲根。", "滿樓山色供鄰里，一洞松聲付子孫。", "甘露施衣封淚點，秘書取集印苔痕。", "吟魂醉魄歸何處，御水嗚嗚夜遶門。"]'),
('ee20475d-7930-43dd-9451-d3afdb00910b','贈長安畢郎中','李洞','唐','唐诗','tang','','[]','高門寒沼水連雲，鷺識朱衣傍主人。',64,'全唐诗/poet.tang.40000.json','["高門寒沼水連雲，鷺識朱衣傍主人。", "地肺半邊晴帶雪，天街一面靜無塵。", "朝迴座客酬琴價，衙退留僧寫鶴真。", "從此幾遷爲計相，蓬萊三刻奏東巡。"]'),
('865ff86d-2470-48ad-998e-180aff28b34f','寄東蜀幕中友','李洞','唐','唐诗','tang','','[]','官亭池碧海榴殷，遙想清才倚畫欄。',64,'全唐诗/poet.tang.40000.json','["官亭池碧海榴殷，遙想清才倚畫欄。", "柳絮漲天籠地暖，角聲經雨透雲寒。", "曉侵台座香煙濕，夜草軍書蠟炬乾。", "爲話門人吟太苦，風摧蘭秀一枝殘。"]'),
('0919bd54-20f4-4c8d-8c8b-f162de3dac9a','曲江漁父','李洞','唐','唐诗','tang','','[]','兒孫閑弄雪霜髯，浪颭南山影入簷。',64,'全唐诗/poet.tang.40000.json','["兒孫閑弄雪霜髯，浪颭南山影入簷。", "臥穩篷舟龜作枕，病來茅舍網爲簾。", "值春游子憐蓴滑，通蜀行人說鱠甜。", "數尺寒絲一竿竹，豈知浮世有猜嫌。"]'),
('72c6bbb1-6ff5-43ee-b640-14f107c6275e','和劉駕博士贈莊嚴律禪師','李洞','唐','唐诗','tang','','[]','人言紫綬有光輝，不二心觀似草衣。',64,'全唐诗/poet.tang.40000.json','["人言紫綬有光輝，不二心觀似草衣。", "塵劫自營還自壞，禪門無住亦無歸。", "松根穴蟻通山遠，塔頂巢禽見海微。", "每話南遊偏起念，五峰波上入船扉。"]'),
('d5431302-07b4-4def-b5ff-e5b1ffd70fcb','智新上人話舊','李洞','唐','唐诗','tang','','[]','蟋蟀燈前話舊遊，師經幾夏我經秋。',64,'全唐诗/poet.tang.40000.json','["蟋蟀燈前話舊遊，師經幾夏我經秋。", "金陵市合月光裏，甘露門開峰朵頭。", "晴眺遠帆飛入海，夜禪陰火吐當樓。", "相看未得東歸去，滿壁寒濤瀉白鷗。"]'),
('3463f4dd-2477-4bc7-ab5c-1f0f2c24590a','和淮南太尉留題鳳州王氏別業','李洞','唐','唐诗','tang','','[]','清秋看長鷺雛成，說向湘僧亦動情。',64,'全唐诗/poet.tang.40000.json','["清秋看長鷺雛成，說向湘僧亦動情。", "節屋折將松上影，印龕移鎖月中聲。", "野人陪賞增詩價，太尉因居著谷名。", "閑想此中遺勝事，宿齋吟遶鳳池行。"]'),
('2ad567e3-9d83-4272-8e32-fb4d0bc41ff3','乙酉歲自蜀隨計趂試不及','李洞','唐','唐诗','tang','','[]','客臥涪江蘸月廳，知音喚起進趨生。',64,'全唐诗/poet.tang.40000.json','["客臥涪江蘸月廳，知音喚起進趨生。", "寒梅折後方離蜀，臘月圓前未到京。", "風卷壞亭羸僕病，雪糊危棧蹇驢行。", "文昌一試應關分，豈校褒斜兩日程。"]'),
('591954e3-94ae-41f0-a2b1-5dbad55e951f','龍州韋郎中先夢六赤後因打葉子以詩上','李洞','唐','唐诗','tang','','[]','紅蠟香煙撲畫楹，梅花落盡庾樓清。',64,'全唐诗/poet.tang.40000.json','["紅蠟香煙撲畫楹，梅花落盡庾樓清。", "光輝圓魄銜山冷，彩鏤方牙着腕輕。", "寶帖牽來獅子鎮，金盆引出鳳凰傾。", "微黃喜兆莊周夢，六赤重新擲印成。"]'),
('da446e03-8b8b-4974-acbe-a962685e4264','和壽中丞傷猿','李洞','唐','唐诗','tang','','[]','遺挂朱欄鎖半尋，清聲難買恨黃金。',96,'全唐诗/poet.tang.40000.json','["遺挂朱欄鎖半尋，清聲難買恨黃金。", "懸崖接果今何在，淺井窺星影已沉。", "歸宅葉鋪曾睡石，入朝燈照舊啼林。", "小山罷遶隨湘客，高樹休升對嶽禽。", "天竺省憐傷倍切，親知寬和思難任。", "相門恩重無由報，竟託仙郎日夜吟。"]'),
('f0555091-c336-42f6-98e6-8b5103b2a298','上靈州令狐相公','李洞','唐','唐诗','tang','','[]','征蠻破虜漢功臣，提劒歸來萬里身。',32,'全唐诗/poet.tang.40000.json','["征蠻破虜漢功臣，提劒歸來萬里身。", "笑倚凌煙金柱看，形容憔悴老於真。"]'),
('59d55f22-70af-4c9f-b208-2899ca9220fd','寓言','李洞','唐','唐诗','tang','','[]','三千宮女露蛾眉，笑煮黃金日月遲。',32,'全唐诗/poet.tang.40000.json','["三千宮女露蛾眉，笑煮黃金日月遲。", "麟鳳隔雲攀不及，空山惆悵夕陽時。"]'),
('ad66e2cd-4bd3-4ca9-ac5b-4b6b69892d50','客亭對月','李洞','唐','唐诗','tang','','[]','游子離魂隴上花，風飄浪卷遶天涯。',32,'全唐诗/poet.tang.40000.json','["游子離魂隴上花，風飄浪卷遶天涯。", "一年十二度圓月，十一回圓不在家。"]'),
('f10da4e2-dc93-4c65-931e-6adb79f74a33','宿鄠郊贈羅處士','李洞','唐','唐诗','tang','','[]','川靜星高櫟已枯，南山落石水聲麤。',32,'全唐诗/poet.tang.40000.json','["川靜星高櫟已枯，南山落石水聲麤。", "白雲釣客窗中宿，臥數嵩峰聽五湖。"]'),
('e072d5d0-8b78-4177-aa34-7d566dd63cdf','有寄','李洞','唐','唐诗','tang','','[]','愛酒耽棊田處士，彈琴詠史賈先生。',32,'全唐诗/poet.tang.40000.json','["愛酒耽棊田處士，彈琴詠史賈先生。", "御溝臨岸有雲石，不見鶴來何處行。"]'),
('3c89f910-3c30-4728-b5d6-48b2bf980932','送三藏歸西天國','李洞','唐','唐诗','tang','','[]','十萬里程多少磧，沙中彈舌授降龍。',32,'全唐诗/poet.tang.40000.json','["十萬里程多少磧，沙中彈舌授降龍。", "五天到日應頭白，月落長安半夜鐘。"]'),
('a51bce6a-da65-43b3-9841-65a5e81830de','金陵懷古','李洞','唐','唐诗','tang','','[]','古來無此戰爭功，日日戈船卷海風。',32,'全唐诗/poet.tang.40000.json','["古來無此戰爭功，日日戈船卷海風。", "一遇靈鼇開睡眼，六朝灰盡九江空。"]'),
('e11a4613-541f-4ace-8c40-7fe47dbf1776','長安縣廳','李洞','唐','唐诗','tang','','[]','主人寂寞客屯邅，愁絕終南滿案前。',32,'全唐诗/poet.tang.40000.json','["主人寂寞客屯邅，愁絕終南滿案前。", "乞取中庭藤五尺，爲君高斸扣青天。"]'),
('883ca947-bb8a-4579-a191-bb51bff9852d','題晰上人賈島詩卷','李洞','唐','唐诗','tang','','[]','賈生詩卷惠休裝，百葉蓮花萬里香。',32,'全唐诗/poet.tang.40000.json','["賈生詩卷惠休裝，百葉蓮花萬里香。", "供得半年吟不足，長須字字頂司倉。"]'),
('841b15a6-0553-49ee-8de6-37ec9419c3b3','送僧清演歸山','李洞','唐','唐诗','tang','','[]','毛褐斜肩背負經，曉思吟入竇山青。',32,'全唐诗/poet.tang.40000.json','["毛褐斜肩背負經，曉思吟入竇山青。", "峰前野水橫官道，踏着秋天三四星。"]'),
('5cd09c7f-80bc-432a-a690-bdb4a5b8f0d8','贈僧','李洞','唐','唐诗','tang','','[]','不羨王公與貴人，唯將雲鶴自相親。',32,'全唐诗/poet.tang.40000.json','["不羨王公與貴人，唯將雲鶴自相親。", "閑來石上觀流水，欲洗禪衣未有塵。"]'),
('2f7b0eca-4f32-4451-a153-6dc5f2290b37','題學公院池蓮','李洞','唐','唐诗','tang','','[]','竹引山泉玉甃池，栽蓮莫怪藕生絲。',32,'全唐诗/poet.tang.40000.json','["竹引山泉玉甃池，栽蓮莫怪藕生絲。", "如何不似麻衣客，坐對秋風待一枝。"]'),
('1775fa41-f1d8-4845-8168-a6cda90bbd80','山居喜友人見訪','李洞','唐','唐诗','tang','','[]','入雲晴斸茯苓還，日暮逢迎木石間。',32,'全唐诗/poet.tang.40000.json','["入雲晴斸茯苓還，日暮逢迎木石間。", "看待詩人無別物，半潭秋水一房山。"]'),
('8b82a19f-8596-4c4f-b3f3-276667cfc0cb','秋宿長安韋主簿廳','李洞','唐','唐诗','tang','','[]','水木清涼夜直廳，愁人樓上唱寒更。',32,'全唐诗/poet.tang.40000.json','["水木清涼夜直廳，愁人樓上唱寒更。", "坐勞同步簾前月，鼠動牀頭印鎖聲。"]'),
('b3516a20-be76-4d2d-81ca-15d285deadfc','冬憶友人','李洞','唐','唐诗','tang','','[]','吟上山前數竹枝，葉翻似雪落霏霏。',32,'全唐诗/poet.tang.40000.json','["吟上山前數竹枝，葉翻似雪落霏霏。", "枕前明月誰動影，睡裏驚來不覺歸。"]'),
('79f8e0a1-fe11-48fa-aa8b-136fdddfde1d','懷圭峰影林泉','李洞','唐','唐诗','tang','','[]','吾家舊物賈生傳，入內遙分錫杖泉。',32,'全唐诗/poet.tang.40000.json','["吾家舊物賈生傳，入內遙分錫杖泉。", "鶴去帝移宮女散，更堪嗚咽過樓前。"]'),
('f05eec46-29b3-4290-a899-96502ec548d6','贈青龍印禪師','李洞','唐','唐诗','tang','','[]','雨澀秋刀剃雪時，菴前曾禮草堂師。',32,'全唐诗/poet.tang.40000.json','["雨澀秋刀剃雪時，菴前曾禮草堂師。", "居人昨日相過說，鶴已生孫竹滿池。"]'),
('2266386d-8617-44b2-8cd4-49beb4d97e32','戲贈侯常侍','李洞','唐','唐诗','tang','','[]','葛洪卷與江淹賦，名動天邊傲石居。',32,'全唐诗/poet.tang.40000.json','["葛洪卷與江淹賦，名動天邊傲石居。", "兩蜀詞人多載後，同君諱却馬相如。"]'),
('2f03d934-3eb3-430b-8055-d524ced4af8f','繡嶺宮詞','李洞','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6000\u5ff5"]','春日遲遲春草綠，野棠開盡飄香玉。',32,'全唐诗/poet.tang.40000.json','["春日遲遲春草綠，野棠開盡飄香玉。", "繡嶺宮前鶴髮翁，猶唱開元太平曲。"]'),
('129c374f-2356-421c-b215-784c679d24e2','中秋月','李洞','唐','唐诗','tang','','[]','九十日秋色，今秋已半分。',48,'全唐诗/poet.tang.40000.json','["九十日秋色，今秋已半分。", "孤光吞列宿，四面絕微雲。", "衆木排疎影，寒流疊細紋。", "遙遙望丹桂，心緒更紛紛。"]'),
('4f928988-ac03-47bf-9505-ee5a41067cba','宿書僧院','李洞','唐','唐诗','tang','','[]','夜水筆前澄，時推外學能。',48,'全唐诗/poet.tang.40000.json','["夜水筆前澄，時推外學能。", "書成百箇字，庭轉幾遭燈。", "寄墨大壇吏，分牋蜀國僧。", "爲題江寺塔，牌挂入雲層。"]'),
('513d8869-5c70-4ca0-9c0f-ff0a0c3931b1','雪','李洞','唐','唐诗','tang','','[]','迢迢來極塞，連闕謂風吹。',96,'全唐诗/poet.tang.40000.json','["迢迢來極塞，連闕謂風吹。", "禪客呵金錫，征人擘凍旗。", "細填蟲穴滿，重壓鶴巢欹。", "有影晴飄野，無聲夜落池。", "正繁秦甸暖，漸厚楚宮飢。", "凍挹分泉澀，光凝二閣癡。", "踏遺蘭署跡，聽起石門思。", "用表豐年瑞，無令埽玉墀。"]'),
('bd38d815-9052-4066-a9a8-315a93d7a5fe','述懷二十韻獻覃懷相公','李洞','唐','唐诗','tang','','[]','帝夢求良弼，生申屬聖明。',240,'全唐诗/poet.tang.40000.json','["帝夢求良弼，生申屬聖明。", "青雲縣器業，白日貫忠貞。", "靄靄隨春動，忻忻共物榮。", "靜宜浮競息，坐覺好風生。", "萬國聞應躍，千門望盡傾。", "瑞含楊柳色，氣變管絃聲。", "百辟尋知度，三階正有程。", "魯儒規蘊藉，周誥美和平。", "碧水遺幽抱，朱絲寄遠情。", "風流秦印綬，儀表漢公卿。", "忠讜期登用，回邪自震驚。", "雲開長劒倚，路絕一峰橫。", "九野方無事，滄溟本不爭。", "國將身共計，心與衆爲城。", "早晚中條下，紅塵一顧清。", "南潭容伴鶴，西笑忽遷鶯。", "折樹恩難報，懷仁命甚輕。", "二年猶困辱，百口望經營。", "未在英侯選，空勞短羽征。", "知音初相國，從此免長鳴。"]'),
('6dddcac1-5920-40e9-a837-02894ac12e86','歲暮自廣江至新興往復中題峽山寺','李洞','唐','唐诗','tang','','[]','薄暮緣西峽，停橈一訪僧。',72,'全唐诗/poet.tang.40000.json','["薄暮緣西峽，停橈一訪僧。", "鷺巢行臥柳，猿飲倒垂藤。", "水曲巖千疊，雲深樹百層。", "山風寒殿磬，溪雨夜船燈。", "灘漲危槎沒，泉衝怪石崩。", "中臺一襟淚，歲杪別良朋。"]'),
('04a08d2f-b83b-4599-9954-49a7162b9f15','冬日送涼州刺史','李洞','唐','唐诗','tang','','[]','寵餞西門外，雙旌出漢陵。',120,'全唐诗/poet.tang.40000.json','["寵餞西門外，雙旌出漢陵。", "未辭金殿日，已夢雪山燈。", "地遠終峰盡，天寒朔氣凝。", "新年行已到，舊典聽難勝。", "吏掃盤雕影，人遮散馬乘。", "移軍駝馱角，下塞掾河冰。", "獵近崑崙獸，吟招磧石僧。", "重輸右藏實，方見左車能。", "兵聚邊風急，城寬夜月澄。", "連營煙火嶺，望詔幾迴登。"]'),
('196eb93d-e3f5-4537-8efd-da5f8f6b03a1','過賈浪仙舊地','李洞','唐','唐诗','tang','','["\u957f\u6c5f"]','鶴外唐來有謫星，長江東注冷滄溟。',64,'全唐诗/poet.tang.40000.json','["鶴外唐來有謫星，長江東注冷滄溟。", "境搜松雪仙人島，吟歇林泉主簿廳。", "片月已能臨榜黑，遙天何益抱墳青。", "年年誰不登高第，未勝騎驢入畫屏。"]'),
('fc3945f6-f7a7-434c-adc5-fe0b2043d17d','句','李洞','唐','唐诗','tang','','[]','公道此時如不得，昭陵慟哭一生休。',16,'全唐诗/poet.tang.40000.json','["公道此時如不得，昭陵慟哭一生休。"]'),
('c0aace3b-defb-4eb2-98bd-bc2dcb6968af','酬友生早秋','唐求','唐','唐诗','tang','','[]','彤雲將欲罷，蟬柳響如秋。',48,'全唐诗/poet.tang.40000.json','["彤雲將欲罷，蟬柳響如秋。", "霧散九霄近，日程三伏愁。", "殘陽宿雨霽，高浪碎沙漚。", "袪足餘旬後，分襟任自由。"]'),
('df9e4ccc-8781-44b8-8346-5af01a82a612','曉發','唐求','唐','唐诗','tang','','[]','旅館候天曙，整車趨遠程。',48,'全唐诗/poet.tang.40000.json','["旅館候天曙，整車趨遠程。", "幾處曉鐘斷，半橋殘月明。", "沙上鳥猶在，渡頭人未行。", "去去古時道，馬嘶三兩聲。"]'),
('ed0f4a06-37b2-4b14-9e6b-d06d6a0b9c5e','客行','唐求','唐','唐诗','tang','','[]','上山下山去，千里萬里愁。',48,'全唐诗/poet.tang.40000.json','["上山下山去，千里萬里愁。", "樹色野橋暝，雨聲孤館秋。", "南北眼前道，東西江畔舟。", "世人重金玉，無金徒遠游。"]'),
('9478951f-94ad-4e93-b43e-295eb8ae6055','題鄭處士隱居','唐求','唐','唐诗','tang','','[]','不信最清曠，及來愁已空。',48,'全唐诗/poet.tang.40000.json','["不信最清曠，及來愁已空。", "數點石泉雨，一溪霜葉風。", "業在有山處，道成無事中。", "酌盡一尊酒，病夫顏亦紅。"]'),
('4ab353c5-7e72-4011-9a4e-00d35924ed0d','古寺','唐求','唐','唐诗','tang','','[]','路傍古時寺，寥落藏金容。',48,'全唐诗/poet.tang.40000.json','["路傍古時寺，寥落藏金容。", "破塔有寒草，壞樓無曉鐘。", "亂紙失經偈，斷碑分篆蹤。", "日暮月光吐，繞門千樹松。"]'),
('2b2b0bee-cf55-40d5-a60b-917ed2b4e52f','贈著上人','唐求','唐','唐诗','tang','','[]','掩門江上住，盡日更無爲。',48,'全唐诗/poet.tang.40000.json','["掩門江上住，盡日更無爲。", "古木坐禪處，殘星鳴磬時。", "水澆冰滴滴，珠數落纍纍。", "自有閑行伴，青藤杖一枝。"]'),
('1f12e4d4-7d21-47f0-9ce9-469675b1da62','馬嵬感事','唐求','唐','唐诗','tang','','[]','冷氣生深殿，狼星渡遠關。',48,'全唐诗/poet.tang.40000.json','["冷氣生深殿，狼星渡遠關。", "九城鼙鼓內，千騎道途間。", "鳳髻隨秋草，鑾輿入暮山。", "恨多留不得，悲淚滿龍顏。"]'),
('cf3c2ed5-3fa1-4d06-bdcd-86062190682b','贈行如上人','唐求','唐','唐诗','tang','','[]','不知名利苦，念佛老岷峨。',48,'全唐诗/poet.tang.40000.json','["不知名利苦，念佛老岷峨。", "衲補雲千片，香燒印一窠。", "戀山人事少，怜客道心多。", "日日齋鐘後，高懸濾水羅。"]'),
('d1dba4a6-d331-4bb1-8deb-5dd1b487eb0e','送友人歸邛州','唐求','唐','唐诗','tang','','[]','鶴鳴山下去，滿篋荷瑤琨。',48,'全唐诗/poet.tang.40000.json','["鶴鳴山下去，滿篋荷瑤琨。", "放馬荒田草，看碑古寺門。", "漸寒沙上雨，欲暝水邊村。", "莫忘分襟處，梅花撲酒尊。"]'),
('60714e33-f2d6-4f05-a705-304eb3714f4e','和舒上人山居即事','唐求','唐','唐诗','tang','','[]','敗葉填溪路，殘陽過野亭。',48,'全唐诗/poet.tang.40000.json','["敗葉填溪路，殘陽過野亭。", "仍彈一滴水，更讀兩張經。", "暝鳥煙中見，寒鐘竹裏聽。", "不多山下去，人世盡羶腥。"]'),
('639970cc-320d-4252-992d-a1790f0ed448','發邛州寄友人','唐求','唐','唐诗','tang','','[]','茫茫驅一馬，自歎又何之。',48,'全唐诗/poet.tang.40000.json','["茫茫驅一馬，自歎又何之。", "出郭見山處，待船逢雨時。", "曉雞鳴野店，寒葉墮秋枝。", "寂寞前程去，閑吟欲共誰。"]'),
('0640d467-2c30-4a7f-8400-28be62286f70','舟行夜泊夔州','唐求','唐','唐诗','tang','','[]','維舟鏡面中，迴對白鹽峰。',48,'全唐诗/poet.tang.40000.json','["維舟鏡面中，迴對白鹽峰。", "夜靜沙堤月，天寒水寺鐘。", "故園何日到，舊友幾時逢。", "欲作還家夢，青山一萬重。"]'),
('6b13138e-e63e-4232-89a9-552ad6f21002','山東蘭若遇靜公夜歸','唐求','唐','唐诗','tang','','[]','松門一徑微，苔滑往來稀。',48,'全唐诗/poet.tang.40000.json','["松門一徑微，苔滑往來稀。", "半夜聞鐘後，渾身帶雪歸。", "問寒僧接杖，辨語犬銜衣。", "又是安禪去，呼童閉竹扉。"]'),
('e4c53bc0-79f1-4f7c-a189-45489569ff54','邊將','唐求','唐','唐诗','tang','','[]','三千護塞兒，獨自滯邊陲。',48,'全唐诗/poet.tang.40000.json','["三千護塞兒，獨自滯邊陲。", "老向二毛見，秋從一葉知。", "地寒鄉思苦，天暮角聲悲。", "却被交親笑，封侯未有期。"]'),
('38af662c-3fbd-4372-945c-8dfbdff6f2a8','秋寄□江舒公','唐求','唐','唐诗','tang','','[]','故人何處望，秋色滿江濆。',48,'全唐诗/poet.tang.40000.json','["故人何處望，秋色滿江濆。", "入水溪蟲亂，過橋山路分。", "鶴歸松上月，僧入竹間雲。", "莫惜中宵磬，從教夢裏聞。"]'),
('e44bb14d-46c6-48ac-9dc6-e719d770d922','題楊山人隱居','唐求','唐','唐诗','tang','','[]','深山道者家，門戶帶煙霞。',48,'全唐诗/poet.tang.40000.json','["深山道者家，門戶帶煙霞。", "綠綴沿巖草，紅飄落水花。", "半庭栽小樹，一徑掃平沙。", "往往溪邊坐，持竿到日斜。"]'),
('6b9648ad-db50-4e4d-a427-fe43c1362e88','夜上隱居寺','唐求','唐','唐诗','tang','','[]','尋師擬學空，空住虎磎東。',48,'全唐诗/poet.tang.40000.json','["尋師擬學空，空住虎磎東。", "千里照山月，一枝驚鶴風。", "年如流去水，山似轉來蓬。", "盡日都無事，安禪石窟中。"]'),
('f1613ad5-4202-4972-9131-47bc15f4f193','友人見訪不值因寄','唐求','唐','唐诗','tang','','[]','門戶寒江近，籬墻野樹深。',48,'全唐诗/poet.tang.40000.json','["門戶寒江近，籬墻野樹深。", "晚風搖竹影，斜日轉山陰。", "砌覺披秋草，牀驚倒古琴。", "更聞鄰舍說，一隻鶴來尋。"]'),
('5de5982f-4328-46d5-bab3-2752a284ae23','塗次偶作','唐求','唐','唐诗','tang','','[]','歲月客中銷，崎嶇力自招。',48,'全唐诗/poet.tang.40000.json','["歲月客中銷，崎嶇力自招。", "問人尋野寺，牽馬渡危橋。", "爲雨疑天晚，因山覺路遙。", "前程何處是，一望又迢迢。"]'),
('6c5d1f75-a00a-493d-9be7-458f96e36061','送友人江行之廬山肄業','唐求','唐','唐诗','tang','','["\u5e90\u5c71"]','蜀國初開棹，廬峰擬拾螢。',48,'全唐诗/poet.tang.40000.json','["蜀國初開棹，廬峰擬拾螢。", "獸皮裁褥暖，蓮葉製衣馨。", "楚水秋來碧，巫山雨後青。", "莫教銜鳳詔，三度到中庭。"]'),
('9d8ea906-f518-4a22-b35f-6b05155b8b32','山居偶作','唐求','唐','唐诗','tang','','[]','趨名逐利身，終日走風塵。',48,'全唐诗/poet.tang.40000.json','["趨名逐利身，終日走風塵。", "還到水邊宅，却爲山下人。", "僧教開竹戶，客許戴紗巾。", "且喜琴書在，蘇生未厭貧。"]'),
('4381aa2a-5c16-405f-aa6b-9f367b9beffc','贈道者','唐求','唐','唐诗','tang','','[]','披霞戴鹿胎，歲月不能催。',48,'全唐诗/poet.tang.40000.json','["披霞戴鹿胎，歲月不能催。", "飯把琪花煮，衣將藕葉裁。", "鶴從歸日養，松是小時栽。", "往往樵人見，溪邊洗藥來。"]'),
('2bc3ca14-757d-4be9-9d52-ade66aa3d912','邛州水亭夜讌送顧非熊之官','唐求','唐','唐诗','tang','','[]','寂寞邛城夜，寒塘對庾樓。',48,'全唐诗/poet.tang.40000.json','["寂寞邛城夜，寒塘對庾樓。", "蜀關蟬已噪，秦樹葉應秋。", "道路連天遠，笙歌到曉愁。", "不堪分袂後，殘月正如鈎。"]'),
('1b964993-047d-4618-b4af-6b8e02b65592','題青城山范賢觀','唐求','唐','唐诗','tang','','[]','數里緣山不厭難，爲尋真訣問黃冠。',64,'全唐诗/poet.tang.40000.json','["數里緣山不厭難，爲尋真訣問黃冠。", "苔鋪翠點仙橋滑，松織香梢古道寒。", "晝傍綠畦薅嫩玉，夜開紅竈撚新丹。", "鐘聲已斷泉聲在，風動茅花月滿壇。"]'),
('1cf12d7e-93e6-4c0e-ac47-fc7ccdfd4109','送僧講罷歸山','唐求','唐','唐诗','tang','','[]','休將如意辯真空，吹盡天花任曉風。',64,'全唐诗/poet.tang.40000.json','["休將如意辯真空，吹盡天花任曉風。", "共看玉蟾三皎潔，獨懸金錫一玲瓏。", "巖間松桂秋煙白，江上樓臺晚日紅。", "依舊曹溪念經處，野泉聲在草堂東。"]'),
('16a1792d-8510-4f93-9a39-984a2975787b','題友人寓居','唐求','唐','唐诗','tang','','[]','寓居無不在天涯，莫恨秦關道路賒。',64,'全唐诗/poet.tang.40000.json','["寓居無不在天涯，莫恨秦關道路賒。", "繚繞城邊山是蜀，彎環門外水名巴。", "黃頭卷席賓初散，白鼻嘶風日欲斜。", "何處一聲金磬發，古松南畔有僧家。"]'),
('44e606c8-7d4a-40c4-807e-5fd3a8bd2898','傷張玖秀才','唐求','唐','唐诗','tang','','[]','銅梁劍閣幾區區，十上探珠不見珠。',64,'全唐诗/poet.tang.40000.json','["銅梁劍閣幾區區，十上探珠不見珠。", "卞玉影沈沙草闇，驊騮聲斷隴城孤。", "入關詞客秋懷友，出戶孀妻曉望夫。", "吳水楚山千萬里，旅魂歸到故鄉無。"]'),
('36bd761d-5aeb-4b12-8d6e-cc17a2e04da1','題李少府別業','唐求','唐','唐诗','tang','','[]','尋得仙家不姓梅，馬嘶人語出塵埃。',64,'全唐诗/poet.tang.40000.json','["尋得仙家不姓梅，馬嘶人語出塵埃。", "竹和庭上春煙動，花帶溪頭曉露開。", "繞岸白雲終日在，傍松黃鶴有時來。", "何年亦作圍碁伴，一到松間醉一回。"]'),
('756e60ee-feb6-421e-8b8c-e6c3aa133259','贈楚公','唐求','唐','唐诗','tang','','[]','曾聞半偈雪山中，貝葉飜時理盡通。',64,'全唐诗/poet.tang.40000.json','["曾聞半偈雪山中，貝葉飜時理盡通。", "般若恆添持戒力，落叉誰算念經功。", "雲間曉月應難染，海上虛舟自信風。", "長說滿庭花色好，一枝紅是一枝空。"]'),
('b57dbe7f-df79-4b24-8517-500f231091c3','贈王山人','唐求','唐','唐诗','tang','','[]','紅藤一柱腳常輕，日日緣溪入谷行。',64,'全唐诗/poet.tang.40000.json','["紅藤一柱腳常輕，日日緣溪入谷行。", "山下有家身未老，竈前無火藥初成。", "經秋少見閑人說，帶雨多聞野鶴鳴。", "知到蓬萊難再訪，問何方法得長生。"]'),
('b811b8d4-1290-4f1f-bdfa-2afe33279cc1','庭竹','唐求','唐','唐诗','tang','','[]','月籠翠葉秋承露，風亞繁梢暝掃煙。',32,'全唐诗/poet.tang.40000.json','["月籠翠葉秋承露，風亞繁梢暝掃煙。", "知道雪霜終不變，永留寒色在庭前。"]'),
('66f32008-c660-498a-a325-a26f59bf6122','題常樂寺','唐求','唐','唐诗','tang','','[]','桂冷香聞十里間，殿臺渾不似人寰。',32,'全唐诗/poet.tang.40000.json','["桂冷香聞十里間，殿臺渾不似人寰。", "日斜回首江頭望，一片晴雲落後山。"]'),
('c87c1927-03e4-4104-97e5-f5fb54de3345','題劉鍊師歸山','唐求','唐','唐诗','tang','','[]','風急雲輕鶴背寒，洞天誰道却歸難。',32,'全唐诗/poet.tang.40000.json','["風急雲輕鶴背寒，洞天誰道却歸難。", "千山萬水瀛洲路，何處煙飛是醮壇。"]'),
('9bfee45f-5958-4cfa-a8fb-42536c22acaa','酬舒公見寄','唐求','唐','唐诗','tang','','[]','無客不言雲外見，爲文長遣世間知。',32,'全唐诗/poet.tang.40000.json','["無客不言雲外見，爲文長遣世間知。", "一聲松徑寒吟後，正是前山雪下時。"]'),
('f643e194-522c-4420-8fe8-7f0c0e96fc81','巫山下作','唐求','唐','唐诗','tang','','[]','細腰宮盡舊城摧，神女歸山更不來。',32,'全唐诗/poet.tang.40000.json','["細腰宮盡舊城摧，神女歸山更不來。", "唯有楚江斜日裏，至今猶自繞陽臺。"]'),
('19bd9a22-3b09-4240-95dd-f774dfaa08ca','句','唐求','唐','唐诗','tang','','[]','恰似有龍深處臥，被人驚起黑雲生。',16,'全唐诗/poet.tang.40000.json','["恰似有龍深處臥，被人驚起黑雲生。"]'),
('b9dc6a94-5846-4660-97ee-eee857c53cb2','書懷','于鄴','唐','唐诗','tang','','[]','長安多路岐，西去欲何依。',48,'全唐诗/poet.tang.40000.json','["長安多路岐，西去欲何依。", "浮世祗如此，舊山長憶歸。", "自離京國久，應已故人稀。", "好與孤雲住，孤雲無是非。"]'),
('d3e1fe8f-735e-4bc9-a7b6-074982db7da9','書情','于鄴','唐','唐诗','tang','','[]','負郭有田在，年年長廢耕。',48,'全唐诗/poet.tang.40000.json','["負郭有田在，年年長廢耕。", "欲磨秋鏡淨，恐見白頭生。", "未作一旬別，已過千里程。", "不知書與劒，十載兩無成。"]'),
('da487c90-ee19-4010-88f8-bbc55c179fa6','塗中作','于鄴','唐','唐诗','tang','','[]','西南千里程，處處有車聲。',48,'全唐诗/poet.tang.40000.json','["西南千里程，處處有車聲。", "若使地無利，始應人不營。", "天涯猶馬到，石跡尚塵生。", "如此未曾息，蜀山終冀平。"]'),
('63cdd33b-74f3-464a-b3f4-50d562835157','春過函谷關','于鄴','唐','唐诗','tang','','[]','幾度作遊客，客行長苦辛。',48,'全唐诗/poet.tang.40000.json','["幾度作遊客，客行長苦辛。", "愁看函谷路，老盡布衣人。", "歲遠關猶固，時移草亦春。", "何當名利息，遣此絕征輪。"]'),
('65a46783-81db-43d0-94c8-5770f102008a','褒中即事','于鄴','唐','唐诗','tang','','[]','風吹殘雨歇，雲去有煙霞。',48,'全唐诗/poet.tang.40000.json','["風吹殘雨歇，雲去有煙霞。", "南浦足遊女，綠蘋應發花。", "遠鐘當半夜，明月入千家。", "不作故鄉夢，始知京洛賒。"]'),
('bf891f5f-857e-404c-8297-42cfbd109ff2','歲暮還家','于鄴','唐','唐诗','tang','','[]','東西流不駐，白日與車輪。',48,'全唐诗/poet.tang.40000.json','["東西流不駐，白日與車輪。", "殘雪半成水，微風應欲春。", "幾經他國歲，已減故鄉人。", "回首長安道，十年空苦辛。"]'),
('c167e959-59e2-47cd-bfa5-b7f9eed944b1','還家','于鄴','唐','唐诗','tang','','[]','爲客憶歸舍，歸來還寂寥。',48,'全唐诗/poet.tang.40000.json','["爲客憶歸舍，歸來還寂寥。", "壯時看欲過，白首固非遙。", "獨酌幾回醉，此愁終不銷。", "猶殘雞與犬，驅去住山椒。"]'),
('cd822f79-420b-419a-83f3-54785afa28a6','題華山麻處士所居','于鄴','唐','唐诗','tang','','[]','貴賤各擾擾，皆逢朝市間。',48,'全唐诗/poet.tang.40000.json','["貴賤各擾擾，皆逢朝市間。", "到此馬無迹，始知君獨閑。", "冰破聽敷水，雪晴看華山。", "西風寂寥地，唯我坐忘還。"]'),
('7b666abe-efd8-453c-81f2-b0f5ddddd494','天南懷故人','于鄴','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','獨行千里塵，軋軋轉征輪。',48,'全唐诗/poet.tang.40000.json','["獨行千里塵，軋軋轉征輪。", "一別已多日，總看成老人。", "洞庭雪不下，故國草應春。", "三月煙波暖，南風生綠蘋。"]'),
('abbb3831-df36-49dc-aa97-6e01f3f6f08c','路傍草','于鄴','唐','唐诗','tang','','[]','春至始青青，香車碾已平。',48,'全唐诗/poet.tang.40000.json','["春至始青青，香車碾已平。", "不知山下處，來向路傍生。", "每歲有人在，何時無馬行。", "應隨塵與土，吹滿洛陽城。"]'),
('d6b0d091-4682-4647-bca2-d21d33a57502','秋夕聞雁','于鄴','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','星漢欲沈盡，誰家砧未休。',48,'全唐诗/poet.tang.40000.json','["星漢欲沈盡，誰家砧未休。", "忽聞梁雁至，如報杜陵秋。", "千樹又黃葉，幾人新白頭。", "洞庭今夜客，一半却登舟。"]'),
('0b24b34e-734d-4d15-8790-40fc09cbe238','洛中有懷','于鄴','唐','唐诗','tang','','[]','潺潺伊洛河，寂寞少恩波。',24,'全唐诗/poet.tang.40000.json','["潺潺伊洛河，寂寞少恩波。", "鑾駕久不幸，洛陽春草多。"]'),
('04ba30d8-a51c-4479-b40b-4c88c8d72071','送魏山韋處士','于鄴','唐','唐诗','tang','','[]','陰陰亭際間，相顧慘離顏。',24,'全唐诗/poet.tang.40000.json','["陰陰亭際間，相顧慘離顏。", "一片雲飛去，嵯峨空魏山。"]'),
('ceddbc9d-6574-4028-9469-dcb81df4092a','白櫻桃','于鄴','唐','唐诗','tang','','[]','王母階前種幾株，水晶簾內看如無。',32,'全唐诗/poet.tang.40000.json','["王母階前種幾株，水晶簾內看如無。", "只應漢武金盤上，瀉得珊珊白露珠。"]'),
('2eada0df-407f-438f-a37d-e61c50d3c0dc','白櫻樹','于鄴','唐','唐诗','tang','','[]','記得花開雪滿枝，和蜂和蝶帶花移。',32,'全唐诗/poet.tang.40000.json','["記得花開雪滿枝，和蜂和蝶帶花移。", "如今花落遊蜂去，空作主人惆悵詩。"]'),
('588784ae-fa8a-41af-acbe-0cd53327aeaf','下第不勝其忿題路左佛廟','于鄴','唐','唐诗','tang','','[]','雀兒未逐颺風高，下視鷹鸇意氣豪。',32,'全唐诗/poet.tang.40000.json','["雀兒未逐颺風高，下視鷹鸇意氣豪。", "自謂能生千里足，黃昏依舊委蓬蒿。"]'),
('f1853651-08d4-40fa-b598-18f316d63cbb','感懷','于鄴','唐','唐诗','tang','','[]','東風吹草色，空使客蹉跎。',48,'全唐诗/poet.tang.40000.json','["東風吹草色，空使客蹉跎。", "不設太平險，更應遊子多。", "幾傷行處淚，一曲醉中歌。", "盡向青門外，東隨渭水波。"]'),
('ddc3beab-051a-4dae-9f5b-3304bc310423','遊中梁山','于鄴','唐','唐诗','tang','','[]','僻地好泉石，何人曾陸沈。',48,'全唐诗/poet.tang.40000.json','["僻地好泉石，何人曾陸沈。", "不知青嶂外，更有白雲深。", "因此見喬木，幾回思舊林。", "殷勤猨與鳥，唯我獨何心。"]'),
('08193479-272f-47bb-957a-6f74a4fb7e7a','尋山','于鄴','唐','唐诗','tang','','[]','到此絕車輪，萋萋草樹春。',48,'全唐诗/poet.tang.40000.json','["到此絕車輪，萋萋草樹春。", "青山如有利，白石亦成塵。", "水闊應無路，松深不見人。", "如知巢與許，千載迹猶新。"]'),
('fa9fa888-1dfd-4b78-93e3-cd155dddf3e9','宿江口','于鄴','唐','唐诗','tang','','[]','南渡人來絕，喧喧雁滿沙。',48,'全唐诗/poet.tang.40000.json','["南渡人來絕，喧喧雁滿沙。", "自生江上月，長有客思家。", "半夜下霜岸，北風吹荻花。", "自驚歸夢斷，不得到天涯。"]'),
('26899957-16a6-43b4-b70e-7bfbb254b686','秋夜達蕭關','于鄴','唐','唐诗','tang','','[]','擾擾浮梁路，人忙月自閑。',48,'全唐诗/poet.tang.40000.json','["擾擾浮梁路，人忙月自閑。", "去年爲塞客，今夜宿蕭關。", "辭國幾經歲，望鄉空見山。", "不知江葉下，又作布衣還。"]'),
('68b97b04-7b2d-4e1f-a271-f0b0ac137f13','斜谷道','于鄴','唐','唐诗','tang','','[]','亂峰連疊嶂，千里綠峨峨。',48,'全唐诗/poet.tang.40000.json','["亂峰連疊嶂，千里綠峨峨。", "蜀國路如此，遊人車亦過。", "遠煙當驛歛，驟雨逐風多。", "獨憶紫芝叟，臨風歌舊歌。"]'),
('59d82cdd-7383-472a-bf5d-936e788aa9ee','過百牢關貽舟中者','于鄴','唐','唐诗','tang','','[]','蜀國少平地，方思京洛間。',48,'全唐诗/poet.tang.40000.json','["蜀國少平地，方思京洛間。", "遠爲千里客，來度百牢關。", "帆影清江水，鈴聲碧草山。", "不因名與利，爾我各應閑。"]'),
('0fd9a554-119c-456a-8d4e-b52a5b460163','客中覽鏡','于鄴','唐','唐诗','tang','','[]','何當開此鏡，即見髮如絲。',48,'全唐诗/poet.tang.40000.json','["何當開此鏡，即見髮如絲。", "白日急於水，少年能幾時。", "每逢芳草處，長返故園遲。", "所以多爲客，蹉跎欲怨誰。"]'),
('cc66f4d6-2055-40bf-9904-97b02c59ff9c','長安逢隱者','于鄴','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','征車千里至，碾遍六街塵。',48,'全唐诗/poet.tang.40000.json','["征車千里至，碾遍六街塵。", "向此有營地，忽逢無事人。", "昔時顏未改，浮世路多新。", "且脫衣沽酒，終南山欲春。"]'),
('93b4e474-c248-4da8-a1c1-e02c989b0d19','與僧話舊','于鄴','唐','唐诗','tang','','[]','草堂前有山，一見一相寬。',48,'全唐诗/poet.tang.40000.json','["草堂前有山，一見一相寬。", "處世貴僧靜，青松因歲寒。", "他山逢舊侶，盡日話長安。", "所以閑行迹，千回繞藥欄。"]'),
('e8ac4222-39b9-48fe-9538-8556c1b08b37','贈王道士','于鄴','唐','唐诗','tang','','[]','日日市朝路，何時無苦辛。',48,'全唐诗/poet.tang.40000.json','["日日市朝路，何時無苦辛。", "不隨丹竈客，終作白頭人。", "浮世度千載，桃源方一春。", "歸來華表上，應笑北邙塵。"]'),
('55fd32fd-5072-4a24-8ca1-f51307259da7','匣中琴','于鄴','唐','唐诗','tang','','[]','世人無正心，蟲網匣中琴。',48,'全唐诗/poet.tang.40000.json','["世人無正心，蟲網匣中琴。", "何以經時廢，非爲娛耳音。", "獨令高韻在，誰感隙塵深。", "應是南風曲，聲聲不合今。"]'),
('183ffb29-cb99-4eb4-b349-db564ff8bd07','友人亭松','于鄴','唐','唐诗','tang','','[]','俛仰不能去，如逢舊友同。',48,'全唐诗/poet.tang.40000.json','["俛仰不能去，如逢舊友同。", "曾因春雪散，見在華山中。", "何處有明月，訪君聽遠風。", "相將歸未得，各占石巖東。"]'),
('099c09a3-9bb4-46ac-b077-d3a47d03535d','過洛陽城','于鄴','唐','唐诗','tang','','[]','古來利與名，俱在洛陽城。',48,'全唐诗/poet.tang.40000.json','["古來利與名，俱在洛陽城。", "九陌鼓初起，萬車輪已行。", "周秦時幾變，伊洛水猶清。", "二月中橋路，鳥啼春草生。"]'),
('639fd58e-c0f9-4265-9fd9-2cd235fbd687','客中月','于鄴','唐','唐诗','tang','','[]','離家凡幾宵，一望一寥寥。',48,'全唐诗/poet.tang.40000.json','["離家凡幾宵，一望一寥寥。", "新魄又將滿，故鄉應漸遙。", "獨臨彭蠡水，遠憶洛陽橋。", "更有乘舟客，悽然亦駐橈。"]'),
('67e13b0a-1a45-46d7-a52f-78a8aaf58fe6','王將軍宅夜聽歌','于鄴','唐','唐诗','tang','','[]','朱檻滿明月，美人歌落梅。',48,'全唐诗/poet.tang.40000.json','["朱檻滿明月，美人歌落梅。", "忽驚塵起處，疑有鳳飛來。", "一曲聽初徹，幾年愁暫開。", "東南正雲雨，不得見陽臺。"]'),
('9dc949de-547f-45b8-a234-65c047ecdc85','長信宮','于鄴','唐','唐诗','tang','','[]','莫問古宮名，古宮空有城。',24,'全唐诗/poet.tang.40000.json','["莫問古宮名，古宮空有城。", "惟應東去水，不改舊時聲。"]'),
('4e19c7d1-484a-4a7f-b9d0-9ff2e278aa15','高樓','于鄴','唐','唐诗','tang','','[]','遠天明月出，照此誰家樓。',24,'全唐诗/poet.tang.40000.json','["遠天明月出，照此誰家樓。", "上有羅衣裳，涼風吹不休。"]'),
('ad3af8c3-05b7-4885-a66b-41699c3ebd5c','和三鄉詩','陸貞洞','唐','唐诗','tang','','[]','惆悵殘花怨暮春，孤鸞舞鏡倍傷神。',32,'全唐诗/poet.tang.40000.json','["惆悵殘花怨暮春，孤鸞舞鏡倍傷神。", "清詞好箇干人事，疑是文姬第二身。"]'),
('95491a87-d014-4d63-860e-5c1d2a5b11d7','和三鄉詩','劉谷','唐','唐诗','tang','','[]','蘭蕙芬香見玉姿，路傍花笑景遲遲。',32,'全唐诗/poet.tang.40000.json','["蘭蕙芬香見玉姿，路傍花笑景遲遲。", "苧蘿山下無窮意，併在三鄉惜別時。"]'),
('b7ae520d-6134-4fb8-9385-702c5c2a2797','和三鄉詩','王祝','唐','唐诗','tang','','[]','女几山前嵐氣低，佳人留恨此中題。',32,'全唐诗/poet.tang.40000.json','["女几山前嵐氣低，佳人留恨此中題。", "不知雲雨歸何處，空使王孫見即迷。"]'),
('829abc29-6788-44e0-86b8-31e772fe877e','和三鄉詩','王滌','唐','唐诗','tang','','[]','浣紗游女出關東，舊跡新詞一夢中。',32,'全唐诗/poet.tang.40000.json','["浣紗游女出關東，舊跡新詞一夢中。", "槐陌柳亭何限事，年年迴首向春風。"]'),
('83a8c92c-5c97-469b-a2aa-e1c411934cf0','和三鄉詩','韋冰','唐','唐诗','tang','','[]','來時歡笑去時哀，家國迢迢向越臺。',32,'全唐诗/poet.tang.40000.json','["來時歡笑去時哀，家國迢迢向越臺。", "待寫百年幽思盡，故宮流水莫相催。"]'),
('69cd0bcd-9e58-4660-a48e-e5ee47e62232','和三鄉詩','李昌鄴','唐','唐诗','tang','','[]','紅粉蕭娘手自題，分明幽怨發雲閨。',32,'全唐诗/poet.tang.40000.json','["紅粉蕭娘手自題，分明幽怨發雲閨。", "不應更學文君去，泣向殘花歸剡溪。"]'),
('10ddafb1-fd9a-42a2-82c4-16e28862cde8','和三鄉詩','王碩','唐','唐诗','tang','','[]','無姓無名越水濱，芳詞空怨路傍人。',32,'全唐诗/poet.tang.40000.json','["無姓無名越水濱，芳詞空怨路傍人。", "莫教才子偏惆悵，宋玉東家是舊鄰。"]'),
('b91a62c4-c64c-47c6-8793-7d6f63b042d0','和三鄉詩','李縞','唐','唐诗','tang','','[]','會稽王謝兩風流，王子沉淪謝女愁。',32,'全唐诗/poet.tang.40000.json','["會稽王謝兩風流，王子沉淪謝女愁。", "歸思若隨文字在，路傍空爲感千秋。"]'),
('36bdfe34-1016-4b81-98fe-865c009ace28','和三鄉詩','張綺','唐','唐诗','tang','','[]','洛川依舊好風光，蓮帳無因見女郎。',32,'全唐诗/poet.tang.40000.json','["洛川依舊好風光，蓮帳無因見女郎。", "雲雨散來音信斷，此生遺恨寄三鄉。"]'),
('f65d3d26-cc34-49cd-b3c4-ac2fa4b23d30','和三鄉詩','高衢','唐','唐诗','tang','','[]','南北千山與萬山，軒車誰不思鄉關。',32,'全唐诗/poet.tang.40000.json','["南北千山與萬山，軒車誰不思鄉關。", "獨留芳翰悲前跡，陌上恐傷桃李顏。"]'),
('93b3e72f-b22b-45ef-bd9c-0132e993f46a','復覩三鄉題處留贈','賈馳','唐','唐诗','tang','','[]','壁古字未滅，聲長響不絕。',48,'全唐诗/poet.tang.40000.json','["壁古字未滅，聲長響不絕。", "蕙質本如雲，松心應耐雪。", "耿耿離幽谷，悠悠望甌越。", "杞婦哭夫時，城崩無此說。"]'),
('3665e325-1fcd-40f3-961d-b7c7b68c4c33','秋入關','賈馳','唐','唐诗','tang','','[]','河上微風來，關頭樹初濕。',36,'全唐诗/poet.tang.40000.json','["河上微風來，關頭樹初濕。", "今朝關城吏，又見孤客入。", "上國誰與期，西來徒自急。"]'),
('8bef7931-3bf4-446d-b637-f6049fae28d3','詠手二首 一','趙光遠','唐','唐诗','tang','','[]','妝成皓腕洗凝脂，背接紅巾掬水時。',64,'全唐诗/poet.tang.40000.json','["妝成皓腕洗凝脂，背接紅巾掬水時。", "薄霧袖中拈玉斝，斜陽屏上撚青絲。", "喚人急拍臨前檻，摘杏高揎近曲池。", "好是琵琶弦畔見，細圓無節玉參差。"]'),
('a774e867-f248-4c5f-a140-df0b32839c61','詠手二首 二','趙光遠','唐','唐诗','tang','','[]','撚玉搓瓊軟復圓，綠窗誰見上琴弦。',64,'全唐诗/poet.tang.40000.json','["撚玉搓瓊軟復圓，綠窗誰見上琴弦。", "慢籠彩筆閑書字，斜指瑤階笑打錢。", "爐面試香添麝炷，舌頭輕點貼金鈿。", "象床珍簟宮棊處，拈定文楸占角邊。"]'),
('f4578241-d9e5-4888-ab93-c6fa3ec86431','題妓萊兒壁','趙光遠','唐','唐诗','tang','','[]','魚鑰獸環斜掩門，萋萋芳草憶王孫。',64,'全唐诗/poet.tang.40000.json','["魚鑰獸環斜掩門，萋萋芳草憶王孫。", "醉凭青瑣窺韓壽，閑擲金梭惱謝鯤。", "不夜珠光連玉匣，辟寒釵影落瑤尊。", "欲知腸斷相思處，役盡江淹別後魂。"]'),
('51e55e97-cc29-4408-9fd9-0b20e8c54581','題興化高田院橋亭','鄭良士','唐','唐诗','tang','','[]','到此溪亭上，浮生始覺非。',48,'全唐诗/poet.tang.40000.json','["到此溪亭上，浮生始覺非。", "野僧還惜別，遊客亦忘歸。", "月滿千巖靜，風清一磬微。", "何時脫塵役，杖履願相依。"]'),
('0bd4e597-795c-45a5-8258-72651344594d','遊九鯉湖','鄭良士','唐','唐诗','tang','','[]','仄徑傾崖不可通，湖嵐林靄共溟濛。',64,'全唐诗/poet.tang.40000.json','["仄徑傾崖不可通，湖嵐林靄共溟濛。", "九溪瀑影飛花外，萬樹春聲細雨中。", "覆石雲閑丹竈冷，採芝人去洞門空。", "我來不乞邯鄲夢，取醉聊乘鄭國風。"]'),
('9a29a695-ed4c-4f31-969e-065c44a57532','寄富洋院禪者','鄭良士','唐','唐诗','tang','','[]','畫破青山路一條，走鞭飛蓋去何遙。',64,'全唐诗/poet.tang.40000.json','["畫破青山路一條，走鞭飛蓋去何遙。", "礙天巖樹春先冷，鎖院溪雲晝不銷。", "霅上茗芽因客煮，海南沈屑爲齋燒。", "誰能學得空門士，冷却心灰守寂寥。"]'),
('495ddb3b-e0bf-4f23-bf28-10a78951b1ce','贈翁承贊漆林書堂詩','蕭項','唐','唐诗','tang','','[]','軺車故國世應稀，昔日書堂二紀歸。',64,'全唐诗/poet.tang.40000.json','["軺車故國世應稀，昔日書堂二紀歸。", "手植松筠同茂盛，身榮金紫倍光輝。", "入門鄰里喧迎接，列坐兒童見等威。", "却對芸窗勤苦處，舉頭全是錦爲衣。"]'),
('e916c79a-369a-4b15-b5d6-ed208f445ed6','喜韓少府見訪','胡令能','唐','唐诗','tang','','[]','忽聞梅福來相訪，笑著荷衣出草堂。',32,'全唐诗/poet.tang.40000.json','["忽聞梅福來相訪，笑著荷衣出草堂。", "兒童不慣見車馬，走入蘆花深處藏。"]'),
('c740ff6c-2a8d-4d11-9a7e-9e699c7c7998','觀鄭州崔郎中諸妓繡樣','胡令能','唐','唐诗','tang','','[]','日暮堂前花蘂嬌，爭拈小筆上牀描。',32,'全唐诗/poet.tang.40000.json','["日暮堂前花蘂嬌，爭拈小筆上牀描。", "繡成安向春園裏，引得黃鶯下柳條。"]'),
('055f52cc-4e4b-4ee3-8e4b-737805cb3d6e','小兒垂釣','胡令能','唐','唐诗','tang','','["\u513f\u7ae5", "\u4e09\u5e74\u7ea7\u4e0a\u518c", "\u5782\u9493"]','蓬頭穉子學垂綸，側坐莓苔草映身。',32,'全唐诗/poet.tang.40000.json','["蓬頭穉子學垂綸，側坐莓苔草映身。", "路人借問遙招手，怕得魚驚不應人。"]'),
('cea26d6c-4b88-4982-a31b-f01aead537e6','王昭君','胡令能','唐','唐诗','tang','','[]','胡風似劒鎪人骨，漢月如鉤釣胃腸。',32,'全唐诗/poet.tang.40000.json','["胡風似劒鎪人骨，漢月如鉤釣胃腸。", "魂夢不知身在路，夜來猶自到昭陽。"]'),
('f5aebf25-2856-431d-9897-3aff171a421d','望夫石','嚴郾','唐','唐诗','tang','','[]','何代提戈去不還，獨留形影白雲間。',64,'全唐诗/poet.tang.40000.json','["何代提戈去不還，獨留形影白雲間。", "肌膚銷盡雪霜色，羅綺點成苔蘚斑。", "江燕不能傳遠信，野花空解妬愁顏。", "近來豈少征人婦，笑採蘼蕪上北山。"]'),
('c08a4113-c425-410f-9e0c-a7c3711d167a','賦百舌鳥','嚴郾','唐','唐诗','tang','','[]','此禽輕巧少同倫，我聽長疑舌滿身。',64,'全唐诗/poet.tang.40000.json','["此禽輕巧少同倫，我聽長疑舌滿身。", "星未沒河先報曉，柳猶黏雪便迎春。", "頻嫌海燕巢難定，却訝林鶯語不真。", "莫倚春風便多事，玉樓還有晏眠人。"]'),
('0579224a-aac4-430f-be7e-2067f8718d03','永州陪鄭太守登舟夜宴席上各賦詩','蔣肱','唐','唐诗','tang','','[]','江頭朱紱間青衿，豈是仙舟不可尋。',64,'全唐诗/poet.tang.40000.json','["江頭朱紱間青衿，豈是仙舟不可尋。", "誰敢強登徐稚榻，自憐還學謝安吟。", "月凝蘭櫂輕風起，妓勸金罍盡醉斟。", "剪盡蠟紅人未覺，歸時城郭曉煙深。"]'),
('f251a6c0-e594-4095-8c07-9ce9024a2bf6','寄遠','張逈','唐','唐诗','tang','','[]','錦字憑誰達，閑庭草又枯。',48,'全唐诗/poet.tang.40000.json','["錦字憑誰達，閑庭草又枯。", "夜長燈影滅，天遠雁聲孤。", "蟬鬢凋將盡，虬髯白也無。", "幾回愁不語，因看朔方圖。"]'),
('8bd75875-20ad-4b0c-8e73-948d5f282e4b','春草凝露','張友正','唐','唐诗','tang','','[]','蒼蒼芳草色，含露對青春。',72,'全唐诗/poet.tang.40000.json','["蒼蒼芳草色，含露對青春。", "已賴陽和長，仍慙潤澤頻。", "日臨殘未滴，風度欲成津。", "蕙葉垂偏重，蘭叢洗轉新。", "將行愁裛逕，欲采畏濡身。", "獨愛池塘畔，清華遠襲人。"]'),
('8162fe87-00b8-44fc-b2f4-1d27e0019246','錦帶佩吳鉤','張友正','唐','唐诗','tang','','[]','帶劒誰家子，春朝紫陌遊。',72,'全唐诗/poet.tang.40000.json','["帶劒誰家子，春朝紫陌遊。", "結邊霞聚錦，懸處月隨鉤。", "綵縷迴文出，雄芒練影浮。", "葉依花裏豔，霜向鍔中秋。", "的皪宜驄馬，斕斒映綺裘。", "應須待報國，一刎月支頭。"]'),
('5b3cb41e-72c6-4d91-af6a-cbc0c2e32d4d','山中臥寄盧郎中','伍唐珪','唐','唐诗','tang','','[]','十年耕釣水雲間，住僻家貧少往還。',64,'全唐诗/poet.tang.40000.json','["十年耕釣水雲間，住僻家貧少往還。", "一徑綠苔凝曉露，滿頭白髮對青山。", "野僧採藥來醫病，樵客攜觴爲解顏。", "空戀舊時恩獎地，無因匍匐出柴關。"]'),
('6163908f-5c01-47d1-b46c-0f61a2b28717','寒食日獻郡守','伍唐珪','唐','唐诗','tang','','[]','入門堪笑復堪憐，三徑苔荒一釣船。',32,'全唐诗/poet.tang.40000.json','["入門堪笑復堪憐，三徑苔荒一釣船。", "慙愧四隣教斷火，不知廚裏久無煙。"]'),
('b2b0119e-9bd7-4b5b-b453-2fdf81f79c77','上蘇使君','伍唐珪','唐','唐诗','tang','','[]','江西昔日推韓注，袁水今朝數趙祥。',32,'全唐诗/poet.tang.40000.json','["江西昔日推韓注，袁水今朝數趙祥。", "縱使文翁能待客，終栽桃李不成行。"]'),
('4219be47-4add-40a6-9eff-bd78b2d028e0','贈妓人王福娘','孫棨','唐','唐诗','tang','','[]','綵翠仙衣紅玉膚，輕盈年在破瓜初。',64,'全唐诗/poet.tang.40000.json','["綵翠仙衣紅玉膚，輕盈年在破瓜初。", "霞杯醉勸劉郎賭，雲髻慵邀阿母梳。", "不怕寒侵緣帶寶，每憂風舉倩持裾。", "謾圖西子晨粧樣，西子元來未得如。"]'),
('67690f1a-568e-4837-be62-689fdb9cb58c','題妓王福娘墻 一','孫棨','唐','唐诗','tang','','[]','移壁迴窗費幾朝，指鐶偷解博紅椒。',32,'全唐诗/poet.tang.40000.json','["移壁迴窗費幾朝，指鐶偷解博紅椒。", "無端鬬草輸鄰女，更被拈將玉步搖。"]'),
('a55c2233-1ef7-4b7c-bd37-20f801d512b9','題妓王福娘墻 二','孫棨','唐','唐诗','tang','','[]','寒繡衣裳餉阿嬌，新團香獸不禁燒。',32,'全唐诗/poet.tang.40000.json','["寒繡衣裳餉阿嬌，新團香獸不禁燒。", "東鄰起樣裙腰闊，剩蹙黃金線幾條。"]'),
('9858abdb-024f-4c4d-819a-722b227e8a1f','題妓王福娘墻 三','孫棨','唐','唐诗','tang','','[]','試共卿卿語笑初，畫堂連遣侍兒呼。',32,'全唐诗/poet.tang.40000.json','["試共卿卿語笑初，畫堂連遣侍兒呼。", "寒肌不耐金如意，白獺爲膏郎有無。"]'),
('3b58bfa5-9a3a-4d93-aa01-1a3a7f2e6d0e','戲李文遠','孫棨','唐','唐诗','tang','','[]','引君來訪洞中仙，新月如眉拂戶前。',32,'全唐诗/poet.tang.40000.json','["引君來訪洞中仙，新月如眉拂戶前。", "領取嫦娥攀取桂，便從陵谷一時遷。"]'),
('57d46fc4-2e0f-453d-86fc-5b23af5b4497','題劉泰娘舍','孫棨','唐','唐诗','tang','','[]','尋常凡木最輕樗，今日尋樗桂不如。',32,'全唐诗/poet.tang.40000.json','["尋常凡木最輕樗，今日尋樗桂不如。", "漢高新破咸陽後，英俊奔波遂喫虛。"]'),
('dafcc512-e764-422d-9b9a-e6f12ef1b23b','戲張道人不飲酒','顏蕘','唐','唐诗','tang','','[]','言自雲山訪我來，每聞奇秘覺叨陪。',32,'全唐诗/poet.tang.40000.json','["言自雲山訪我來，每聞奇秘覺叨陪。", "吾師不飲人間酒，應待流霞即舉杯。"]'),
('e32e0433-911d-4e9e-b834-0102f4fc02b5','句','顏蕘','唐','唐诗','tang','','[]','爽籟盡成鳴鳳曲，遊人多是弄珠仙。',16,'全唐诗/poet.tang.40000.json','["爽籟盡成鳴鳳曲，遊人多是弄珠仙。"]'),
('88ee9037-f145-4538-8397-f1e8b1cce4c5','秋醉歌','張爲','唐','唐诗','tang','','[]','金風颯已起，還是招漁翁。',192,'全唐诗/poet.tang.40000.json','["金風颯已起，還是招漁翁。", "攜酒天姥岑，自彈嶧陽桐。", "脫却登山履，赤脚翹青筇。", "泉聲掃殘暑，猨臂攀長松。", "翠微泛罇綠，苔蘚分煙紅。", "造化處術內，相對數壺空。", "醉眠嶺上草，不覺夜露濃。", "一夢到天曉，始覺一醉中。", "皎然夢中路，直到瀛洲東。", "初平把我臂，相與騎白龍。", "三留對上帝，玉樓十二重。", "上帝賜我酒，送我敲金鍾。", "寶閣香斂苒，琪樹寒玲瓏。", "動葉如笙篁，音律相怡融。", "珍重此一醉，百骸出天地。", "長如此夢魂，永謝名與利。"]'),
('0de89bd5-852d-4a30-be20-a7c8c6f49eb9','謝別毛仙翁','張爲','唐','唐诗','tang','','["\u9ec4\u6cb3"]','羸形感神藥，削骨生豐肌。',60,'全唐诗/poet.tang.40000.json','["羸形感神藥，削骨生豐肌。", "蘭炷飄靈煙，妖怪立誅夷。", "重覩日月光，何報父母慈。", "黃河濁衮衮，別淚流澌澌。", "黃河清有時，別淚無收期。"]'),
('a2341666-1fc9-4c72-8e99-2775ab5dff14','漁陽將軍','張爲','唐','唐诗','tang','','[]','霜髭擁頷對窮秋，著白貂裘獨上樓。',32,'全唐诗/poet.tang.40000.json','["霜髭擁頷對窮秋，著白貂裘獨上樓。", "向北望星提劒立，一生長爲國家憂。"]'),
('98ae2afc-2ec3-4fbf-8561-78d373464a45','句','張爲','唐','唐诗','tang','','[]','到處即閉戶，逢君方展眉。',12,'全唐诗/poet.tang.40000.json','["到處即閉戶，逢君方展眉。"]'),
('30156080-0d07-4b6c-ad53-7ff3ac764b6d','岑公巖','馬冉','唐','唐诗','tang','','[]','南溪有仙澗，咫尺非人間。',24,'全唐诗/poet.tang.40000.json','["南溪有仙澗，咫尺非人間。", "泠泠松風下，日暮空蒼山。"]'),
('2ba5b680-8c05-46fa-8ca3-80cff02ee98a','諸暨五洩山','周鏞','唐','唐诗','tang','','[]','路入蒼煙九過溪，九穿巖曲到招提。',64,'全唐诗/poet.tang.40000.json','["路入蒼煙九過溪，九穿巖曲到招提。", "天分五溜寒傾北，地秀諸峰翠插西。", "鑿徑破崖來木杪，駕泉鳴竹落榱題。", "當年老默無消息，猶有詞堂一杖藜。"]'),
('819a6b2a-6337-4ca8-bcaa-405ca5766415','贈羅隱','劉贊','唐','唐诗','tang','','[]','人皆言子屈，獨我謂君非。',48,'全唐诗/poet.tang.40000.json','["人皆言子屈，獨我謂君非。", "明主既難謁，青山何不歸？", "年虛侵雪鬢，塵枉汚麻衣。", "自古逃名者，至今名豈微。"]'),
('2dacb6eb-7a73-482c-9d02-aedecfd386f0','句','劉贊','唐','唐诗','tang','','[]','絮花飛起雪漫漫，長得宮娥帶笑看。',16,'全唐诗/poet.tang.40000.json','["絮花飛起雪漫漫，長得宮娥帶笑看。"]'),
('2171e44d-f83c-4277-9155-6d06f66a9fab','洛陽道','任翻','唐','唐诗','tang','','[]','憧憧洛陽道，塵下生青草。',72,'全唐诗/poet.tang.40000.json','["憧憧洛陽道，塵下生青草。", "行者豈無家，無人在家老。", "雞鳴前結束，爭去恐不早。", "百年路傍盡，白日車中曉。", "求富江海狹，取貴山岳小。", "二端立在途，奔走無由了。"]'),
('6e5cf931-e8ba-4eb5-bba1-08180cb72982','春晴','任翻','唐','唐诗','tang','','[]','楚國多春雨，柴門喜晚晴。',48,'全唐诗/poet.tang.40000.json','["楚國多春雨，柴門喜晚晴。", "幽人臨水坐，好鳥隔花鳴。", "野色臨空闊，江流接海平。", "門前到溪路，今夜月分明。"]'),
('f3d9b0ff-0a97-4993-9279-5bed56560e90','秋晚郊居','任翻','唐','唐诗','tang','','[]','遠聲霜後樹，秋色水邊村。',48,'全唐诗/poet.tang.40000.json','["遠聲霜後樹，秋色水邊村。", "野徑無來客，寒風自動門。", "海山藏日影，江月落潮痕。", "惆悵高飛晚，年年別故園。"]'),
('dcd30036-50f3-4374-bcc5-940b466d54f2','秋晚途次','任翻','唐','唐诗','tang','','[]','秋色滿行路，此時心不閑。',48,'全唐诗/poet.tang.40000.json','["秋色滿行路，此時心不閑。", "孤貧遊上國，少壯有衰顏。", "衆鳥已歸樹，旅人猶過山。", "蕭條遠林外，風急水潺潺。"]'),
('300aa35a-b18a-4b04-8c8b-9f625cb15c7b','葛仙井','任翻','唐','唐诗','tang','','[]','古井碧沈沈，分明見百尋。',48,'全唐诗/poet.tang.40000.json','["古井碧沈沈，分明見百尋。", "味甘傳邑內，脉冷應山心。", "圓入月輪淨，直涵峰影深。", "自從仙去後，汲引到如今。"]'),
('78c6e097-b066-4e41-bec8-341110b60443','桐柏觀','任翻','唐','唐诗','tang','','[]','飄飄雲外者，蹔宿聚仙堂。',48,'全唐诗/poet.tang.40000.json','["飄飄雲外者，蹔宿聚仙堂。", "半夜人無語，中宵月送涼。", "鶴歸高樹靜，螢過小池光。", "不得多時住，門開是事忙。"]'),
('8b4ccdea-b064-4e64-a8d8-81fe36fc9be4','冬暮野寺','任翻','唐','唐诗','tang','','[]','江東寒近臘，野寺水天昏。',48,'全唐诗/poet.tang.40000.json','["江東寒近臘，野寺水天昏。", "無酒可銷夜，隨僧早閉門。", "照墻燈影短，著瓦雪聲繁。", "飄泊仍千里，清吟欲斷魂。"]'),
('aae858de-d014-439b-b33b-d919dbdeab21','贈濟禪師','任翻','唐','唐诗','tang','','[]','碧峰秋寺內，禪客已無情。',48,'全唐诗/poet.tang.40000.json','["碧峰秋寺內，禪客已無情。", "半頂髮根白，一生心地清。", "竹房侵月靜，石徑到門平。", "山下塵囂路，終年誓不行。"]'),
('4a3a07b0-9369-4e7f-99dd-32685256e16b','經墮淚碑','任翻','唐','唐诗','tang','','[]','羊公傳化地，千古事空存。',48,'全唐诗/poet.tang.40000.json','["羊公傳化地，千古事空存。", "碑已無文字，人猶敬子孫。", "峴山長閉恨，漢水自流恩。", "數處煙嵐色，分明是淚痕。"]'),
('3abfdba9-2a0c-41fd-83db-17b9a1d18e96','長安冬夜書事','任翻','唐','唐诗','tang','','[]','憂來長不寐，往事重思量。',48,'全唐诗/poet.tang.40000.json','["憂來長不寐，往事重思量。", "清渭幾年客，故衣今夜霜。", "春風誰識面，水國但牽腸。", "十二門車馬，昏明各自忙。"]'),
('92e403e1-8dc4-49fe-83f8-b5fcd551be40','越江漁父','任翻','唐','唐诗','tang','','[]','借問釣魚者，持竿多少年。',48,'全唐诗/poet.tang.40000.json','["借問釣魚者，持竿多少年。", "眼明汀島畔，頭白子孫前。", "櫂入花時浪，燈留雨夜船。", "越江深見底，誰識此心堅。"]'),
('cc087581-acef-4440-9e83-f3d53cdf7bde','哭友人','任翻','唐','唐诗','tang','','[]','逢著南州史，江邊哭問君。',48,'全唐诗/poet.tang.40000.json','["逢著南州史，江邊哭問君。", "送終時有雪，歸葬處無雲。", "官庫惟留劒，隣僧共結墳。", "兒孫未成立，誰與集遺文。"]'),
('7597bff3-6104-4b19-96ca-b377b5a53424','送李衡','任翻','唐','唐诗','tang','','[]','羈棲親故少，遠別惜清才。',48,'全唐诗/poet.tang.40000.json','["羈棲親故少，遠別惜清才。", "天畔出相送，路長知未迴。", "欲銷今日恨，強把異鄉杯。", "君去南堂後，應無客到來。"]'),
('f69af4c2-f99b-4593-a732-969d99243fd3','宮怨','任翻','唐','唐诗','tang','','[]','淚乾紅落臉，心盡白垂頭。',24,'全唐诗/poet.tang.40000.json','["淚乾紅落臉，心盡白垂頭。", "自此方知怨，從來豈信愁。"]'),
('b4ca5669-16d6-4b2c-b60a-8b424c1e5d12','惜花','任翻','唐','唐诗','tang','','["\u5199\u82b1", "\u82b1"]','無語與花別，細看枝上紅。',24,'全唐诗/poet.tang.40000.json','["無語與花別，細看枝上紅。", "明年又相見，還恐是愁中。"]'),
('25748fc8-5511-4aa3-b7b2-ee7c7b8af56d','宿巾子山禪寺','任翻','唐','唐诗','tang','','[]','絕頂新秋生夜涼，鶴翻松露滴衣裳。',32,'全唐诗/poet.tang.40000.json','["絕頂新秋生夜涼，鶴翻松露滴衣裳。", "前峰月映半江水，僧在翠微開竹房。"]'),
('f709816d-d21d-45db-963e-814ce89aba20','再遊巾子山寺','任翻','唐','唐诗','tang','','[]','靈江江上幘峰寺，三十年來兩度登。',32,'全唐诗/poet.tang.40000.json','["靈江江上幘峰寺，三十年來兩度登。", "野鶴尚巢松樹徧，竹房不見舊時僧。"]'),
('28b2104f-d0ca-46e5-af36-f99951136d3a','三遊巾子山寺感述','任翻','唐','唐诗','tang','','[]','清秋絕頂竹房開，松鶴何年去不迴。',32,'全唐诗/poet.tang.40000.json','["清秋絕頂竹房開，松鶴何年去不迴。", "惟有前峰明月在，夜深猶過半江來。"]'),
('cc0bdb14-572d-41d2-993e-925e8fb7d36e','畫山水圖荅大愚','荆浩','唐','唐诗','tang','','[]','恣意縱橫埽，峰巒次第成。',48,'全唐诗/poet.tang.40000.json','["恣意縱橫埽，峰巒次第成。", "筆尖寒樹瘦，墨澹野雲輕。", "巖石噴泉窄，山根到水平。", "禪房時一展，兼稱苦空情。"]'),
('77b8c821-bdbc-43c9-819c-1d57ee5a7db0','宿顧城二首 一','張直','唐','唐诗','tang','','[]','綠草展青裀，樾影連春樹。',60,'全唐诗/poet.tang.40000.json','["綠草展青裀，樾影連春樹。", "茅屋八九家，農器六七具。", "主人有好懷，搴衣留我住。", "春酒新潑醅，香美連糟濾。", "一醉臥花陰，明朝送君去。"]'),
('33086607-fc85-487b-adfb-cb937624403d','宿顧城二首 二','張直','唐','唐诗','tang','','[]','醉臥夜將半，土底聞雞啼。',72,'全唐诗/poet.tang.40000.json','["醉臥夜將半，土底聞雞啼。", "驚駭問主人，爲我剖荒迷。", "武湯東伐韋，固君含悲悽。", "神奪悔悟魄，幻化爲石雞。", "形骸僅盈寸，咿喔若啁蜺。", "吾村耕耘叟，多獲於鋤犂。"]'),
('24f25d1e-409b-4d27-bb36-6e9e071e432b','題桃源僧','陳光','唐','唐诗','tang','','[]','桃源有僧舍，跬步異人天。',48,'全唐诗/poet.tang.40000.json','["桃源有僧舍，跬步異人天。", "花亂似無主，鶴鳴疑有仙。", "軒廊明野色，松檜濕春煙。", "定擬辭塵境，依師過晚年。"]'),
('b7cf3faf-ef1c-48db-82f6-99bc2ddfabbc','吟敘','周曇','唐','唐诗','tang','','[]','歷代興亡億萬心，聖人觀古貴知今。',32,'全唐诗/poet.tang.40000.json','["歷代興亡億萬心，聖人觀古貴知今。", "古今成敗無多事，月殿花臺幸一吟。"]'),
